    const Risu = globalThis.risuai || globalThis.Risuai;
    if (!Risu) throw new Error('[MessengerGod] RisuAI Plugin API v3 required');

    const STORAGE_STATE = 'msgod_state_v2';
    const STORAGE_MEDIA_PREFIX = 'msgod_media_v2:';
    const STORAGE_MEDIA_INDEX = 'msgod_media_index_v1';
    const STORAGE_SUMGOD_BACKUP = 'msgod_sumgod_backup_v1';
    const LEGACY_CONFIG = 'rlm_config_v1';
