            size: document.getElementById('img-size')?.value || DEFAULT_CONFIG.imageGeneration.size,
            quality: document.getElementById('img-quality')?.value || DEFAULT_CONFIG.imageGeneration.quality,
            promptPrefix: valueOf('img-prefix') || DEFAULT_CONFIG.imageGeneration.promptPrefix,
