    async function generateCharacterProfile() {
        try {
            const prompt = `${state.config.prompts.profile_creation}\n\nUser Profile\n- Name: ${state.config.userName}\n- Description: ${state.config.userDescription || '(empty)'}`;
            const payload = await callLLM([
                { role: 'system', content: prompt },
                { role: 'user', content: 'Create one character profile JSON. Return only JSON with name, handle, prompt, firstMessage, avatarText, and illustrationTags when possible.' }
            ], { rawTextOnly: true, responseMimeType: 'application/json', maxTokens: 1200 });
            const rawProfile = String(payload.rawText || payload.text || payload.messages?.map(item => item.content).join('\n') || '').trim();
            let parsed;
            try { parsed = JSON.parse(extractJson(rawProfile)); }
            catch (_) { parsed = JSON.parse(repairJsonish(extractJson(rawProfile))); }
            if (!parsed || (!parsed.name && !parsed.prompt)) throw new Error(`프로필 JSON에 name/prompt가 없습니다: ${rawProfile.slice(0, 160)}`);
            await addCharacter();
            const character = currentCharacter();
            character.name = parsed.name || character.name;
            character.avatarText = character.name.slice(0, 2);
            character.handle = String(parsed.handle || character.handle || character.id || '').replace(/^@/, '').slice(0, 40);
            character.prompt = parsed.prompt || character.prompt;
            character.firstMessage = parsed.firstMessage || character.firstMessage;
            character.illustrationTags = parsed.illustrationTags || character.illustrationTags;
            await saveState();
            activeTab = 'characters';
            render();
        } catch (error) {
            alert(`캐릭터 생성 실패: ${error.message}`);
        }
    }

