    async function createSnsPost() {
        const character = currentCharacter() || state.characters[0];
        const hintText = valueOf('mg-post-text');
        if (!character || isPosting) return;
        isPosting = true;
        render();
        try {
            await generateSnsPost(character, selectedRoomId, hintText, { image: postAttachment?.image || '', manual: true });
            postAttachment = null;
            await saveState();
        } catch (error) {
            alert(`SNS 게시 실패: ${error.message}`);
        } finally {
            isPosting = false;
            render();
        }
    }

    async function generateSnsPost(character, roomId, hintText = '', options = {}) {
        const payload = await callLLM(buildSnsPostMessages(character, hintText, roomId));
        const text = payload.messages.map(item => item.content).filter(Boolean).join('\n').trim();
        if (!text) throw new Error('SNS 포스트 텍스트를 만들지 못했습니다.');
        state.snsPosts = state.snsPosts || [];
        state.snsPosts.push({ id: makeId(), characterId: character.id, text, image: options.image || '', likes: 0, createdAt: Date.now(), sourceRoomId: roomId, hint: hintText, auto: options.manual ? false : true });
        const messages = state.messages[roomId] || [];
        character.lastSnsMessageCount = messages.length;
    }

    async function createSnsPost() {
        const character = currentCharacter() || state.characters[0];
        const hintText = valueOf('mg-post-text');
        if (!character || isPosting) return;
        await saveSnsSettingsFromForm(false);
        isPosting = true;
        render();
        try {
            await generateSnsPost(character, selectedRoomId, hintText, { image: postAttachment?.image || '', manual: true, sns: state.config.sns });
            postAttachment = null;
            await saveState();
        } catch (error) {
            alert(`SNS 게시 실패: ${error.message}`);
        } finally {
            isPosting = false;
            render();
        }
    }

    async function generateSnsPost(character, roomId, hintText = '', options = {}) {
        const sns = { ...DEFAULT_CONFIG.sns, ...(state.config.sns || {}), ...(options.sns || {}) };
        let raw = '';
        let parsed;
        try {
            const payload = await callLLM(buildSnsPostMessages(character, hintText, roomId, { ...options, sns }), { maxTokens: sns.platform === 'hybrid' ? 2200 : 1600 });
            raw = String(payload.rawText || payload.messages.map(item => item.content).filter(Boolean).join('\n')).trim();
            if (!raw) throw new Error('SNS post text was empty.');
        } catch (error) {
            raw = fallbackSnsPostText(character, roomId, hintText);
            parsed = { platforms: [{ platform: sns.platform === 'instagram' ? 'instagram' : 'twitter', text: raw, comments: [], stats: {}, imagePrompt: fallbackSnsImagePrompt(character, raw), imageCaption: raw }], dms: [] };
            logDebug('sns-text-fallback', `${character.name} SNS text generation failed, using fallback post: ${error.message}`, { roomId });
        }
        if (!parsed) {
            try { parsed = JSON.parse(extractJson(raw)); }
            catch (_) {
                try { parsed = JSON.parse(repairJsonish(extractJson(raw))); }
                catch (_) { parsed = { platforms: [{ platform: sns.platform === 'instagram' ? 'instagram' : 'twitter', text: cleanSnsVisibleText(raw), comments: [], stats: {}, imagePrompt: extractSnsLooseField(raw, 'imagePrompt'), imageCaption: extractSnsLooseField(raw, 'imageCaption') }], dms: [] }; }
            }
        }
        const platforms = normalizeSnsPlatforms(parsed.platforms, sns, character);
        const attachedImage = options.image || '';
        for (const [index, item] of platforms.entries()) {
            if (attachedImage && index === 0) item.image = attachedImage;
            if (!item.imagePrompt && !sns.textOnly && sns.autoImage !== false) item.imagePrompt = fallbackSnsImagePrompt(character, item.text);
            if (sns.nsfw && item.imagePrompt) item.imagePrompt = ensureNsfwTag(item.imagePrompt, { nsfw: true });
            if (!item.image && !sns.textOnly && sns.autoImage !== false && item.imagePrompt && (state.config.imageGeneration || {}).enabled) {
                try {
                    const imageItem = { imagePrompt: item.imagePrompt, imageCaption: item.imageCaption || item.text || '' };
                    item.image = await callImageGeneration(character, imageItem);
                    item.finalImagePrompt = imageItem.finalImagePrompt || item.imagePrompt;
                } catch (error) {
                    logDebug('sns-image-error', `${character.name} SNS image generation failed: ${error.message}`, { roomId, platform: item.platform });
                }
            }
        }
        state.snsPosts = state.snsPosts || [];
        const first = platforms[0] || {};
        const post = { id: makeId(), characterId: character.id, platforms, dms: Array.isArray(parsed.dms) && !sns.noDM ? parsed.dms.slice(0, 2) : [], text: first.text || raw, image: first.image || attachedImage, imagePrompt: first.finalImagePrompt || first.imagePrompt || '', likes: Number(first.stats?.likes) || 0, createdAt: Date.now(), sourceRoomId: roomId, hint: hintText, auto: options.manual ? false : true };
        state.snsPosts.unshift(post);
        noteSnsPost(character, post);
        const messages = state.messages[roomId] || [];
        character.lastSnsMessageCount = messages.length;
    }

    function normalizeSnsPlatforms(platforms, sns, character) {
        const source = Array.isArray(platforms) && platforms.length ? platforms : [];
        const expected = sns.platform === 'hybrid' ? ['twitter', 'instagram'] : [sns.platform || 'twitter'];
        const picked = source.length ? [...source] : expected.map(platform => ({ platform, text: '' }));
        if (sns.platform === 'hybrid') {
            for (const platform of expected) if (!picked.some(item => item.platform === platform)) picked.push({ platform, text: picked[0]?.text || '' });
        }
        return picked.slice(0, sns.platform === 'hybrid' ? 2 : 1).map((item, index) => {
            const platform = ['twitter', 'instagram', 'onlyfans'].includes(item.platform) ? item.platform : expected[index] || 'twitter';
            const comments = Array.isArray(item.comments) ? item.comments : [];
            const stats = item.stats && typeof item.stats === 'object' ? item.stats : {};
            return {
                platform,
                displayName: String(item.displayName || character.name || 'Character'),
                handle: String(item.handle || character.handle || character.id || '').replace(/^@/, ''),
                text: String(item.text || item.post || item.tweet || '').trim(),
                hashtags: Array.isArray(item.hashtags) ? item.hashtags.slice(0, 8) : String(item.hashtags || '').split(/\s+/).filter(Boolean).slice(0, 8),
                time: String(item.time || 'now'),
                stats: {
                    views: Number(stats.views) || randomMetric(120, 9000),
                    likes: Number(stats.likes) || randomMetric(3, 800),
                    replies: Number(stats.replies) || comments.length,
                    reposts: Number(stats.reposts) || Number(stats.retweets) || randomMetric(0, 90),
                    bookmarks: Number(stats.bookmarks) || randomMetric(0, 120)
                },
                comments: comments.slice(0, 8).map(comment => ({ name: String(comment.name || comment.nick || 'anon'), handle: String(comment.handle || '').replace(/^@/, ''), body: String(comment.body || comment.text || comment.comment || '').trim(), likes: Number(comment.likes) || 0 })).filter(comment => comment.body),
                image: item.image || '',
                imagePrompt: String(item.imagePrompt || item.image_desc || '').trim(),
                imageCaption: String(item.imageCaption || item.caption || '').trim(),
                finalImagePrompt: String(item.finalImagePrompt || '').trim()
            };
        }).filter(item => item.text || item.imagePrompt || item.image);
    }

    function randomMetric(min, max) {
        return Math.floor(min + Math.random() * Math.max(1, max - min));
    }

    async function maybeCreateAutoSnsPost(character, roomId) {
        if (!state.config.autoSnsEnabled || isPosting || !character || !roomId) return;
        const messages = state.messages[roomId] || [];
        const minMessages = Math.max(2, Number(state.config.autoSnsMinMessages) || 6);
        const cooldown = Math.max(1, Number(state.config.autoSnsCooldownMessages) || 4);
        if (messages.length < minMessages) return;
        if (messages.length - (Number(character.lastSnsMessageCount) || 0) < cooldown) return;
        const chance = Math.max(0, Math.min(100, Number(state.config.autoSnsChance) || 40));
        if (Math.random() * 100 >= chance) return;
        isPosting = true;
        try {
            await generateSnsPost(character, roomId, 'Recent chat may contain something worth posting as a private-account update.', { manual: false });
            await saveState();
        } finally {
            isPosting = false;
            render();
        }
    }

    async function likeSnsPost(id) {
        const post = (state.snsPosts || []).find(item => item.id === id);
        if (!post) return;
        post.likes = (Number(post.likes) || 0) + 1;
        const first = Array.isArray(post.platforms) ? post.platforms[0] : null;
        if (first) {
            first.stats = first.stats || {};
            first.stats.likes = (Number(first.stats.likes) || 0) + 1;
        }
        await saveState();
        render();
    }

    async function deleteSnsPost(id) {
        if (!confirm('이 SNS 게시물을 삭제할까요?')) return;
        state.snsPosts = (state.snsPosts || []).filter(item => item.id !== id);
        await saveState();
        render();
    }

    async function addSnsComment(postId, index = 0) {
        const post = (state.snsPosts || []).find(item => item.id === postId);
        const platform = post?.platforms?.[Number(index) || 0];
        if (!platform) return;
        const body = document.getElementById(`sns-comment-${postId}-${Number(index) || 0}`)?.value?.trim() || '';
        if (!body) return;
        platform.comments = Array.isArray(platform.comments) ? platform.comments : [];
        platform.comments.push({ name: state.config.userName || '나', handle: 'me', body, likes: 0, isUser: true, createdAt: Date.now() });
        platform.stats = platform.stats || {};
        platform.stats.replies = Number(platform.stats.replies || 0) + 1;
        await saveState();
        render();
    }

    function openSnsDm(postId, index = 0) {
        const post = (state.snsPosts || []).find(item => item.id === postId);
        if (!post) return;
        state.snsDmThreads = state.snsDmThreads || [];
        const platformIndex = Number(index) || 0;
        let thread = state.snsDmThreads.find(item => item.postId === postId && item.platformIndex === platformIndex);
        if (!thread) {
            const platform = post.platforms?.[platformIndex] || {};
            const character = getCharacter(post.characterId);
            thread = { id: makeId(), postId, platformIndex, characterId: post.characterId, title: `${platformLabel(platform.platform)}에서 시작된 DM`, context: snsPlatformContext(post, platform), messages: [{ from: 'character', name: character?.name || 'Character', body: '방금 올린 글 보고 DM한 거야?', createdAt: Date.now() }], createdAt: Date.now() };
            state.snsDmThreads.unshift(thread);
        }
        saveState().then(() => render());
    }

    async function sendSnsDm(threadId) {
        const thread = (state.snsDmThreads || []).find(item => item.id === threadId);
        const character = getCharacter(thread?.characterId);
        if (!thread || !character) return;
        const inlineInput = document.getElementById(`sns-dm-${threadId}`);
        const fullInput = document.getElementById('mg-sns-dm-input');
        const body = (inlineInput?.value || fullInput?.value || '').trim();
        if (!body) return;
        if (inlineInput) inlineInput.value = '';
        if (fullInput) fullInput.value = '';
        thread.messages.push({ from: 'user', name: state.config.userName || '나', body, createdAt: Date.now() });
        await saveState();
        render();
        try {
            const history = thread.messages.map(message => `${message.from === 'user' ? state.config.userName : character.name}: ${message.body}`).join('\n');
            const payload = await callLLM([
                { role: 'system', content: [`Act as ${character.name} in a private SNS DM thread that is separate from the normal chat room.`, `Character profile: ${character.prompt}`, `SNS post context:\n${thread.context || '(none)'}`, `Output language: ${state.config.language}.`, 'Return JSON: {"messages":[{"content":"..."}]}'].join('\n') },
                { role: 'user', content: `SNS DM history:\n${history}\n\nReply as ${character.name}.` }
            ], { maxTokens: 700 });
            const replies = normalizeReplyMessages(character, payload);
            for (const reply of replies.slice(0, 3)) if (reply.content || reply.imageCaption) thread.messages.push({ from: 'character', name: character.name, body: reply.content || reply.imageCaption || '', createdAt: Date.now() });
            await saveState();
        } catch (error) {
            thread.messages.push({ from: 'character', name: character.name, body: `DM reply failed: ${error.message}`, createdAt: Date.now() });
            await saveState();
        }
        render();
    }

    function snsPlatformContext(post, platform) {
        const comments = (platform.comments || []).slice(-mgSnsContextMessageLimit()).map(comment => `- ${comment.name || comment.handle || 'anon'}: ${comment.body}`).join('\n');
        return [`Post: ${platform.text || post.text || ''}`, platform.hashtags?.length ? `Hashtags: ${platform.hashtags.join(' ')}` : '', comments ? `Comments:\n${comments}` : ''].filter(Boolean).join('\n');
    }

    async function handleAvatarFileSelect(event) {
        const file = event.target.files?.[0];
        event.target.value = '';
        const character = currentCharacter();
        if (!file || !character) return;
        character.avatar = await fileToCompressedImage(file, 512, 512, 0.82);
        await saveState();
        render();
    }

    async function handleStickerFiles(event, target) {
        const files = Array.from(event.target.files || []);
        event.target.value = '';
        const character = currentCharacter();
        for (const file of files) {
            if (file.size > 30 * 1024 * 1024) { alert(`${file.name}은(는) 30MB를 초과합니다.`); continue; }
            const data = file.type.startsWith('image/') ? await fileToCompressedImage(file, 1024, 1024, 0.85) : await fileToDataUrl(file);
            const baseName = file.name.replace(/\.[^.]+$/, '');
            const description = prompt(`AI에게 전달할 스티커 설명을 입력하세요:\n${baseName}`, '') || '';
            const sticker = { id: makeId(), name: baseName, description: description.trim(), data, type: file.type || 'image/png', createdAt: Date.now() };
            if (target === 'character' && character) character.stickers.push(sticker);
            else state.userStickers.push(sticker);
        }
        await saveState();
        render();
    }

    function prepareUserSticker(id) {
        const sticker = state.userStickers.find(item => String(item.id) === String(id));
        if (!sticker) return;
        inputAttachment = { mediaType: 'sticker', mediaData: sticker.data, stickerName: sticker.name, stickerDescription: sticker.description || '', stickerId: sticker.id, type: sticker.type };
        showStickerPanel = false;
        render();
    }

    async function describeUserSticker(id) {
        const sticker = state.userStickers.find(item => String(item.id) === String(id));
        const description = sticker && prompt('AI에게 전달할 스티커 설명', sticker.description || '');
        if (description === null || !sticker) return;
        sticker.description = description.trim();
        await saveState();
        render();
    }

    async function describeCharacterSticker(id) {
        const character = currentCharacter();
        const sticker = character?.stickers?.find(item => String(item.id) === String(id));
        const description = sticker && prompt('AI에게 전달할 스티커 설명', sticker.description || '');
        if (description === null || !sticker) return;
        sticker.description = description.trim();
        await saveState();
        render();
    }

