        const hashtags = Array.isArray(item.hashtags) && item.hashtags.length ? `<div class="mg-hashtags">${item.hashtags.slice(0, 4).map(tag => escapeHtml(String(tag).startsWith('#') ? tag : `#${tag}`)).join(' ')}</div>` : '';
        return `<section class="mg-sns-card mg-x-post"><div class="mg-x-avatar">${avatarHtml(character, 'small')}</div><div class="mg-x-body"><div class="mg-x-head"><div><b>${escapeHtml(item.displayName || character?.name || 'Character')}</b><span>@${escapeHtml(handle)} · ${escapeHtml(item.time || formatTime(post.createdAt))}</span></div><button class="mg-icon" data-action="delete-sns-post" data-id="${escapeHtml(post.id)}">×</button></div><p class="mg-x-text">${escapeHtml(item.text || '')}</p>${hashtags}${rawImage ? `<img class="mg-post-img mg-x-img" loading="lazy" decoding="async" src="${escapeHtml(image)}" alt="" data-action="open-sns-image" data-id="${escapeHtml(post.id)}" data-index="${index}">` : ''}<div class="mg-x-actions"><button data-action="focus-sns-comment" data-id="${escapeHtml(post.id)}" data-index="${index}">댓글 ${commentCount}</button><button>재게시 ${Number(stats.reposts) || 0}</button><button data-action="like-sns-post" data-id="${escapeHtml(post.id)}">좋아요 ${Number(stats.likes) || 0}</button><button>공유</button><button class="mg-sns-dm-cta" data-action="open-sns-dm" data-id="${escapeHtml(post.id)}" data-index="${index}">SNS DM 보내기</button></div><div class="mg-sns-reply"><input class="mg-field" id="sns-comment-${escapeHtml(post.id)}-${index}" placeholder="답글 게시하기"><button class="mg-btn" data-action="add-sns-comment" data-id="${escapeHtml(post.id)}" data-index="${index}">답글</button></div>${mgV10CommentsBlock(post, item, index, character, 'mg-x-comments')}</div></section>`;
