    // --- v14: background settings popover + bubble opacity controls ---
    let mgV14RoomBgSettingsOpen = false;

    function mgV14Clamp(value, min, max, fallback) {
        const number = Number(value);
        if (!Number.isFinite(number)) return fallback;
        return Math.max(min, Math.min(max, number));
    }

    function mgV14BubbleOpacityValue() {
        state.config.bubbleOpacity = Math.round(mgV14Clamp(state.config.bubbleOpacity, 25, 100, 92));
        return state.config.bubbleOpacity;
    }

    function mgV14ApplyBubbleOpacity() {
        const value = mgV14BubbleOpacityValue();
        document.documentElement.style.setProperty('--mg-bubble-opacity-percent', `${value}%`);
    }

    const mgBaseApplyFontScaleV14 = applyFontScale;
    applyFontScale = function() {
        mgBaseApplyFontScaleV14();
        mgV14ApplyBubbleOpacity();
    };

    function mgV14BubbleSettingsHtml() {
        const value = mgV14BubbleOpacityValue();
        return `<div class="mg-section mg-v14-bubble-settings"><h3>말풍선</h3><p class="mg-help">배경 사진이 더 잘 보이게 1:1 DM 말풍선 배경 투명도를 조정합니다. 글자는 흐려지지 않게 말풍선 배경색만 조절해요.</p><label class="mg-v14-wide-slider"><span>말풍선 불투명도</span><input id="ui-bubble-opacity" type="range" min="25" max="100" value="${escapeHtml(value)}"><output>${escapeHtml(value)}%</output></label><div class="mg-inline" style="justify-content:flex-end;margin-top:12px"><button class="mg-btn primary" data-action="save-appearance">화면 설정 저장</button></div></div>`;
    }

    const mgBaseAppearanceHtmlV14 = appearanceHtml;
    appearanceHtml = function() {
        let html = mgBaseAppearanceHtmlV14();
        if (html.includes('id="ui-bubble-opacity"')) return html;
        const block = mgV14BubbleSettingsHtml();
        if (html.includes('</section>')) return html.replace('</section>', `${block}</section>`);
        return `${html}${block}`;
    };

    const mgBaseSaveAppearanceFromFormV14 = saveAppearanceFromForm;
    saveAppearanceFromForm = async function() {
        const input = document.getElementById('ui-bubble-opacity');
        if (input) state.config.bubbleOpacity = Math.round(mgV14Clamp(input.value, 25, 100, mgV14BubbleOpacityValue()));
        mgV14ApplyBubbleOpacity();
        await mgBaseSaveAppearanceFromFormV14();
        mgV14ApplyBubbleOpacity();
    };

    function mgV14RoomThemePanelHtml() {
        if (!mgV14RoomBgSettingsOpen || !mgV8IsOneToOneChat()) return '';
        const room = getCurrentRoom();
        const theme = mgRoomThemeFor(room);
        const hasImage = Boolean(String(theme.backgroundImage || ''));
        return `<aside class="mg-room-theme-popover mg-v14-room-bg-settings"><div class="mg-room-theme-popover-head"><div><strong>DM 배경 설정</strong><span>${hasImage ? '현재 방에 배경 적용됨' : '배경 사진 없음'}</span></div><button class="mg-icon" type="button" title="닫기" data-action="toggle-room-theme-panel">×</button></div><div class="mg-room-theme-popover-actions"><button class="mg-btn" type="button" data-action="pick-room-bg">배경사진</button><button class="mg-btn danger" type="button" data-action="clear-room-bg">배경 삭제</button></div><label class="mg-v14-wide-slider"><span>사진 진하기</span><input id="chat-room-bg-opacity" type="range" min="0" max="100" value="${escapeHtml(theme.backgroundOpacity)}"><output>${escapeHtml(theme.backgroundOpacity)}%</output></label><label class="mg-v14-wide-slider"><span>어둡게</span><input id="chat-room-bg-dim" type="range" min="0" max="90" value="${escapeHtml(theme.backgroundDim)}"><output>${escapeHtml(theme.backgroundDim)}%</output></label><label class="mg-v14-wide-slider"><span>블러</span><input id="chat-room-bg-blur" type="range" min="0" max="24" value="${escapeHtml(theme.backgroundBlur)}"><output>${escapeHtml(theme.backgroundBlur)}px</output></label><p class="mg-help">배경사진 버튼은 바로 사진을 바꾸고, 삭제는 이 설정 안에서만 처리되게 했어.</p><div class="mg-inline" style="justify-content:flex-end"><button class="mg-btn primary" type="button" data-action="save-room-theme">적용</button></div></aside>`;
    }

    function mgV14UpdateRoomThemeFromPanel({ persist = false } = {}) {
        const room = getCurrentRoom();
        if (!room) return;
        const theme = mgRoomThemeFor(room);
        const opacityInput = document.getElementById('chat-room-bg-opacity');
        const dimInput = document.getElementById('chat-room-bg-dim');
        const blurInput = document.getElementById('chat-room-bg-blur');
        if (opacityInput) theme.backgroundOpacity = Math.round(mgV14Clamp(opacityInput.value, 0, 100, theme.backgroundOpacity));
        if (dimInput) theme.backgroundDim = Math.round(mgV14Clamp(dimInput.value, 0, 90, theme.backgroundDim));
        if (blurInput) theme.backgroundBlur = Math.round(mgV14Clamp(blurInput.value, 0, 24, theme.backgroundBlur));
        const panel = document.querySelector('.mg-room-themed');
        if (panel) panel.setAttribute('style', mgRoomThemeStyleAttr(room));
        document.querySelectorAll('#chat-room-bg-opacity,#chat-room-bg-dim,#chat-room-bg-blur').forEach(input => {
            const output = input.closest('label')?.querySelector('output');
            if (output) output.textContent = `${input.value}${input.id === 'chat-room-bg-blur' ? 'px' : '%'}`;
        });
        if (persist) saveState();
    }

    const mgBaseAppHtmlV14 = appHtml;
    appHtml = function() {
        let html = mgBaseAppHtmlV14();
        html = html
            .replace(/<aside class="mg-room-theme-popover[\s\S]*?<\/aside>/g, '')
            .replace(/<div class="mg-room-theme-bar"[\s\S]*?<\/div>/g, '')
            .replace(/<button class="mg-btn mg-top-extra"[^>]*data-action="pick-room-bg"[^>]*>배경사진<\/button>/g, '')
            .replace(/<button class="mg-btn mg-top-extra"[^>]*data-action="clear-room-bg"[^>]*>배경삭제<\/button>/g, '')
            .replace(/<button class="mg-btn mg-top-extra"[^>]*data-action="toggle-room-theme-panel"[^>]*>배경(?:설정)?<\/button>/g, '')
            .replace(/<button class="mg-icon mg-top-extra"[^>]*data-action="clear-room-bg"[^>]*>▧<\/button>/g, '');
        if (mgV8IsOneToOneChat()) {
            const buttons = '<button class="mg-btn mg-top-extra" title="현재 DM 방 배경사진 적용" data-action="pick-room-bg">배경사진</button><button class="mg-btn mg-top-extra" title="현재 DM 방 배경 설정" data-action="toggle-room-theme-panel">배경설정</button>';
            const target = /(<button class="mg-btn mg-top-extra"[^>]*data-action="tab" data-tab="social"[^>]*>SNS<\/button>)/;
            html = target.test(html) ? html.replace(target, `$1${buttons}`) : html.replace('<div class="mg-actions">', `<div class="mg-actions">${buttons}`);
            const panel = mgV14RoomThemePanelHtml();
            if (panel) html = html.includes('</main>') ? html.replace('</main>', `</main>${panel}`) : `${html}${panel}`;
        } else {
            mgV14RoomBgSettingsOpen = false;
        }
        return html;
    };

    const mgBaseHandleActionV14 = handleAction;
    handleAction = async function(action, element) {
        if (action === 'toggle-room-theme-panel') { mgV14RoomBgSettingsOpen = !mgV14RoomBgSettingsOpen; render(); return; }
        if (action === 'pick-room-bg') { mgV14RoomBgSettingsOpen = true; return document.getElementById('mg-file-room-bg')?.click(); }
        if (action === 'clear-room-bg') { mgV14RoomBgSettingsOpen = true; await mgClearRoomBackground(); return; }
        if (action === 'save-room-theme') { mgV14UpdateRoomThemeFromPanel({ persist: true }); await saveState(); render(); return; }
        return mgBaseHandleActionV14(action, element);
    };

    const mgBaseBindEventsV14 = bindEvents;
    bindEvents = function() {
        mgBaseBindEventsV14();
        const bubble = document.getElementById('ui-bubble-opacity');
        if (bubble && !bubble.dataset.v14Bound) {
            bubble.dataset.v14Bound = '1';
            const update = () => {
                state.config.bubbleOpacity = Math.round(mgV14Clamp(bubble.value, 25, 100, mgV14BubbleOpacityValue()));
                mgV14ApplyBubbleOpacity();
                const output = bubble.closest('label')?.querySelector('output');
                if (output) output.textContent = `${state.config.bubbleOpacity}%`;
                saveState();
            };
            bubble.addEventListener('input', update);
            bubble.addEventListener('change', update);
        }
        document.querySelectorAll('#chat-room-bg-opacity,#chat-room-bg-dim,#chat-room-bg-blur').forEach(input => {
            if (input.dataset.v14RoomThemeBound) return;
            input.dataset.v14RoomThemeBound = '1';
            input.addEventListener('input', () => mgV14UpdateRoomThemeFromPanel({ persist: true }));
            input.addEventListener('change', () => mgV14UpdateRoomThemeFromPanel({ persist: true }));
        });
    };

    const mgBaseHandleRoomBackgroundFileV14 = mgHandleRoomBackgroundFile;
    mgHandleRoomBackgroundFile = async function(event) {
        const room = getCurrentRoom();
        const themeBefore = room ? mgRoomThemeFor(room) : null;
        const hadImage = Boolean(String(themeBefore?.backgroundImage || ''));
        await mgBaseHandleRoomBackgroundFileV14(event);
        const theme = room ? mgRoomThemeFor(room) : null;
        if (theme && String(theme.backgroundImage || '') && !hadImage) {
            theme.backgroundOpacity = Math.max(Number(theme.backgroundOpacity) || 0, 70);
            theme.backgroundDim = Math.min(Number(theme.backgroundDim) || 0, 16);
            theme.backgroundBlur = Math.min(Number(theme.backgroundBlur) || 0, 2);
            await saveState();
            render();
        }
    };

    const mgBaseInjectStylesV14 = injectStyles;
    injectStyles = function() {
        mgBaseInjectStylesV14();
        mgV14ApplyBubbleOpacity();
        if (document.getElementById('mg-v14-bg-bubble-style')) return;
        const style = document.createElement('style');
        style.id = 'mg-v14-bg-bubble-style';
        style.textContent = `
            .mg-v14-bubble-settings{display:grid!important;gap:10px!important}
            .mg-v14-wide-slider{display:grid;grid-template-columns:92px minmax(120px,1fr) 46px;gap:10px;align-items:center;color:var(--muted);font-size:12px}
            .mg-v14-wide-slider input{width:100%;accent-color:var(--accent)}.mg-v14-wide-slider output{font-variant-numeric:tabular-nums;text-align:right;color:var(--sub);font-size:11px}
            .mg-room-theme-popover.mg-v14-room-bg-settings{display:grid!important;position:fixed!important;top:64px!important;right:16px!important;z-index:90!important;width:min(430px,calc(100vw - 28px))!important;box-sizing:border-box!important;border:1px solid var(--border2)!important;border-radius:14px!important;background:color-mix(in srgb,var(--panel),#000 10%)!important;box-shadow:var(--shadow)!important;padding:13px!important;gap:12px!important;backdrop-filter:blur(12px)!important}
            .mg-v14-room-bg-settings .mg-room-theme-popover-actions{display:flex!important;gap:8px!important;flex-wrap:wrap!important}.mg-v14-room-bg-settings .mg-help{margin:0!important;font-size:11px!important;color:var(--muted)!important;line-height:1.45!important}
            .mg-message:not(.user):not(.system) .mg-bubble:not(.media-only){background:color-mix(in srgb,var(--surface2) var(--mg-bubble-opacity-percent,92%),transparent)!important;backdrop-filter:blur(2px)}
            .mg-message.user .mg-bubble:not(.media-only){background:color-mix(in srgb,var(--accent) var(--mg-bubble-opacity-percent,92%),transparent)!important;backdrop-filter:blur(2px)}
            .mg-message.system .mg-bubble:not(.media-only){background:color-mix(in srgb,var(--surface) var(--mg-bubble-opacity-percent,92%),transparent)!important;backdrop-filter:blur(2px)}
            /* v20: removed whole-bubble opacity fallback; text must stay opaque */
            @media(max-width:780px){.mg-room-theme-popover.mg-v14-room-bg-settings{top:58px!important;right:8px!important;width:calc(100vw - 16px)!important}.mg-v14-wide-slider{grid-template-columns:76px minmax(96px,1fr) 42px}}
        `;
        document.head.appendChild(style);
    };


    // --- v15: compact DM background bounds + room-local bubble opacity + rollback SNS commenter world naming ---
    function mgV15Number(value, min, max, fallback) {
        const number = Number(value);
        if (!Number.isFinite(number)) return fallback;
        return Math.max(min, Math.min(max, number));
    }

    function mgV15RoomBubbleOpacity(room = getCurrentRoom()) {
        const theme = room ? mgRoomThemeFor(room) : null;
        if (theme && theme.bubbleOpacity !== undefined) return Math.round(mgV15Number(theme.bubbleOpacity, 25, 100, 92));
        return Math.round(mgV15Number(state.config?.bubbleOpacity, 25, 100, 92));
    }

    const mgBaseRoomThemeStyleAttrV15 = mgRoomThemeStyleAttr;
    mgRoomThemeStyleAttr = function(room) {
        const base = String(mgBaseRoomThemeStyleAttrV15(room) || '');
        const opacity = mgV15RoomBubbleOpacity(room);
        return `${base}${base.endsWith(';') ? '' : ';'}--mg-bubble-opacity-percent:${opacity}%;`;
    };

    const mgBaseAppearanceHtmlV15 = appearanceHtml;
    appearanceHtml = function() {
        let html = (typeof mgBaseAppearanceHtmlV14 === 'function' ? mgBaseAppearanceHtmlV14() : mgBaseAppearanceHtmlV15());
        html = html.replace(/<div class="mg-section mg-v14-bubble-settings">[\s\S]*?<\/div><\/div>/g, '');
        html = html.replace(/<div class="mg-section mg-v14-bubble-settings">[\s\S]*?<\/div>/g, '');
        return html;
    };

    mgV14RoomThemePanelHtml = function() {
        if (!mgV14RoomBgSettingsOpen || !mgV8IsOneToOneChat()) return '';
        const room = getCurrentRoom();
        const theme = mgRoomThemeFor(room);
        theme.bubbleOpacity = mgV15RoomBubbleOpacity(room);
        const hasImage = Boolean(String(theme.backgroundImage || ''));
        return `<aside class="mg-room-theme-popover mg-v14-room-bg-settings mg-v15-room-bg-settings"><div class="mg-room-theme-popover-head"><div><strong>DM 배경 설정</strong><span>${hasImage ? '현재 방에 배경 적용됨' : '배경 사진 없음'}</span></div><button class="mg-icon" type="button" title="닫기" data-action="toggle-room-theme-panel">×</button></div><div class="mg-room-theme-popover-actions"><button class="mg-btn danger" type="button" data-action="clear-room-bg">배경 삭제</button></div><label class="mg-v14-wide-slider"><span>사진 진하기</span><input id="chat-room-bg-opacity" type="range" min="0" max="100" value="${escapeHtml(theme.backgroundOpacity)}"><output>${escapeHtml(theme.backgroundOpacity)}%</output></label><label class="mg-v14-wide-slider"><span>어둡게</span><input id="chat-room-bg-dim" type="range" min="0" max="90" value="${escapeHtml(theme.backgroundDim)}"><output>${escapeHtml(theme.backgroundDim)}%</output></label><label class="mg-v14-wide-slider"><span>블러</span><input id="chat-room-bg-blur" type="range" min="0" max="24" value="${escapeHtml(theme.backgroundBlur)}"><output>${escapeHtml(theme.backgroundBlur)}px</output></label><label class="mg-v14-wide-slider"><span>말풍선</span><input id="chat-bubble-opacity" type="range" min="25" max="100" value="${escapeHtml(theme.bubbleOpacity)}"><output>${escapeHtml(theme.bubbleOpacity)}%</output></label><div class="mg-inline" style="justify-content:flex-end"><button class="mg-btn primary" type="button" data-action="save-room-theme">적용</button></div></aside>`;
    };

    mgV14UpdateRoomThemeFromPanel = function({ persist = false } = {}) {
        const room = getCurrentRoom();
        if (!room) return;
        const theme = mgRoomThemeFor(room);
        const opacityInput = document.getElementById('chat-room-bg-opacity');
        const dimInput = document.getElementById('chat-room-bg-dim');
        const blurInput = document.getElementById('chat-room-bg-blur');
        const bubbleInput = document.getElementById('chat-bubble-opacity');
        if (opacityInput) theme.backgroundOpacity = Math.round(mgV15Number(opacityInput.value, 0, 100, theme.backgroundOpacity));
        if (dimInput) theme.backgroundDim = Math.round(mgV15Number(dimInput.value, 0, 90, theme.backgroundDim));
        if (blurInput) theme.backgroundBlur = Math.round(mgV15Number(blurInput.value, 0, 24, theme.backgroundBlur));
        if (bubbleInput) theme.bubbleOpacity = Math.round(mgV15Number(bubbleInput.value, 25, 100, mgV15RoomBubbleOpacity(room)));
        const panel = document.querySelector('.mg-room-themed');
        if (panel) panel.setAttribute('style', mgRoomThemeStyleAttr(room));
        document.querySelectorAll('#chat-room-bg-opacity,#chat-room-bg-dim,#chat-room-bg-blur,#chat-bubble-opacity').forEach(input => {
            const output = input.closest('label')?.querySelector('output');
            if (output) output.textContent = `${input.value}${input.id === 'chat-room-bg-blur' ? 'px' : '%'}`;
        });
        if (persist) saveState();
    };

    const mgBaseBindEventsV15 = bindEvents;
    bindEvents = function() {
        mgBaseBindEventsV15();
        const bubble = document.getElementById('chat-bubble-opacity');
        if (bubble && !bubble.dataset.v15RoomBubbleBound) {
            bubble.dataset.v15RoomBubbleBound = '1';
            bubble.addEventListener('input', () => mgV14UpdateRoomThemeFromPanel({ persist: true }));
            bubble.addEventListener('change', () => mgV14UpdateRoomThemeFromPanel({ persist: true }));
        }
    };

    const mgBaseHandleRoomBackgroundFileV15 = mgHandleRoomBackgroundFile;
    mgHandleRoomBackgroundFile = async function(event) {
        await mgBaseHandleRoomBackgroundFileV15(event);
        const room = getCurrentRoom();
        const theme = room ? mgRoomThemeFor(room) : null;
        if (theme && String(theme.backgroundImage || '')) {
            theme.bubbleOpacity = Math.round(mgV15Number(theme.bubbleOpacity, 25, 100, 88));
            await saveState();
        }
    };

    // Roll back v13 world/lore-based commenter-name coercion. Keep model-provided names and generic fallbacks.
    if (typeof mgBaseBuildSnsPostMessagesV13 === 'function') buildSnsPostMessages = mgBaseBuildSnsPostMessagesV13;

    mgV12GeneratedComment = function(post, item, character, seed = 0) {
        const anonymous = Boolean(mgSnsV5SnsForCharacter(character).anonymous);
        const name = anonymous ? '익명' : MG_V12_FOLLOWER_NAMES[seed % MG_V12_FOLLOWER_NAMES.length];
        const handle = anonymous ? '' : `user${String(seed + 1).padStart(2, '0')}`;
        const text = String(item?.text || post?.text || '').trim();
        const base = MG_V12_COMMENT_BODIES[seed % MG_V12_COMMENT_BODIES.length];
        const body = text.length > 50 && seed % 3 === 1 ? '아니 이 글 문장 하나하나가 너무 의미심장한데.' : base;
        return { id: `auto_${makeId()}`, name, handle, body, likes: Math.floor(Math.random() * 7), createdAt: Date.now() - Math.floor(Math.random() * 900000) };
    };

    mgV13CommentEntries = function(item) {
        item.comments = Array.isArray(item?.comments) ? item.comments.map(mgV12NormalizeComment).filter(Boolean) : [];
        return item.comments.map((comment, originalIndex) => ({ comment, originalIndex }));
    };

    mgV12CommentEntries = function(item) {
        return mgV13CommentEntries(item);
    };

    mgV12EnsureGeneratedCommentCount = function(item, post, character = currentCharacter()) {
        if (!item) return 0;
        item.stats = item.stats && typeof item.stats === 'object' ? item.stats : {};
        item.comments = Array.isArray(item.comments) ? item.comments.map(mgV12NormalizeComment).filter(Boolean) : [];
        const actual = item.comments.length;
        const statTarget = Math.floor(Number(item.stats.replies) || 0);
        const previousFloor = Math.floor(Number(item._mgV15ReplyFloor) || Number(item._mgV13ReplyFloor) || Number(item._mgV12ReplyFloor) || 0);
        const target = Math.min(30, Math.max(actual, statTarget, previousFloor));
        if (target > actual) {
            for (let i = actual; i < target; i++) item.comments.push(mgV12GeneratedComment(post, item, character, i));
        }
        const count = item.comments.length;
        item._mgV15ReplyFloor = count;
        item._mgV13ReplyFloor = count;
        item.stats.replies = count;
        return count;
    };

    mgV11SyncCommentCount = function(item, post = null, character = currentCharacter()) {
        return mgV12EnsureGeneratedCommentCount(item, post, character);
    };
    mgV11AllCommentEntries = function(item) { return mgV12CommentEntries(item); };
    mgSnsV4VisibleComments = function(item) { return mgV12CommentEntries(item).map(entry => entry.comment); };
    mgV11CommentsBlock = function(post, item, index, character, extraClass = '') {
        mgV12EnsureGeneratedCommentCount(item, post, character);
        const entries = mgV12CommentEntries(item);
        if (!entries.length) return '';
        return `<div class="mg-comments ${extraClass}" data-post-id="${escapeHtml(post.id)}" data-index="${index}" data-comment-total="${entries.length}">${entries.map(entry => mgSnsV4CommentHtml(post, index, entry.comment, entry.originalIndex, character)).join('')}</div>`;
    };
    mgV7SnsCommentsBlock = mgV11CommentsBlock;
    mgV7VisibleCommentEntries = function(item) {
        const all = mgV12CommentEntries(item);
        return { all, visible: all, hiddenCount: 0 };
    };

    const mgBaseSaveStateV15 = saveState;
    saveState = async function() {
        try {
            for (const post of state.snsPosts || []) {
                const character = getCharacter(post?.characterId) || currentCharacter();
                for (const item of post.platforms || []) mgV12EnsureGeneratedCommentCount(item, post, character);
            }
        } catch (error) {
            console.warn('[MessengerGod] v15 SNS comment stabilization skipped:', error);
        }
        return mgBaseSaveStateV15();
    };

    const mgBaseInjectStylesV15 = injectStyles;
