        const anonymous = Boolean(state.config?.sns?.anonymous);
        const names = anonymous ? ['익명'] : ['구독계', '지나가다봄', '알림켜둔사람', '새벽타임라인', '친구의친구', '눈팅러', '오늘도옴', '모브계', '옆집계정', '스크롤멈춤'];
        const pool = [];
        const add = (...items) => pool.push(...items.filter(Boolean));
