        if (/아침|햇살|morning|sunlight/i.test(source)) add('아침부터 이런 문장 보면 하루가 이상해짐', '햇빛 얘기인데 왜 마음이 좀 찔림', '일찍 깬 사람 감성 맞네');
        if (/비|우산|흐림|rain/i.test(source)) add('비 오는 날이라 더 그렇게 보이는 건가', '습도까지 같이 느껴짐', '우산 들고 읽어야 할 글 같음');
        if (/사진|셀카|거울|image|photo|selfie/i.test(source)) add('사진이랑 글 온도 차이 뭐야', '이 컷 올리고 아무 말 없는 척하는 게 제일 수상함', '구도보다 표정이 더 말 많은데');
        if (/질투|보고싶|외로|좋아|사랑|마음|miss|love/i.test(source)) add('숨긴다고 숨겨지는 글이 아닌데', '이건 특정인 저격 맞지', '읽는 사람 마음 불편하게 잘 쓴다');
