    const mgV24CommentJobs = new Set();
    async function mgV24AddSnsComment(postId, index = 0) {
        const platformIndex = Number(index) || 0;
        const jobKey = `${postId}:${platformIndex}`;
        if (mgV24CommentJobs.has(jobKey)) return;
        const post = (state.snsPosts || []).find(item => String(item.id) === String(postId));
        const platform = post?.platforms?.[platformIndex];
        const character = getCharacter(post?.characterId) || currentCharacter();
        if (!post || !platform || !character) return;
        const input = document.getElementById(`sns-comment-${postId}-${platformIndex}`);
        const body = typeof mgV12CommentText === 'function'
            ? mgV12CommentText({ body: input?.value || '' })
            : String(input?.value || '').trim();
        if (!body) return;
        mgV24CommentJobs.add(jobKey);
        try {
            if (input) input.value = '';
            const now = Date.now();
            const sns = mgV24SnsForLimit(platform, post, character);
            platform.comments = Array.isArray(platform.comments) ? platform.comments.filter(comment => !comment.pending) : [];
            mgV24CapGeneratedComments(platform, sns, post, character);
            const anonymous = Boolean(sns?.anonymous);
            platform.comments.push({ id: `user_${makeId()}`, name: anonymous ? '익명' : userNameFor(character), handle: anonymous ? '' : 'me', body, likes: 0, isUser: true, createdAt: now });
            const pendingId = `char_${makeId()}`;
            platform.comments.push({ id: pendingId, name: character.name, handle: platform.handle || character.handle || character.id, body: '답댓 쓰는 중…', likes: 0, isCharacter: true, pending: true, createdAt: now + 1 });
            mgV12EnsureGeneratedCommentCount(platform, post, character);
            if (typeof mgSnsV5LastCommentTarget !== 'undefined') mgSnsV5LastCommentTarget = { postId: String(postId), index: platformIndex };
            await saveState();
            render();
            try { mgV11ScrollCommentBox(postId, platformIndex); } catch (_) {}

            const reply = await mgV12DirectSnsReply(character, post, platform, body);
            const pending = platform.comments.find(comment => comment.id === pendingId);
            if (pending) {
                pending.body = reply || '봤어.';
                delete pending.pending;
            } else {
                platform.comments.push({ id: `char_${makeId()}`, name: character.name, handle: platform.handle || character.handle || character.id, body: reply || '봤어.', likes: 0, isCharacter: true, createdAt: Date.now() });
            }
            mgV12EnsureGeneratedCommentCount(platform, post, character);
            if (typeof mgSnsV5LastCommentTarget !== 'undefined') mgSnsV5LastCommentTarget = { postId: String(postId), index: platformIndex };
            await saveState();
            render();
            try { mgV11ScrollCommentBox(postId, platformIndex); } catch (_) {}
        } finally {
            mgV24CommentJobs.delete(jobKey);
        }
    }

