    function mgV24InstallSnsCommentCapture() {
        if (document.__mgV24SnsCommentCapture) return;
        document.__mgV24SnsCommentCapture = true;
        document.addEventListener('click', event => {
            const button = event.target?.closest?.('[data-action="add-sns-comment"]');
            if (!button) return;
            event.preventDefault();
            event.stopPropagation();
            event.stopImmediatePropagation();
            mgV24AddSnsComment(button.dataset.id, button.dataset.index);
        }, true);
        document.addEventListener('keydown', event => {
            const input = event.target?.closest?.('.mg-sns-reply input[id^="sns-comment-"]');
            if (!input || event.key !== 'Enter' || event.shiftKey || event.isComposing) return;
            const match = input.id.match(/^sns-comment-(.+)-(\d+)$/);
            if (!match) return;
            event.preventDefault();
            event.stopPropagation();
            event.stopImmediatePropagation();
            mgV24AddSnsComment(match[1], match[2]);
        }, true);
    }

