    function mgV29RemoveExtraPngPreviewRow(html) {
        return String(html || '').replace(/<div class="mg-sns-export-row">[\s\S]*?<\/div>/g, '');
    }

    function mgV29FeedImageButtonHtml(post, index, label = '피드 이미지') {
        return `<button class="mg-sns-feed-export-btn" type="button" data-action="download-sns-post" data-id="${escapeHtml(post?.id || '')}" data-index="${escapeHtml(index)}">${escapeHtml(label)}</button>`;
    }

    function mgV29WireShareButtons(html, post, index, mode = 'twitter') {
        let output = mgV29RemoveExtraPngPreviewRow(html);
        const button = mgV29FeedImageButtonHtml(post, index, mode === 'instagram' ? '피드 이미지' : '피드 이미지');
        // X/Twitter 카드의 무동작 공유 버튼을 이미지 출력 버튼으로 교체.
        output = output.replace(/<button>\s*공유\s*<\/button>/g, button);
        // Instagram 카드의 무동작 저장 버튼도 같은 기능으로 교체.
        output = output.replace(/<button>\s*저장\s*<\/button>/g, button);
        return output;
    }

    if (typeof twitterPostHtml === 'function') {
        const mgBaseTwitterPostHtmlV29 = twitterPostHtml;
        twitterPostHtml = function(post, item, index, character) {
            return mgV29WireShareButtons(mgBaseTwitterPostHtmlV29(post, item, index, character), post, index, 'twitter');
        };
    }

    if (typeof instagramPostHtml === 'function') {
        const mgBaseInstagramPostHtmlV29 = instagramPostHtml;
        instagramPostHtml = function(post, item, index, character) {
            return mgV29WireShareButtons(mgBaseInstagramPostHtmlV29(post, item, index, character), post, index, 'instagram');
        };
    }


    // ===== v30: platform-specific SNS feed image exporter =====
    // "피드 이미지"는 이제 플랫폼에 맞춰 서로 다른 캔버스 템플릿으로 렌더한다.
    // - Twitter/X: 다크 X 포스트 카드 느낌
    // - Instagram: 실제 인스타 피드 캡처 느낌
    function mgV30CanvasFont(weight, size, family = 'Segoe UI, Apple SD Gothic Neo, Malgun Gothic, Arial, sans-serif') {
        return `${weight} ${size}px ${family}`;
    }

    function mgV30ClampText(value, max = 1000) {
        const text = String(value || '').replace(/\s+/g, ' ').trim();
        return text.length > max ? `${text.slice(0, max - 1).trim()}…` : text;
    }

    function mgV30HashtagsText(item) {
        const tags = Array.isArray(item?.hashtags) ? item.hashtags : [];
        return tags
            .map(tag => String(tag || '').trim())
            .filter(Boolean)
            .slice(0, 6)
            .map(tag => tag.startsWith('#') ? tag : `#${tag.replace(/^#+/, '')}`)
            .join(' ');
    }

    function mgV30CommentCount(item) {
        const comments = Array.isArray(item?.comments) ? item.comments : [];
        return Number(item?.stats?.replies) || comments.length || 0;
    }

    function mgV30Likes(item) {
        return Number(item?.stats?.likes) || 0;
    }

    function mgV30SafeHandle(item, character) {
        return String(item?.handle || character?.handle || character?.id || character?.name || 'user').replace(/^@/, '') || 'user';
    }

    function mgV30DisplayName(item, character) {
        return String(item?.displayName || character?.name || 'Character');
    }

    function mgV30WrapText(ctx, text, maxWidth, maxLines = 999) {
        const source = String(text || '').split('\n');
        const lines = [];
        for (const rawLine of source) {
            const chunks = rawLine.includes(' ') ? rawLine.split(/(\s+)/).filter(Boolean) : Array.from(rawLine);
            let line = '';
            for (const chunk of chunks) {
                const test = `${line}${chunk}`;
                if (line && ctx.measureText(test).width > maxWidth) {
                    lines.push(line.trimEnd());
                    line = chunk.trimStart ? chunk.trimStart() : chunk;
                    if (lines.length >= maxLines) {
                        lines[lines.length - 1] = `${lines[lines.length - 1].replace(/…$/, '')}…`;
                        return lines;
                    }
                } else {
                    line = test;
                }
            }
            if (line.trim()) {
                lines.push(line.trimEnd());
                if (lines.length >= maxLines) {
                    lines[lines.length - 1] = `${lines[lines.length - 1].replace(/…$/, '')}…`;
                    return lines;
                }
            }
        }
        return lines;
    }

    function mgV30FillWrappedText(ctx, text, x, y, maxWidth, lineHeight, maxLines = 999) {
        const lines = mgV30WrapText(ctx, text, maxWidth, maxLines);
        for (const line of lines) {
            ctx.fillText(line, x, y);
            y += lineHeight;
        }
        return { y, lines };
    }

    function mgV30RoundRectPath(ctx, x, y, w, h, r) {
        roundedCanvasRect(ctx, x, y, w, h, r);
    }

    function mgV30FillRoundRect(ctx, x, y, w, h, r, fill) {
        ctx.save();
        mgV30RoundRectPath(ctx, x, y, w, h, r);
        ctx.fillStyle = fill;
        ctx.fill();
        ctx.restore();
    }

    function mgV30StrokeRoundRect(ctx, x, y, w, h, r, stroke, lineWidth = 1) {
        ctx.save();
        mgV30RoundRectPath(ctx, x, y, w, h, r);
        ctx.strokeStyle = stroke;
        ctx.lineWidth = lineWidth;
        ctx.stroke();
        ctx.restore();
    }

    function mgV30DrawCircleImageOrInitial(ctx, image, x, y, size, label, bg = '#8bd3dd', fg = '#061112') {
        ctx.save();
        ctx.beginPath();
        ctx.arc(x + size / 2, y + size / 2, size / 2, 0, Math.PI * 2);
        ctx.closePath();
        if (image) {
            ctx.clip();
            ctx.drawImage(image, x, y, size, size);
        } else {
            ctx.fillStyle = bg || '#8bd3dd';
            ctx.fill();
            ctx.fillStyle = fg;
            ctx.font = mgV30CanvasFont('900', Math.round(size * 0.38));
            ctx.textAlign = 'center';
            ctx.textBaseline = 'middle';
            ctx.fillText(String(label || '?').slice(0, 2), x + size / 2, y + size / 2 + 1);
            ctx.textAlign = 'left';
            ctx.textBaseline = 'alphabetic';
        }
        ctx.restore();
    }

    function mgV30DrawImageCover(ctx, image, x, y, w, h) {
        if (!image) return;
        const iw = image.naturalWidth || image.width || w;
        const ih = image.naturalHeight || image.height || h;
        const scale = Math.max(w / iw, h / ih);
        const sw = w / scale;
        const sh = h / scale;
        const sx = (iw - sw) / 2;
        const sy = (ih - sh) / 2;
        ctx.drawImage(image, sx, sy, sw, sh, x, y, w, h);
    }

    function mgV30DrawImageFit(ctx, image, x, y, w, h, fill = '#101417') {
        if (!image) return;
        const iw = image.naturalWidth || image.width || w;
        const ih = image.naturalHeight || image.height || h;
        const scale = Math.min(w / iw, h / ih);
        const dw = iw * scale;
        const dh = ih * scale;
        const dx = x + (w - dw) / 2;
        const dy = y + (h - dh) / 2;
        ctx.fillStyle = fill;
        ctx.fillRect(x, y, w, h);
        ctx.drawImage(image, dx, dy, dw, dh);
    }

    async function mgV30LoadFeedAssets(post, item, index, character) {
        const avatarData = characterAvatarData(character);
        const avatarSrc = avatarData ? mediaDisplayUrl(avatarData, `feed-v30-avatar-${character?.id || character?.name || ''}`) : '';
        const imageSrc = item?.image ? mediaDisplayUrl(item.image, `feed-v30-sns-${post?.id || 'post'}-${index}`) : '';
        const [avatarImage, postImage] = await Promise.all([
            loadCanvasImage(avatarSrc),
            loadCanvasImage(imageSrc)
        ]);
        return { avatarImage, postImage };
    }

    function mgV30ExportModal(post, item, platform, data) {
        const handle = String(item?.handle || 'sns').replace(/[^\w가-힣-]+/g, '_') || 'sns';
        const type = platform === 'instagram' ? 'instagram_feed' : 'x_post';
        const downloadName = `${type}_${handle}_${post?.id || Date.now()}.png`;
        imageModal = { kind: 'sns-export', id: post?.id || '', data, prompt: platform === 'instagram' ? 'Instagram 피드 이미지' : 'X 피드 이미지', downloadName };
        render();
    }

    async function mgV30RenderXFeedImage(post, item, index, character) {
        const { avatarImage, postImage } = await mgV30LoadFeedAssets(post, item, index, character);
        const width = 1080;
        const pad = 52;
        const inner = width - pad * 2;
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');

        const text = mgV30ClampText(item?.text || post?.text || '', 1200);
        const tags = mgV30HashtagsText(item);
        const comments = Array.isArray(item?.comments) ? item.comments.slice(0, 3) : [];
        ctx.font = mgV30CanvasFont('500', 34);
        const textLines = mgV30WrapText(ctx, text, inner - 108, 14);
        ctx.font = mgV30CanvasFont('700', 28);
        const tagLines = tags ? mgV30WrapText(ctx, tags, inner - 108, 3) : [];
        const imageHeight = postImage ? Math.min(620, Math.max(420, Math.round((postImage.height || postImage.naturalHeight || 900) * (inner - 108) / Math.max(1, postImage.width || postImage.naturalWidth || 900)))) : 0;
        const commentLineCount = comments.reduce((sum, comment) => {
            ctx.font = mgV30CanvasFont('500', 26);
            return sum + Math.min(2, mgV30WrapText(ctx, `${comment.name || '익명'}: ${comment.body || ''}`, inner - 112, 2).length || 1);
        }, 0);
        const height = Math.max(720, pad * 2 + 98 + textLines.length * 44 + tagLines.length * 38 + (postImage ? imageHeight + 32 : 0) + 86 + commentLineCount * 32 + 82);

        canvas.width = width;
        canvas.height = height;

        ctx.fillStyle = '#000000';
        ctx.fillRect(0, 0, width, height);

        mgV30FillRoundRect(ctx, 28, 28, width - 56, height - 56, 34, '#050505');
        mgV30StrokeRoundRect(ctx, 28, 28, width - 56, height - 56, 34, '#2f3336', 2);

        let y = pad + 16;
        mgV30DrawCircleImageOrInitial(ctx, avatarImage, pad, y, 76, character?.avatarText || character?.name || '?', character?.color || '#8bd3dd');
        const nameX = pad + 98;
        ctx.fillStyle = '#f7f9f9';
        ctx.font = mgV30CanvasFont('900', 31);
        ctx.fillText(mgV30DisplayName(item, character).slice(0, 26), nameX, y + 28);
        ctx.fillStyle = '#71767b';
        ctx.font = mgV30CanvasFont('500', 25);
        ctx.fillText(`@${mgV30SafeHandle(item, character)} · ${item?.time || formatTime(post?.createdAt)}`, nameX, y + 62);

        y += 104;
        ctx.fillStyle = '#f7f9f9';
        ctx.font = mgV30CanvasFont('500', 34);
        for (const line of textLines) {
            ctx.fillText(line, nameX, y);
            y += 44;
        }

        if (tagLines.length) {
            y += 6;
            ctx.fillStyle = '#1d9bf0';
            ctx.font = mgV30CanvasFont('700', 28);
            for (const line of tagLines) {
                ctx.fillText(line, nameX, y);
                y += 38;
            }
        }

        if (postImage) {
            y += 18;
            const imgX = nameX;
            const imgW = inner - 98;
            mgV30RoundRectPath(ctx, imgX, y, imgW, imageHeight, 28);
            ctx.save();
            ctx.clip();
            mgV30DrawImageCover(ctx, postImage, imgX, y, imgW, imageHeight);
            ctx.restore();
            mgV30StrokeRoundRect(ctx, imgX, y, imgW, imageHeight, 28, '#2f3336', 2);
            y += imageHeight + 34;
        } else {
            y += 20;
        }

        ctx.strokeStyle = '#2f3336';
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(nameX, y);
        ctx.lineTo(width - pad, y);
        ctx.stroke();
        y += 46;

        ctx.fillStyle = '#71767b';
        ctx.font = mgV30CanvasFont('700', 25);
        const actions = [
            `💬 ${mgV30CommentCount(item)}`,
            `↻ ${Number(item?.stats?.reposts) || 0}`,
            `♡ ${mgV30Likes(item)}`,
            `↗ 공유`
        ];
        let ax = nameX;
        for (const action of actions) {
            ctx.fillText(action, ax, y);
            ax += 176;
        }
        y += 48;

        if (comments.length) {
            ctx.fillStyle = '#2f3336';
            ctx.fillRect(nameX, y - 18, inner - 98, 2);
            y += 28;
            for (const comment of comments) {
                ctx.font = mgV30CanvasFont('800', 24);
                ctx.fillStyle = '#e7e9ea';
                const label = `${comment.name || '익명'}`;
                ctx.fillText(label.slice(0, 18), nameX, y);
                const labelWidth = ctx.measureText(label.slice(0, 18)).width + 10;
                ctx.font = mgV30CanvasFont('500', 24);
                ctx.fillStyle = '#cfd9de';
                const bodyLines = mgV30WrapText(ctx, comment.body || '', inner - 120 - labelWidth, 2);
                if (bodyLines.length) {
                    ctx.fillText(bodyLines[0], nameX + labelWidth, y);
                    y += 31;
                    for (let i = 1; i < bodyLines.length; i++) {
                        ctx.fillText(bodyLines[i], nameX + labelWidth, y);
                        y += 31;
                    }
                } else {
                    y += 31;
                }
            }
        }

        mgV30ExportModal(post, item, 'twitter', canvas.toDataURL('image/png'));
    }

    async function mgV30RenderInstagramFeedImage(post, item, index, character) {
        const { avatarImage, postImage } = await mgV30LoadFeedAssets(post, item, index, character);
        const width = 1080;
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');

        const handle = mgV30SafeHandle(item, character);
        const displayName = mgV30DisplayName(item, character);
        const text = mgV30ClampText(item?.text || post?.text || '', 900);
        const tags = mgV30HashtagsText(item);
        const comments = Array.isArray(item?.comments) ? item.comments.slice(0, 2) : [];
        const photoHeight = postImage ? 1080 : 560;

        ctx.font = mgV30CanvasFont('500', 30);
        const captionLines = mgV30WrapText(ctx, `${text}${tags ? ` ${tags}` : ''}`, 930, 5);
        const commentLines = [];
        ctx.font = mgV30CanvasFont('500', 25);
        for (const comment of comments) {
            commentLines.push(...mgV30WrapText(ctx, `${comment.name || '익명'} ${comment.body || ''}`, 930, 2));
        }

        const height = 118 + photoHeight + 90 + 52 + captionLines.length * 36 + Math.max(0, commentLines.length) * 31 + 84;
        canvas.width = width;
        canvas.height = height;

        ctx.fillStyle = '#ffffff';
        ctx.fillRect(0, 0, width, height);

        let y = 0;
        ctx.fillStyle = '#ffffff';
        ctx.fillRect(0, y, width, 118);
        ctx.strokeStyle = '#dbdbdb';
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(0, 117);
        ctx.lineTo(width, 117);
        ctx.stroke();

        mgV30DrawCircleImageOrInitial(ctx, avatarImage, 36, 26, 66, character?.avatarText || character?.name || '?', character?.color || '#8bd3dd');
        ctx.fillStyle = '#0f1419';
        ctx.font = mgV30CanvasFont('900', 29);
        ctx.fillText(handle.slice(0, 28), 124, 58);
        ctx.fillStyle = '#737373';
        ctx.font = mgV30CanvasFont('500', 21);
        ctx.fillText(displayName.slice(0, 36), 124, 88);
        ctx.fillStyle = '#0f1419';
        ctx.font = mgV30CanvasFont('900', 34);
        ctx.fillText('⋯', width - 72, 66);

        y = 118;
        if (postImage) {
            mgV30DrawImageCover(ctx, postImage, 0, y, width, photoHeight);
        } else {
            const gradient = ctx.createLinearGradient(0, y, width, y + photoHeight);
            gradient.addColorStop(0, '#fafafa');
            gradient.addColorStop(1, '#eceff3');
            ctx.fillStyle = gradient;
            ctx.fillRect(0, y, width, photoHeight);
            mgV30FillRoundRect(ctx, 80, y + 82, width - 160, photoHeight - 164, 32, '#ffffffcc');
            ctx.fillStyle = '#111111';
            ctx.font = mgV30CanvasFont('800', 38);
            let ty = y + 165;
            const titleLines = mgV30WrapText(ctx, text || '(내용 없음)', width - 220, 8);
            for (const line of titleLines) {
                ctx.fillText(line, 110, ty);
                ty += 52;
            }
        }
        y += photoHeight;

        ctx.fillStyle = '#ffffff';
        ctx.fillRect(0, y, width, 90);
        ctx.fillStyle = '#111111';
        ctx.font = mgV30CanvasFont('700', 39, 'Arial, sans-serif');
        ctx.fillText('♡', 35, y + 55);
        ctx.fillText('○', 94, y + 55);
        ctx.fillText('↗', 153, y + 55);
        ctx.fillText('▱', width - 76, y + 55);
        y += 90;

        ctx.fillStyle = '#111111';
        ctx.font = mgV30CanvasFont('900', 27);
        ctx.fillText(`좋아요 ${mgV30Likes(item).toLocaleString('ko-KR')}개`, 36, y + 8);
        y += 52;

        ctx.font = mgV30CanvasFont('500', 29);
        ctx.fillStyle = '#111111';
        for (let i = 0; i < captionLines.length; i++) {
            const line = captionLines[i];
            if (i === 0) {
                ctx.font = mgV30CanvasFont('900', 29);
                ctx.fillText(handle, 36, y);
                const hw = Math.min(ctx.measureText(handle).width + 12, 260);
                ctx.font = mgV30CanvasFont('500', 29);
                ctx.fillText(line, 36 + hw, y);
            } else {
                ctx.fillText(line, 36, y);
            }
            y += 36;
        }

        if (mgV30CommentCount(item)) {
            y += 12;
            ctx.fillStyle = '#737373';
            ctx.font = mgV30CanvasFont('500', 25);
            ctx.fillText(`댓글 ${mgV30CommentCount(item)}개 모두 보기`, 36, y);
            y += 38;
        }

        // 댓글은 인스타처럼 닉네임만 굵게, 내용은 일반 굵기로 분리해서 그린다.
        let drawnCommentLines = 0;
        for (const comment of comments) {
            if (drawnCommentLines >= 4) break;
            const name = String(comment?.name || '익명').trim() || '익명';
            const body = String(comment?.body || '').trim();
            if (!body) continue;

            ctx.fillStyle = '#111111';
            ctx.font = mgV30CanvasFont('900', 25);
            const displayName = name.slice(0, 18);
            ctx.fillText(displayName, 36, y);
            const nameWidth = Math.min(ctx.measureText(displayName).width + 12, 260);

            ctx.font = mgV30CanvasFont('500', 25);
            const bodyLines = mgV30WrapText(ctx, body, 930 - nameWidth, 2);
            if (bodyLines.length) {
                ctx.fillText(bodyLines[0], 36 + nameWidth, y);
                y += 31;
                drawnCommentLines += 1;
                for (let i = 1; i < bodyLines.length && drawnCommentLines < 4; i++) {
                    ctx.fillText(bodyLines[i], 36, y);
                    y += 31;
                    drawnCommentLines += 1;
                }
            }
        }

        ctx.fillStyle = '#737373';
        ctx.font = mgV30CanvasFont('500', 21);
        ctx.fillText(String(item?.time || formatTime(post?.createdAt) || '방금 전').toUpperCase(), 36, Math.min(height - 30, y + 30));

        mgV30ExportModal(post, item, 'instagram', canvas.toDataURL('image/png'));
    }

    downloadSnsPostImage = async function(postId, index = 0) {
        try {
            const post = (state.snsPosts || []).find(item => String(item.id) === String(postId));
            const character = getCharacter(post?.characterId) || currentCharacter();
            if (!post || !character) return;
            const platforms = visibleSnsPlatforms(post, character);
            const platformIndex = Number(index) || 0;
            const item = platforms[platformIndex] || platforms[0];
            if (!item) return;
            const platform = String(item.platform || '').toLowerCase();
            if (platform.includes('instagram')) {
                await mgV30RenderInstagramFeedImage(post, item, platformIndex, character);
            } else {
                await mgV30RenderXFeedImage(post, item, platformIndex, character);
            }
        } catch (error) {
            console.warn('[MessengerGod] v30 feed export failed:', error);
            alert(`피드 이미지 생성 실패: ${error.message}`);
        }
    };



