    // ===== v32: Instagram feed export polish - music line + real IG-like icons =====
    function mgV32HashText(value) {
        const text = String(value || '');
        let hash = 2166136261;
        for (let i = 0; i < text.length; i++) {
            hash ^= text.charCodeAt(i);
            hash = Math.imul(hash, 16777619);
        }
        return Math.abs(hash >>> 0);
    }

    function mgV32PickInstagramSong(character, item) {
        const source = [
            character?.name,
            character?.handle,
            character?.prompt,
            character?.userDescription,
            item?.text,
            Array.isArray(item?.hashtags) ? item.hashtags.join(' ') : ''
        ].filter(Boolean).join(' ');
        const lowered = source.toLowerCase();

        // 실제 존재하는 곡명/아티스트만 넣는 풀.
        // 저작권 문제를 피하려고 가사는 넣지 않고, 피드에는 제목 + 아티스트만 표시한다.
        const pools = [];
        const add = (...songs) => pools.push(...songs);

        if (/새벽|밤|midnight|night|잠|달|moon|고요|외로|기다|그리움|lonely|alone/i.test(source)) {
            add(
                ['IU', '밤편지'],
                ['IU', 'Love poem'],
                ['The Weeknd', 'Die For You'],
                ['Keshi', 'UNDERSTAND'],
                ['Frank Ocean', 'Moon River'],
                ['백예린', 'Square (2017)']
            );
        }
        if (/햇살|아침|morning|sun|봄|따뜻|웃|설레|데이트|기분 좋|happy|smile/i.test(source)) {
            add(
                ['BTS', '봄날'],
                ['IU', 'Good Day'],
                ['AKMU', '200%'],
                ['NewJeans', 'Hype Boy'],
                ['Laufey', 'From The Start'],
                ['FIFTY FIFTY', 'Cupid']
            );
        }
        if (/화|삐졌|질투|장난|놀리|바보|ㅋㅋ|ㅋ|티격|츤데레|jealous/i.test(source)) {
            add(
                ['Red Velvet', 'Psycho'],
                ['NewJeans', 'Attention'],
                ['AKMU', 'Love Lee'],
                ['Ariana Grande', 'Into You'],
                ['Taylor Swift', 'Blank Space'],
                ['BLACKPINK', 'As If It’s Your Last']
            );
        }
        if (/비|rain|흐림|울|눈물|슬픔|기분|우울|아파|sad|cry/i.test(source)) {
            add(
                ['Heize', '비도 오고 그래서'],
                ['Epik High', '우산'],
                ['Taeyeon', 'Rain'],
                ['Younha', '비밀번호 486'],
                ['Billie Eilish', 'everything i wanted'],
                ['Adele', 'Someone Like You']
            );
        }
        if (/로판|왕궁|기사|마탑|공작|황제|성|마법|fantasy|귀족|무도회|검|왕/i.test(source)) {
            add(
                ['Joe Hisaishi', 'Merry-Go-Round of Life'],
                ['Christina Perri', 'A Thousand Years'],
                ['Lana Del Rey', 'Young and Beautiful'],
                ['Taylor Swift', 'Enchanted'],
                ['Yiruma', 'River Flows in You'],
                ['Ramin Djawadi', 'Light of the Seven']
            );
        }
        if (/sf|안드로이드|기계|도시|우주|전쟁|시스템|cyber|네온|회로|robot|space/i.test(lowered)) {
            add(
                ['The Weeknd', 'Blinding Lights'],
                ['Daft Punk', 'Digital Love'],
                ['David Bowie', 'Space Oddity'],
                ['M83', 'Midnight City'],
                ['Kavinsky', 'Nightcall'],
                ['NewJeans', 'ETA']
            );
        }
        if (/카페|디저트|케이크|간식|커피|빵|달콤|먹|food|coffee|cake/i.test(source)) {
            add(
                ['BIBI', '밤양갱'],
                ['BTS', 'Coffee'],
                ['10CM', '아메리카노'],
                ['Doja Cat', 'Say So'],
                ['Laufey', 'Valentine'],
                ['AKMU', 'DINOSAUR']
            );
        }
        if (/집착|소유|위험|비밀|뒷계|dark|obsess|secret|danger/i.test(source)) {
            add(
                ['Lady Gaga', 'Bad Romance'],
                ['Arctic Monkeys', 'Do I Wanna Know?'],
                ['Billie Eilish', 'bad guy'],
                ['The Neighbourhood', 'Sweater Weather'],
                ['Red Velvet', 'Psycho'],
                ['Taemin', 'MOVE']
            );
        }

        const defaults = [
            ['NewJeans', 'Ditto'],
            ['IU', 'Love wins all'],
            ['AKMU', 'Love Lee'],
            ['Jungkook', 'Standing Next to You'],
            ['LE SSERAFIM', 'Perfect Night'],
            ['Wave to Earth', 'seasons'],
            ['Laufey', 'From The Start'],
            ['Sabrina Carpenter', 'Espresso'],
            ['IVE', 'I AM'],
            ['aespa', 'Supernova']
        ];

        const list = pools.length ? pools : defaults;
        const picked = list[mgV32HashText(source) % list.length] || defaults[0];
        return `♪ ${picked[0]} · ${picked[1]}`;
    }

    function mgV32DrawHeartIcon(ctx, x, y, size = 36, color = '#111111') {
        ctx.save();
        ctx.strokeStyle = color;
        ctx.lineWidth = 3.2;
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.beginPath();
        const s = size / 32;
        ctx.moveTo(x + 16*s, y + 28*s);
        ctx.bezierCurveTo(x + 4*s, y + 18*s, x + 2*s, y + 9*s, x + 9*s, y + 6*s);
        ctx.bezierCurveTo(x + 13*s, y + 4*s, x + 16*s, y + 7*s, x + 16*s, y + 11*s);
        ctx.bezierCurveTo(x + 16*s, y + 7*s, x + 19*s, y + 4*s, x + 23*s, y + 6*s);
        ctx.bezierCurveTo(x + 30*s, y + 9*s, x + 28*s, y + 18*s, x + 16*s, y + 28*s);
        ctx.stroke();
        ctx.restore();
    }

    function mgV32DrawCommentIcon(ctx, x, y, size = 36, color = '#111111') {
        ctx.save();
        ctx.strokeStyle = color;
        ctx.lineWidth = 3.2;
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        const s = size / 36;
        ctx.beginPath();
        ctx.ellipse(x + 18*s, y + 16*s, 13*s, 11*s, 0, 0, Math.PI * 2);
        ctx.stroke();
        ctx.beginPath();
        ctx.moveTo(x + 12*s, y + 26*s);
        ctx.lineTo(x + 8*s, y + 32*s);
        ctx.lineTo(x + 17*s, y + 27*s);
        ctx.stroke();
        ctx.restore();
    }

    function mgV32DrawPlaneIcon(ctx, x, y, size = 36, color = '#111111') {
        ctx.save();
        ctx.strokeStyle = color;
        ctx.lineWidth = 3.2;
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        const s = size / 36;
        ctx.beginPath();
        ctx.moveTo(x + 4*s, y + 18*s);
        ctx.lineTo(x + 32*s, y + 5*s);
        ctx.lineTo(x + 22*s, y + 31*s);
        ctx.lineTo(x + 16*s, y + 21*s);
        ctx.lineTo(x + 4*s, y + 18*s);
        ctx.stroke();
        ctx.beginPath();
        ctx.moveTo(x + 16*s, y + 21*s);
        ctx.lineTo(x + 32*s, y + 5*s);
        ctx.stroke();
        ctx.restore();
    }

    function mgV32DrawBookmarkIcon(ctx, x, y, size = 36, color = '#111111') {
        ctx.save();
        ctx.strokeStyle = color;
        ctx.lineWidth = 3.2;
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        const s = size / 36;
        ctx.beginPath();
        ctx.moveTo(x + 10*s, y + 5*s);
        ctx.lineTo(x + 26*s, y + 5*s);
        ctx.lineTo(x + 26*s, y + 31*s);
        ctx.lineTo(x + 18*s, y + 25*s);
        ctx.lineTo(x + 10*s, y + 31*s);
        ctx.closePath();
        ctx.stroke();
        ctx.restore();
    }

    function mgV32DrawVerifiedDot(ctx, x, y) {
        ctx.save();
        ctx.fillStyle = '#3897f0';
        ctx.beginPath();
        ctx.arc(x, y, 8, 0, Math.PI * 2);
        ctx.fill();
        ctx.fillStyle = '#ffffff';
        ctx.font = mgV30CanvasFont('900', 10, 'Arial, sans-serif');
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText('✓', x, y + 0.5);
        ctx.textAlign = 'left';
        ctx.textBaseline = 'alphabetic';
        ctx.restore();
    }

    async function mgV32RenderInstagramFeedImage(post, item, index, character) {
        const { avatarImage, postImage } = await mgV30LoadFeedAssets(post, item, index, character);
        const width = 1080;
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');

        const handle = mgV30SafeHandle(item, character);
        const displayName = mgV30DisplayName(item, character);
        const musicLine = mgV32PickInstagramSong(character, item);
        const text = mgV30ClampText(item?.text || post?.text || '', 900);
        const tags = mgV30HashtagsText(item);
        const comments = Array.isArray(item?.comments) ? item.comments.slice(0, 2) : [];
        const photoHeight = postImage ? 1080 : 560;

        ctx.font = mgV30CanvasFont('500', 30);
        const captionLines = mgV30WrapText(ctx, `${text}${tags ? ` ${tags}` : ''}`, 930, 5);
        const commentLines = [];
        ctx.font = mgV30CanvasFont('500', 25);
        for (const comment of comments) {
            commentLines.push(...mgV30WrapText(ctx, `${comment.name || '익명'} ${comment.body || ''}`, 930, 2));
        }

        const height = 132 + photoHeight + 92 + 52 + captionLines.length * 36 + Math.max(0, commentLines.length) * 31 + 86;
        canvas.width = width;
        canvas.height = height;

        ctx.fillStyle = '#ffffff';
        ctx.fillRect(0, 0, width, height);

        let y = 0;
        ctx.fillStyle = '#ffffff';
        ctx.fillRect(0, y, width, 132);
        ctx.strokeStyle = '#dbdbdb';
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(0, 131);
        ctx.lineTo(width, 131);
        ctx.stroke();

        mgV30DrawCircleImageOrInitial(ctx, avatarImage, 36, 29, 72, character?.avatarText || character?.name || '?', character?.color || '#8bd3dd');

        ctx.fillStyle = '#0f1419';
        ctx.font = mgV30CanvasFont('900', 30);
        ctx.fillText(handle.slice(0, 28), 126, 55);
        const handleWidth = ctx.measureText(handle.slice(0, 28)).width;
        if (handleWidth < 650) mgV32DrawVerifiedDot(ctx, 126 + handleWidth + 18, 45);

        ctx.fillStyle = '#444444';
        ctx.font = mgV30CanvasFont('600', 22);
        ctx.fillText(musicLine.slice(0, 52), 126, 86);

        ctx.fillStyle = '#999999';
        ctx.font = mgV30CanvasFont('500', 18);
        ctx.fillText(displayName.slice(0, 42), 126, 112);

        ctx.fillStyle = '#0f1419';
        ctx.font = mgV30CanvasFont('900', 34);
        ctx.fillText('⋯', width - 72, 68);

        y = 132;
        if (postImage) {
            mgV30DrawImageCover(ctx, postImage, 0, y, width, photoHeight);
        } else {
            const gradient = ctx.createLinearGradient(0, y, width, y + photoHeight);
            gradient.addColorStop(0, '#fafafa');
            gradient.addColorStop(1, '#eceff3');
            ctx.fillStyle = gradient;
            ctx.fillRect(0, y, width, photoHeight);
            mgV30FillRoundRect(ctx, 80, y + 82, width - 160, photoHeight - 164, 32, '#ffffffd9');
            ctx.fillStyle = '#111111';
            ctx.font = mgV30CanvasFont('800', 38);
            let ty = y + 165;
            const titleLines = mgV30WrapText(ctx, text || '(내용 없음)', width - 220, 8);
            for (const line of titleLines) {
                ctx.fillText(line, 110, ty);
                ty += 52;
            }
        }
        y += photoHeight;

        ctx.fillStyle = '#ffffff';
        ctx.fillRect(0, y, width, 92);

        mgV32DrawHeartIcon(ctx, 34, y + 26, 39);
        mgV32DrawCommentIcon(ctx, 99, y + 25, 39);
        mgV32DrawPlaneIcon(ctx, 166, y + 26, 39);
        mgV32DrawBookmarkIcon(ctx, width - 76, y + 25, 39);

        y += 92;

        ctx.fillStyle = '#111111';
        ctx.font = mgV30CanvasFont('900', 27);
        ctx.fillText(`좋아요 ${mgV30Likes(item).toLocaleString('ko-KR')}개`, 36, y + 8);
        y += 52;

        ctx.font = mgV30CanvasFont('500', 29);
        ctx.fillStyle = '#111111';
        for (let i = 0; i < captionLines.length; i++) {
            const line = captionLines[i];
            if (i === 0) {
                ctx.font = mgV30CanvasFont('900', 29);
                ctx.fillText(handle, 36, y);
                const hw = Math.min(ctx.measureText(handle).width + 12, 260);
                ctx.font = mgV30CanvasFont('500', 29);
                ctx.fillText(line, 36 + hw, y);
            } else {
                ctx.fillText(line, 36, y);
            }
            y += 36;
        }

        if (mgV30CommentCount(item)) {
            y += 12;
            ctx.fillStyle = '#737373';
            ctx.font = mgV30CanvasFont('500', 25);
            ctx.fillText(`댓글 ${mgV30CommentCount(item)}개 모두 보기`, 36, y);
            y += 38;
        }

        // 댓글은 인스타처럼 닉네임만 굵게, 내용은 일반 굵기로 분리해서 그린다.
        let drawnCommentLines = 0;
        for (const comment of comments) {
            if (drawnCommentLines >= 4) break;
            const name = String(comment?.name || '익명').trim() || '익명';
            const body = String(comment?.body || '').trim();
            if (!body) continue;

            ctx.fillStyle = '#111111';
            ctx.font = mgV30CanvasFont('900', 25);
            const displayName = name.slice(0, 18);
            ctx.fillText(displayName, 36, y);
            const nameWidth = Math.min(ctx.measureText(displayName).width + 12, 260);

            ctx.font = mgV30CanvasFont('500', 25);
            const bodyLines = mgV30WrapText(ctx, body, 930 - nameWidth, 2);
            if (bodyLines.length) {
                ctx.fillText(bodyLines[0], 36 + nameWidth, y);
                y += 31;
                drawnCommentLines += 1;
                for (let i = 1; i < bodyLines.length && drawnCommentLines < 4; i++) {
                    ctx.fillText(bodyLines[i], 36, y);
                    y += 31;
                    drawnCommentLines += 1;
                }
            }
        }

        ctx.fillStyle = '#737373';
        ctx.font = mgV30CanvasFont('700', 20);
        ctx.fillText(String(item?.time || formatTime(post?.createdAt) || '방금 전').toUpperCase(), 36, Math.min(height - 30, y + 32));

        mgV30ExportModal(post, item, 'instagram', canvas.toDataURL('image/png'));
    }

    // v30의 플랫폼 분기 함수가 호출하는 인스타 렌더러만 v32 버전으로 교체한다.
    mgV30RenderInstagramFeedImage = mgV32RenderInstagramFeedImage;



    // ===== v33: actual-song music line + mobile expanded SNS option labels fix =====
