    // ===== v46: Instagram feed image hashtag line for v43 =====
    // v43 기준으로 인스타 피드 이미지에서 캡션 아래 해시태그가 별도 라인으로 보이게 한다.
    async function mgV46RenderInstagramFeedImage(post, item, index, character) {
        const { avatarImage, postImage } = await mgV30LoadFeedAssets(post, item, index, character);
        const width = 1080;
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');

        const handle = mgV30SafeHandle(item, character);
        const displayName = mgV30DisplayName(item, character);
        const musicLine = mgV32PickInstagramSong(character, item);
        const text = mgV30ClampText(item?.text || post?.text || '', 900);
        const tags = mgV30HashtagsText(item);
        const comments = Array.isArray(item?.comments) ? item.comments.slice(0, 2) : [];
        const photoHeight = postImage ? 1080 : 560;

        ctx.font = mgV30CanvasFont('500', 29);
        const captionLines = mgV30WrapText(ctx, text, 930, 4);
        ctx.font = mgV30CanvasFont('700', 28);
        const tagLines = tags ? mgV30WrapText(ctx, tags, 930, 2) : [];

        const height =
            132 +                      // header
            photoHeight +              // photo
            92 +                       // actions
            52 +                       // like row
            Math.max(1, captionLines.length) * 36 +
            (tagLines.length ? 12 + tagLines.length * 34 : 0) +
            (mgV30CommentCount(item) ? 50 : 0) +
            Math.max(0, Math.min(4, comments.length * 2)) * 31 +
            86;

        canvas.width = width;
        canvas.height = height;

        ctx.fillStyle = '#ffffff';
        ctx.fillRect(0, 0, width, height);

        let y = 0;
        ctx.fillStyle = '#ffffff';
        ctx.fillRect(0, y, width, 132);
        ctx.strokeStyle = '#dbdbdb';
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(0, 131);
        ctx.lineTo(width, 131);
        ctx.stroke();

        mgV30DrawCircleImageOrInitial(ctx, avatarImage, 36, 29, 72, character?.avatarText || character?.name || '?', character?.color || '#8bd3dd');

        ctx.fillStyle = '#0f1419';
        ctx.font = mgV30CanvasFont('900', 30);
        ctx.fillText(handle.slice(0, 28), 126, 55);
        const handleWidth = ctx.measureText(handle.slice(0, 28)).width;
        if (typeof mgV32DrawVerifiedDot === 'function' && handleWidth < 650) mgV32DrawVerifiedDot(ctx, 126 + handleWidth + 18, 45);

        ctx.fillStyle = '#444444';
        ctx.font = mgV30CanvasFont('600', 22);
        ctx.fillText(musicLine.slice(0, 52), 126, 86);

        ctx.fillStyle = '#999999';
        ctx.font = mgV30CanvasFont('500', 18);
        ctx.fillText(displayName.slice(0, 42), 126, 112);

        ctx.fillStyle = '#0f1419';
        ctx.font = mgV30CanvasFont('900', 34);
        ctx.fillText('⋯', width - 72, 68);

        y = 132;
        if (postImage) {
            mgV30DrawImageCover(ctx, postImage, 0, y, width, photoHeight);
        } else {
            const gradient = ctx.createLinearGradient(0, y, width, y + photoHeight);
            gradient.addColorStop(0, '#fafafa');
            gradient.addColorStop(1, '#eceff3');
            ctx.fillStyle = gradient;
            ctx.fillRect(0, y, width, photoHeight);
            mgV30FillRoundRect(ctx, 80, y + 82, width - 160, photoHeight - 164, 32, '#ffffffd9');
            ctx.fillStyle = '#111111';
            ctx.font = mgV30CanvasFont('800', 38);
            let ty = y + 165;
            const titleLines = mgV30WrapText(ctx, text || '(내용 없음)', width - 220, 8);
            for (const line of titleLines) {
                ctx.fillText(line, 110, ty);
                ty += 52;
            }
        }
        y += photoHeight;

        ctx.fillStyle = '#ffffff';
        ctx.fillRect(0, y, width, 92);

        if (typeof mgV32DrawHeartIcon === 'function') mgV32DrawHeartIcon(ctx, 34, y + 26, 39);
        if (typeof mgV32DrawCommentIcon === 'function') mgV32DrawCommentIcon(ctx, 99, y + 25, 39);
        if (typeof mgV32DrawPlaneIcon === 'function') mgV32DrawPlaneIcon(ctx, 166, y + 26, 39);
        if (typeof mgV32DrawBookmarkIcon === 'function') mgV32DrawBookmarkIcon(ctx, width - 76, y + 25, 39);

        y += 92;

        ctx.fillStyle = '#111111';
        ctx.font = mgV30CanvasFont('900', 27);
        ctx.fillText(`좋아요 ${mgV30Likes(item).toLocaleString('ko-KR')}개`, 36, y + 8);
        y += 52;

        // Caption: 닉네임 굵게 + 본문
        ctx.fillStyle = '#111111';
        for (let i = 0; i < captionLines.length; i++) {
            const line = captionLines[i];
            if (i === 0) {
                ctx.font = mgV30CanvasFont('900', 29);
                ctx.fillText(handle, 36, y);
                const hw = Math.min(ctx.measureText(handle).width + 12, 260);
                ctx.font = mgV30CanvasFont('500', 29);
                ctx.fillText(line, 36 + hw, y);
            } else {
                ctx.font = mgV30CanvasFont('500', 29);
                ctx.fillText(line, 36, y);
            }
            y += 36;
        }

        // 해시태그를 캡션 아래 별도 파란 라인으로 표시
        if (tagLines.length) {
            y += 8;
            ctx.fillStyle = '#00376b';
            ctx.font = mgV30CanvasFont('700', 28);
            for (const line of tagLines) {
                ctx.fillText(line, 36, y);
                y += 34;
            }
        }

        if (mgV30CommentCount(item)) {
            y += 10;
            ctx.fillStyle = '#737373';
            ctx.font = mgV30CanvasFont('500', 25);
            ctx.fillText(`댓글 ${mgV30CommentCount(item)}개 모두 보기`, 36, y);
            y += 38;
        }

        // 댓글: 닉네임 굵게 / 본문 일반 굵기
        let drawnCommentLines = 0;
        for (const comment of comments) {
            if (drawnCommentLines >= 4) break;
            const name = String(comment?.name || '익명').trim() || '익명';
            const body = String(comment?.body || '').trim();
            if (!body) continue;

            ctx.fillStyle = '#111111';
            ctx.font = mgV30CanvasFont('900', 25);
            const displayCommentName = name.slice(0, 18);
            ctx.fillText(displayCommentName, 36, y);
            const nameWidth = Math.min(ctx.measureText(displayCommentName).width + 12, 260);

            ctx.font = mgV30CanvasFont('500', 25);
            const bodyLines = mgV30WrapText(ctx, body, 930 - nameWidth, 2);
            if (bodyLines.length) {
                ctx.fillText(bodyLines[0], 36 + nameWidth, y);
                y += 31;
                drawnCommentLines += 1;
                for (let i = 1; i < bodyLines.length && drawnCommentLines < 4; i++) {
                    ctx.fillText(bodyLines[i], 36, y);
                    y += 31;
                    drawnCommentLines += 1;
                }
            }
        }

        ctx.fillStyle = '#737373';
        ctx.font = mgV30CanvasFont('700', 20);
        ctx.fillText(String(item?.time || formatTime(post?.createdAt) || '방금 전').toUpperCase(), 36, Math.min(height - 30, y + 32));

        mgV30ExportModal(post, item, 'instagram', canvas.toDataURL('image/png'));
    }

    // v43 기준에서 인스타 피드 이미지는 v46 렌더러로 교체
    mgV30RenderInstagramFeedImage = mgV46RenderInstagramFeedImage;



    // ===== v48: Persona card import for per-character user profile =====
    // 캐릭터 설정의 "이 캐릭터에게 보일 내 이름 / 내 프로필"에 JSON 페르소나 카드를 불러온다.
    function mgV48FirstText(...values) {
        for (const value of values) {
            if (value == null) continue;
            if (Array.isArray(value)) {
                const joined = value.map(item => typeof item === 'string' ? item : '').filter(Boolean).join('\n').trim();
                if (joined) return joined;
                continue;
            }
            if (typeof value === 'object') continue;
            const text = String(value).trim();
            if (text) return text;
        }
        return '';
    }

    function mgV48GetPath(source, path) {
        let node = source;
        for (const key of path.split('.')) {
            if (!node || typeof node !== 'object') return '';
            node = node[key];
        }
        return node;
    }

    function mgV48CleanPersonaText(value) {
        return String(value || '')
            .replace(/\r\n/g, '\n')
            .replace(/\n{4,}/g, '\n\n\n')
            .trim();
    }

    function mgV48PersonaRoots(data) {
        const roots = [];
        const add = item => {
            if (item && typeof item === 'object' && !roots.includes(item)) roots.push(item);
        };

        if (Array.isArray(data)) {
            for (const item of data) add(item);
            for (const item of data) {
                if (item?.data) add(item.data);
                if (item?.persona) add(item.persona);
                if (item?.profile) add(item.profile);
                if (item?.user) add(item.user);
            }
            return roots;
        }

        add(data);
        add(data?.data);
        add(data?.persona);
        add(data?.profile);
        add(data?.user);
        add(data?.userProfile);
        add(data?.settings?.persona);
        add(data?.settings?.user);
        add(data?.extensions?.persona);
        add(data?.extensions?.user);
        add(data?.metadata?.persona);
        add(data?.meta?.persona);
        return roots;
    }

    function mgV48ExtractPersonaCard(data) {
        const roots = mgV48PersonaRoots(data);
        const directPaths = [
            'name',
            'userName',
            'username',
            'displayName',
            'display_name',
            'nickname',
            'nick',
            'personaName',
            'persona_name',
            'profileName',
            'profile_name'
        ];

        let name = '';
        for (const root of roots) {
            name = mgV48FirstText(...directPaths.map(path => mgV48GetPath(root, path)));
            if (name) break;
        }

        const profilePaths = [
            'userDescription',
            'description',
            'desc',
            'profile',
            'persona',
            'personality',
            'summary',
            'bio',
            'background',
            'appearance',
            'scenario',
            'notes',
            'prompt',
            'content',
            'text',
            'memo'
        ];

        let description = '';
        for (const root of roots) {
            description = mgV48FirstText(...profilePaths.map(path => mgV48GetPath(root, path)));
            if (description) break;
        }

        // 여러 필드로 나뉜 페르소나 카드도 어느 정도 합쳐서 가져온다.
        if (!description) {
            const parts = [];
            const labels = [
                ['description', '소개'],
                ['profile', '프로필'],
                ['personality', '성격'],
                ['background', '배경'],
                ['appearance', '외형'],
                ['scenario', '관계/상황'],
                ['notes', '메모']
            ];
            for (const root of roots) {
                for (const [key, label] of labels) {
                    const value = mgV48FirstText(mgV48GetPath(root, key));
                    if (value) parts.push(`${label}: ${value}`);
                }
                if (parts.length) break;
            }
            description = parts.join('\n');
        }

        name = mgV48CleanPersonaText(name);
        description = mgV48CleanPersonaText(description);

        if (!name && !description) {
            throw new Error('페르소나 이름/프로필을 찾지 못했습니다. name, userName, description, profile 같은 필드가 있는 JSON인지 확인해주세요.');
        }

        return { name, description };
    }

    async function mgV48ImportPersonaCardData(data) {
        const persona = mgV48ExtractPersonaCard(data);
        const character = currentCharacter();

        if (character) {
            if (persona.name) character.userName = persona.name;
            if (persona.description) character.userDescription = persona.description;
            selectedCharacterId = character.id;
            expandedCharacterId = character.id;
            activeTab = 'characters';
        } else {
            if (persona.name) state.config.userName = persona.name;
            if (persona.description) state.config.userDescription = persona.description;
        }

        await saveState();
        render();

        const targetName = character?.name ? `${character.name}에게 보일` : '전역';
        const importedName = persona.name || '(이름 없음)';
        showTransientNotice(`${targetName} 페르소나를 불러왔습니다: ${importedName}`);
    }

    async function mgV48HandlePersonaCardFile(event) {
        const file = event.target.files?.[0];
        event.target.value = '';
        if (!file) return;
        try {
            const raw = await file.text();
            await mgV48ImportPersonaCardData(JSON.parse(raw));
        } catch (error) {
            alert(`페르소나 카드 불러오기 실패: ${error.message}`);
        }
    }

    const mgBaseFileInputsPersonaV48 = fileInputsHtml;
    fileInputsHtml = function() {
        const html = mgBaseFileInputsPersonaV48();
        if (html.includes('mg-file-persona-card')) return html;
        return `${html}<input id="mg-file-persona-card" class="mg-hidden" type="file" accept="image/png,.png,application/json,.json">`;
    };

    const mgBaseBindEventsPersonaV48 = bindEvents;
    bindEvents = function() {
        mgBaseBindEventsPersonaV48();
        bindFile('mg-file-persona-card', mgV48HandlePersonaCardFile);
    };

    const mgBaseHandleActionPersonaV48 = handleAction;
    handleAction = async function(action, element) {
        if (action === 'import-persona-card') {
            document.getElementById('mg-file-persona-card')?.click();
            return;
        }
        return mgBaseHandleActionPersonaV48(action, element);
    };

    const mgBaseCharacterEditorPersonaV48 = characterEditorHtml;
    characterEditorHtml = function(character) {
        let html = mgBaseCharacterEditorPersonaV48(character);
        if (html.includes('data-action="import-persona-card"')) return html;

        const personaButton = '<button class="mg-btn" data-action="import-persona-card">페르소나 불러오기</button>';

        if (html.includes('data-action="import-character-card">카드 불러오기</button>')) {
            return html.replace(
                'data-action="import-character-card">카드 불러오기</button>',
                `data-action="import-character-card">카드 불러오기</button>${personaButton}`
            );
        }

        if (html.includes('data-action="export-character-card">카드 저장</button>')) {
            return html.replace(
                'data-action="export-character-card">카드 저장</button>',
                `data-action="export-character-card">카드 저장</button>${personaButton}`
            );
        }

        return html;
    };



    // ===== v49: Persona PNG card import support =====
    // 페르소나 카드는 JSON뿐 아니라 PNG 메타데이터 카드도 들어올 수 있으므로
    // PNG tEXt/iTXt/zTXt chunk에서 chara/persona JSON 또는 base64 JSON을 읽어온다.
    function mgV49DecodeBytes(bytes, encoding = 'utf-8') {
        try {
            return new TextDecoder(encoding).decode(bytes);
        } catch (_) {
            let out = '';
            const chunk = 0x8000;
            for (let i = 0; i < bytes.length; i += chunk) {
                out += String.fromCharCode(...bytes.slice(i, i + chunk));
            }
            return out;
        }
    }

    function mgV49ReadU32(bytes, offset) {
        return (((bytes[offset] << 24) >>> 0) | (bytes[offset + 1] << 16) | (bytes[offset + 2] << 8) | bytes[offset + 3]) >>> 0;
    }

    function mgV49Ascii(bytes) {
        return Array.from(bytes).map(code => String.fromCharCode(code)).join('');
    }

    function mgV49SplitNull(bytes, start = 0) {
        let index = start;
        while (index < bytes.length && bytes[index] !== 0) index++;
        return {
            head: bytes.slice(start, index),
            next: index < bytes.length ? index + 1 : index
        };
    }

    async function mgV49InflatePngText(bytes) {
        if (!bytes?.length) return new Uint8Array();
        if (typeof DecompressionStream === 'undefined') return null;
        try {
            const stream = new Blob([bytes]).stream().pipeThrough(new DecompressionStream('deflate'));
            return new Uint8Array(await new Response(stream).arrayBuffer());
        } catch (_) {
            return null;
        }
    }

    async function mgV49ReadPngTextChunks(file) {
        const bytes = new Uint8Array(await file.arrayBuffer());
        const signature = [137, 80, 78, 71, 13, 10, 26, 10];
        if (bytes.length < 8 || !signature.every((value, index) => bytes[index] === value)) {
            throw new Error('PNG 파일이 아닙니다.');
        }

        const chunks = [];
        let offset = 8;
        while (offset + 12 <= bytes.length) {
            const length = mgV49ReadU32(bytes, offset);
            const type = mgV49Ascii(bytes.slice(offset + 4, offset + 8));
            const dataStart = offset + 8;
            const dataEnd = dataStart + length;
            if (dataEnd + 4 > bytes.length) break;

            const data = bytes.slice(dataStart, dataEnd);

            if (type === 'tEXt') {
                const first = mgV49SplitNull(data, 0);
                const keyword = mgV49DecodeBytes(first.head, 'latin1').trim();
                const raw = data.slice(first.next);
                // SillyTavern 계열은 보통 ASCII/base64지만, 한글 JSON을 직접 박은 카드도 있어서 utf-8 우선.
                let value = mgV49DecodeBytes(raw, 'utf-8');
                if (value.includes('\uFFFD')) value = mgV49DecodeBytes(raw, 'latin1');
                chunks.push({ type, keyword, value });
            }

            if (type === 'iTXt') {
                const first = mgV49SplitNull(data, 0);
                const keyword = mgV49DecodeBytes(first.head, 'utf-8').trim();
                const compressionFlag = data[first.next] || 0;
                const compressionMethod = data[first.next + 1] || 0;
                let cursor = first.next + 2;

                const lang = mgV49SplitNull(data, cursor);
                cursor = lang.next;
                const translated = mgV49SplitNull(data, cursor);
                cursor = translated.next;

                let textBytes = data.slice(cursor);
                if (compressionFlag === 1) {
                    const inflated = await mgV49InflatePngText(textBytes);
                    if (!inflated) {
                        chunks.push({ type, keyword, value: '', compressed: true, unsupported: true });
                        offset = dataEnd + 4;
                        continue;
                    }
                    textBytes = inflated;
                }
                chunks.push({
                    type,
                    keyword,
                    value: mgV49DecodeBytes(textBytes, 'utf-8'),
                    compressed: compressionFlag === 1,
                    compressionMethod
                });
            }

            if (type === 'zTXt') {
                const first = mgV49SplitNull(data, 0);
                const keyword = mgV49DecodeBytes(first.head, 'latin1').trim();
                const compressionMethod = data[first.next] || 0;
                const compressed = data.slice(first.next + 1);
                const inflated = await mgV49InflatePngText(compressed);
                chunks.push({
                    type,
                    keyword,
                    value: inflated ? mgV49DecodeBytes(inflated, 'utf-8') : '',
                    compressed: true,
                    compressionMethod,
                    unsupported: !inflated
                });
            }

            offset = dataEnd + 4;
            if (type === 'IEND') break;
        }

        return chunks.filter(chunk => String(chunk.value || '').trim());
    }

    function mgV49Base64ToText(value) {
        let source = String(value || '').trim();
        const dataUrl = source.match(/^data:[^,]+,\s*(.+)$/i);
        if (dataUrl) source = dataUrl[1];

        source = source
            .replace(/^base64[:,]\s*/i, '')
            .replace(/\s+/g, '')
            .replace(/-/g, '+')
            .replace(/_/g, '/');

        if (!/^[A-Za-z0-9+/=]+$/.test(source) || source.length < 16) return '';

        while (source.length % 4) source += '=';
        try {
            const binary = atob(source);
            const bytes = new Uint8Array(binary.length);
            for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
            return mgV49DecodeBytes(bytes, 'utf-8').trim();
        } catch (_) {
            return '';
        }
    }

    function mgV49TryJson(value) {
        const raw = String(value || '').replace(/^\uFEFF/, '').trim();
        if (!raw) return null;

        const attempts = [raw];

        const directBase64 = mgV49Base64ToText(raw);
        if (directBase64) attempts.push(directBase64);

        // "chara=base64..." 또는 "persona: {json}" 같이 붙어있는 경우도 완화.
        const jsonStart = raw.search(/[\[{]/);
        if (jsonStart > 0) attempts.push(raw.slice(jsonStart));

        const base64Match = raw.match(/[A-Za-z0-9+/_-]{40,}={0,2}/);
        if (base64Match) {
            const decoded = mgV49Base64ToText(base64Match[0]);
            if (decoded) attempts.push(decoded);
        }

        for (const attempt of attempts) {
            try {
                const parsed = JSON.parse(attempt);
                if (typeof parsed === 'string') {
                    try { return JSON.parse(parsed); } catch (_) {}
                    const nestedDecoded = mgV49Base64ToText(parsed);
                    if (nestedDecoded) {
                        try { return JSON.parse(nestedDecoded); } catch (_) {}
                    }
                }
                if (parsed && typeof parsed === 'object') return parsed;
            } catch (_) {}
        }
        return null;
    }

    async function mgV49ExtractPersonaPngJson(file) {
        const chunks = await mgV49ReadPngTextChunks(file);
        if (!chunks.length) {
            throw new Error('PNG 안에서 텍스트 메타데이터를 찾지 못했습니다.');
        }

        const preferred = ['persona', 'user', 'user_profile', 'profile', 'chara', 'ccv3', 'risuai'];
        const ordered = [
            ...chunks.filter(chunk => preferred.includes(String(chunk.keyword || '').toLowerCase())),
            ...chunks.filter(chunk => !preferred.includes(String(chunk.keyword || '').toLowerCase()))
        ];

        const errors = [];
        for (const chunk of ordered) {
            const parsed = mgV49TryJson(chunk.value);
            if (!parsed) continue;
            try {
                // 여기서 실제 이름/프로필 추출이 되는지 먼저 검증.
                mgV48ExtractPersonaCard(parsed);
                return parsed;
            } catch (error) {
                errors.push(`${chunk.keyword || chunk.type}: ${error.message}`);
            }
        }

        const compressedUnsupported = chunks.some(chunk => chunk.unsupported);
        if (compressedUnsupported) {
            throw new Error('PNG 메타데이터가 압축되어 있는데, 현재 브라우저에서 압축 해제를 지원하지 않습니다. JSON으로 내보낸 페르소나가 있으면 그 파일을 사용해주세요.');
        }

        throw new Error(errors[0] || 'PNG 메타데이터에서 페르소나 JSON/base64 JSON을 찾지 못했습니다.');
    }

    async function mgV49ImportPersonaCardFile(file) {
        const name = String(file?.name || '').toLowerCase();
        const type = String(file?.type || '').toLowerCase();

        if (type.includes('png') || name.endsWith('.png')) {
            const data = await mgV49ExtractPersonaPngJson(file);
            await mgV48ImportPersonaCardData(data);
            return;
        }

        const raw = await file.text();
        const parsed = mgV49TryJson(raw) || JSON.parse(raw);
        await mgV48ImportPersonaCardData(parsed);
    }

    // v48의 JSON 전용 핸들러를 PNG/JSON 겸용으로 교체.
    mgV48HandlePersonaCardFile = async function(event) {
        const file = event.target.files?.[0];
        event.target.value = '';
        if (!file) return;
        try {
            await mgV49ImportPersonaCardFile(file);
        } catch (error) {
            alert(`페르소나 카드 불러오기 실패: ${error.message}`);
        }
    };

    const mgBaseBindEventsPersonaPngV49 = bindEvents;
    bindEvents = function() {
        mgBaseBindEventsPersonaPngV49();
        const input = document.getElementById('mg-file-persona-card');
        if (input) input.accept = 'image/png,.png,application/json,.json';
    };

    const mgBaseHandleActionPersonaPngV49 = handleAction;
