    // ===== v51: fix persona PNG imported profile not filling per-character profile field =====
    // PNG 페르소나를 읽긴 하는데 "이 캐릭터에게 보일 내 프로필"이 비는 케이스 보정.
    function mgV51IsUsefulProfileText(value) {
        const text = String(value || '').trim();
        if (!text) return false;
        if (text.length < 2) return false;
        if (/^data:image\//i.test(text)) return false;
        if (/^[A-Za-z0-9+/=_-]{80,}$/.test(text.replace(/\s+/g, ''))) return false;
        return true;
    }

    function mgV51FlattenPersonaTexts(source, depth = 0, path = '', out = []) {
        if (depth > 5 || source == null) return out;

        if (typeof source === 'string') {
            const value = source.trim();
            if (mgV51IsUsefulProfileText(value)) out.push({ path, value });
            return out;
        }

        if (Array.isArray(source)) {
            source.forEach((item, index) => mgV51FlattenPersonaTexts(item, depth + 1, `${path}[${index}]`, out));
            return out;
        }

        if (typeof source === 'object') {
            for (const [key, value] of Object.entries(source)) {
                if (/avatar|image|png|jpeg|jpg|thumbnail|icon|asset|file|url/i.test(key)) continue;
                mgV51FlattenPersonaTexts(value, depth + 1, path ? `${path}.${key}` : key, out);
            }
        }

        return out;
    }

    function mgV51ScorePersonaText(entry) {
        const path = String(entry?.path || '').toLowerCase();
        const value = String(entry?.value || '').trim();
        let score = 0;

        if (/userdescription|user_description|userprofile|user_profile|persona|profile|description|desc|bio|background|appearance|personality|scenario|summary|prompt|notes|memo|content|text/.test(path)) score += 50;
        if (/name|nickname|displayname|display_name|avatar|image|creator|version|spec|id|uuid|tags|greeting|first_mes|mes_example|alternate/.test(path)) score -= 35;
        if (value.length >= 30) score += 20;
        if (value.length >= 80) score += 20;
        if (/[가-힣]/.test(value)) score += 8;
        if (value.includes('{{user}}') || value.includes('<user>')) score += 10;
        if (value.length > 3000) score -= 10;

        return score;
    }

    function mgV51BestPersonaProfileText(data, detectedName = '') {
        const entries = mgV51FlattenPersonaTexts(data)
            .map(entry => ({ ...entry, value: String(entry.value || '').trim() }))
            .filter(entry => mgV51IsUsefulProfileText(entry.value));

        const cleanedName = String(detectedName || '').trim();

        const candidates = entries
            .filter(entry => {
                const value = entry.value;
                if (cleanedName && value === cleanedName) return false;
                if (value.length <= 2) return false;
                return true;
            })
            .sort((a, b) => mgV51ScorePersonaText(b) - mgV51ScorePersonaText(a));

        const best = candidates[0]?.value || '';
        return mgV50CleanText(best);
    }

    function mgV51ExtractPersonaCard(data) {
        let base = { name: '', description: '' };

        try {
            base = mgV50ExtractPersonaCard(data);
        } catch (_) {
            base = { name: '', description: '' };
        }

        const collected = mgV50CollectObjectsAndStrings(data);
        const objects = collected.objects || [];

        const namePaths = [
            'name',
            'data.name',
            'user.name',
            'profile.name',
            'persona.name',
            'displayName',
            'display_name',
            'nickname',
            'nick',
            'char_name',
            'extensions.persona.name',
            'extensions.risuai.name',
            'extensions.risuAI.name'
        ];

        if (!base.name) {
            for (const obj of objects) {
                base.name = mgV50CleanText(mgV50FirstText(...namePaths.map(path => mgV50GetLoosePath(obj, path))));
                if (base.name) break;
            }
        }

        const descPaths = [
            'userDescription',
            'user_description',
            'userProfile',
            'user_profile',
            'profileText',
            'profile_text',
            'personaDescription',
            'persona_description',
            'personaProfile',
            'persona_profile',
            'description',
            'data.description',
            'desc',
            'data.desc',
            'profile',
            'data.profile',
            'persona',
            'data.persona',
            'bio',
            'data.bio',
            'background',
            'data.background',
            'appearance',
            'data.appearance',
            'personality',
            'data.personality',
            'scenario',
            'data.scenario',
            'summary',
            'prompt',
            'data.prompt',
            'content',
            'text',
            'memo',
            'notes',
            'data.notes',
            'extensions.persona.description',
            'extensions.persona.profile',
            'extensions.persona.userDescription',
            'extensions.risuai.description',
            'extensions.risuai.persona',
            'extensions.risuai.userDescription',
            'extensions.risuAI.description',
            'extensions.risuAI.persona',
            'extensions.risuAI.userDescription'
        ];

        if (!mgV51IsUsefulProfileText(base.description)) {
            for (const obj of objects) {
                const found = mgV50FirstText(...descPaths.map(path => mgV50GetLoosePath(obj, path)));
                if (mgV51IsUsefulProfileText(found) && found !== base.name) {
                    base.description = mgV50CleanText(found);
                    break;
                }
            }
        }

        if (!mgV51IsUsefulProfileText(base.description)) {
            base.description = mgV51BestPersonaProfileText(data, base.name);
        }

        base.name = mgV50CleanText(base.name);
        base.description = mgV50CleanText(base.description);

        if (!base.name && !base.description) {
            throw new Error('페르소나 이름/프로필을 찾지 못했습니다. PNG 안의 메타데이터 구조가 일반 카드 형식과 다른 것 같습니다.');
        }

        return base;
    }

    function mgV51PersonaTargetCharacter() {
        return currentCharacter()
            || state.characters?.find(character => character.id === selectedCharacterId)
            || state.characters?.find(character => character.id === expandedCharacterId)
            || state.characters?.[0]
            || null;
    }

    async function mgV51ImportPersonaCardData(data) {
        const persona = mgV51ExtractPersonaCard(data);
        const character = mgV51PersonaTargetCharacter();

        if (character) {
            if (persona.name) {
                character.userName = persona.name;
                character.user = persona.name;
            }

            if (persona.description) {
                // 기존 저장/프롬프트용 필드
                character.userDescription = persona.description;
                // 일부 UI/구버전 호환 필드
                character.userProfile = persona.description;
                character.profileForCharacter = persona.description;
                character.personaProfile = persona.description;
            }

            selectedCharacterId = character.id;
            expandedCharacterId = character.id;
            activeTab = 'characters';
        } else {
            if (persona.name) state.config.userName = persona.name;
            if (persona.description) {
                state.config.userDescription = persona.description;
                state.config.userProfile = persona.description;
            }
        }

        await saveState();
        render();

        // 렌더 직후 현재 열린 편집 필드에도 직접 밀어 넣어서 "칸이 안 채워져 보이는" 문제 방지.
        requestAnimationFrame(() => {
            const nameInput = document.getElementById('char-user-name');
            const descInput = document.getElementById('char-user-description');
            if (nameInput && persona.name) nameInput.value = persona.name;
            if (descInput && persona.description) descInput.value = persona.description;
        });

        const targetName = character?.name ? `${character.name}에게 보일` : '전역';
        const importedName = persona.name || '(이름 없음)';
        const profileState = persona.description ? '프로필 포함' : '프로필 없음';
        showTransientNotice(`${targetName} 페르소나를 불러왔습니다: ${importedName} · ${profileState}`);
    }

    // 기존 v48/v50 함수들을 v51 보정판으로 교체.
    mgV48ExtractPersonaCard = mgV51ExtractPersonaCard;
    mgV48ImportPersonaCardData = mgV51ImportPersonaCardData;

    async function mgV51ImportPersonaCardFile(file) {
        const name = String(file?.name || '').toLowerCase();
        const type = String(file?.type || '').toLowerCase();

        if (type.includes('png') || name.endsWith('.png')) {
            const data = await mgV50ReadPngCardJson(file, 'persona');
            await mgV51ImportPersonaCardData(data);
            return;
        }

        const raw = await file.text();
        const parsed = mgV50TryJsonLoose(raw) || JSON.parse(raw);
        await mgV51ImportPersonaCardData(parsed);
    }

    mgV48HandlePersonaCardFile = async function(event) {
        const file = event.target.files?.[0];
        event.target.value = '';
        if (!file) return;
        try {
            await mgV51ImportPersonaCardFile(file);
        } catch (error) {
            alert(`페르소나 카드 불러오기 실패: ${error.message}`);
        }
    };

