    function mgSetSaveDockStatus(text, failed = false) {
        const status = document.getElementById('mg-save-dock-status');
        if (status) {
            status.textContent = text;
            status.classList.toggle('is-error', Boolean(failed));
        }
    }

    function mgSaveTimeLabel() {
        try { return new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }); }
        catch (_) { return 'now'; }
    }

    async function mgFinishManualSave(label) {
        mgSetSaveDockStatus('저장 중...');
        await flushSaveState();
        const message = `${label} 저장 완료 · ${mgSaveTimeLabel()}`;
        mgSetSaveDockStatus(message);
        showTransientNotice(message);
    }

    function mgWrapManualSave(original, label) {
        return async function(...args) {
            try {
                const result = await original.apply(this, args);
                await mgFinishManualSave(label);
                return result;
            } catch (error) {
                const message = `${label} 저장 실패: ${error.message}`;
                mgSetSaveDockStatus(message, true);
                showTransientNotice(message);
                throw error;
            }
        };
    }

