    saveApiFromForm = mgWrapManualSave(saveApiFromForm, 'API/이미지 설정');
    savePromptsFromForm = mgWrapManualSave(savePromptsFromForm, '프롬프트');
    saveAppearanceFromForm = mgWrapManualSave(saveAppearanceFromForm, '화면 설정');
    saveSnsSettingsFromForm = mgWrapManualSave(saveSnsSettingsFromForm, 'SNS 옵션');
