    function mgVisibleSaveTarget() {
        if (!isWindowOpen) return null;
        if (activeTab === 'characters' && document.getElementById('char-name')) return { action: 'save-character', title: '현재 캐릭터 저장', note: '프로필, 상태, 말투, 자동화 포함' };
        if (activeTab === 'settings' && document.getElementById('cfg-roomName')) return { action: 'save-room-settings', title: '기본 설정 저장', note: '내 프로필과 전역 자동화 포함' };
        if ((activeTab === 'api' || activeTab === 'image') && (document.getElementById('cfg-apiType') || document.getElementById('img-provider'))) return { action: 'save-api', title: activeTab === 'image' ? '이미지 설정 저장' : 'API 설정 저장', note: '키, 모델, 이미지 생성 옵션 포함' };
        if (activeTab === 'prompts' && document.getElementById('prompt-sns')) return { action: 'save-prompts', title: '프롬프트 저장', note: '수정한 프롬프트 전체 반영' };
        if (activeTab === 'appearance' && document.getElementById('ui-preset')) return { action: 'save-appearance', title: '화면 설정 저장', note: '테마와 글자 크기 반영' };
        return null;
    }

    async function mgSaveVisibleSettingsFromDock(button) {
        const target = mgVisibleSaveTarget();
        if (!target) return;
        button.disabled = true;
        const originalText = button.textContent;
        button.textContent = '저장 중...';
        mgSetSaveDockStatus('저장 중...');
        try {
            await handleAction(target.action, button);
        } finally {
            button.disabled = false;
            button.textContent = originalText;
        }
    }

    function mgRenderSaveDock() {
        document.getElementById('mg-settings-save-dock')?.remove();
        const target = mgVisibleSaveTarget();
        if (!target) return;
        document.body.insertAdjacentHTML('beforeend', `<div id="mg-settings-save-dock" class="mg-settings-save-dock"><span><strong>${escapeHtml(target.title)}</strong><small>${escapeHtml(target.note)}</small></span><span id="mg-save-dock-status" class="mg-save-dock-status">변경 후 저장 필요</span><button class="mg-btn primary" type="button" id="mg-save-dock-button">저장</button></div>`);
        document.getElementById('mg-save-dock-button')?.addEventListener('click', event => {
            event.preventDefault();
            event.stopPropagation();
            mgSaveVisibleSettingsFromDock(event.currentTarget).catch(error => console.warn('[MessengerGod] dock save failed:', error));
        });
    }

