    mgRegenerateProfileMedia = async function(kind = 'all') {
        const character = mgEnsureCharacterProfileFields(currentCharacter() || mgBotProfileCharacter());
        if (!character) return;
        mgApplyProfileFormValues(character, mgProfileFormValues());
        const isStatusOnly = kind === 'status';
        if (!isStatusOnly && !state.config.imageGeneration?.enabled) return alert('이미지 생성 설정이 꺼져 있어 프로필 사진을 만들 수 없습니다.');
        const kinds = kind === 'all' ? ['avatar', 'cover'] : isStatusOnly ? [] : [kind === 'cover' ? 'cover' : 'avatar'];
        const busyKey = `${character.id}:${kind}`;
        if (mgProfileMediaBusyIds.has(busyKey)) return;
        mgProfileMediaBusyIds.add(busyKey);
        for (const itemKind of kinds) mgProfileMediaBusyIds.add(`${character.id}:${itemKind}`);
        render();
        try {
            let changed = false;
            if (kind === 'all' || isStatusOnly) changed = await mgGenerateProfileStatusMessage(character) || changed;
            for (const itemKind of kinds) {
                const prompt = mgProfileMediaPrompt(character, itemKind);
                const item = { imagePrompt: prompt, imageCaption: itemKind === 'cover' ? 'profile cover' : 'profile photo' };
                logDebug('profile-media-start', `${character.name} ${itemKind} generation started`, { prompt });
                const data = await callImageGeneration(mgProfileGenerationCharacter(character, itemKind), item);
                if (data) mgAddProfileMedia(character, itemKind, data, { source: 'generated', prompt: item.finalImagePrompt || prompt, name: item.imageCaption });
                changed = Boolean(data) || changed;
                logDebug('profile-media-done', `${character.name} ${itemKind} generation finished`, { prompt: item.finalImagePrompt || prompt });
            }
            if (changed) {
                await saveState();
                await flushSaveState();
                showTransientNotice('프로필 AI 생성 결과가 저장됐습니다.');
            }
        } catch (error) {
            logDebug('profile-media-error', `${character.name} profile media generation failed: ${error.message}`, { kind });
            alert(`프로필 사진 생성 실패: ${error.message}`);
        } finally {
            mgProfileMediaBusyIds.delete(busyKey);
            for (const itemKind of kinds) mgProfileMediaBusyIds.delete(`${character.id}:${itemKind}`);
            render();
        }
    };

    function mgApplyVisibleProfileFormForCharacter(character) {
        if (!character || !document.getElementById('char-status-message')) return;
        const visibleCharacter = currentCharacter();
        if (visibleCharacter?.id !== character.id) return;
        mgApplyProfileFormValues(character, mgProfileFormValues());
    }

    function mgDropLegacyProfileGalleryFields(character) {
        if (!character) return;
        for (const kind of ['avatar', 'cover']) {
            const field = mgProfileGalleryField(kind);
            const indexField = mgProfileIndexField(kind);
            const gallery = Array.isArray(character[field]) ? character[field] : [];
            const direct = mgLegacyProfileMediaValue(character, kind);
            const last = [...gallery].reverse().find(item => item && (item.data || item.image || item.url));
            if (!direct && last) mgSetCurrentProfileMedia(character, kind, last.data || last.image || last.url || '');
            delete character[field];
            delete character[indexField];
        }
    }

    const mgBaseLoadStateDropLegacyProfileGallery = loadState;
    loadState = async function() {
        await mgBaseLoadStateDropLegacyProfileGallery();
        for (const character of state.characters || []) mgDropLegacyProfileGalleryFields(character);
    };

    const mgBasePrepareStateForSaveDropLegacyProfileGallery = prepareStateForSave;
    prepareStateForSave = function() {
        mgBasePrepareStateForSaveDropLegacyProfileGallery();
        for (const character of state.characters || []) mgDropLegacyProfileGalleryFields(character);
    };

    function mgProfileKindTitle(kind) {
        return kind === 'cover' ? 'Cover' : 'Avatar';
    }

    function mgNormalizeProfileMediaSource(source) {
        const value = String(source || '').toLowerCase();
        return /upload|user|manual-file|direct/.test(value) ? 'upload' : 'generated';
    }

    function mgProfileSourceField(kind, source) {
        return `profile${mgProfileKindTitle(kind)}${mgNormalizeProfileMediaSource(source) === 'upload' ? 'Uploaded' : 'Generated'}`;
    }

    function mgProfileSourceUpdatedField(kind, source) {
        return `${mgProfileSourceField(kind, source)}At`;
    }

    function mgProfileSourceMetaField(kind, source) {
        return `${mgProfileSourceField(kind, source)}Meta`;
    }

    function mgProfileActiveSourceField(kind) {
        return `profile${mgProfileKindTitle(kind)}ActiveSource`;
    }

    function mgProfileSourceMedia(character, kind, source) {
        return character?.[mgProfileSourceField(kind, source)] || '';
    }

    function mgProfileActiveSource(character, kind) {
        const saved = mgNormalizeProfileMediaSource(character?.[mgProfileActiveSourceField(kind)] || 'generated');
        if (mgProfileSourceMedia(character, kind, saved)) return saved;
        if (mgProfileSourceMedia(character, kind, 'upload')) return 'upload';
        if (mgProfileSourceMedia(character, kind, 'generated')) return 'generated';
        return '';
    }

    function mgProfileSourceLabel(source) {
        return mgNormalizeProfileMediaSource(source) === 'upload' ? '직접 넣은 최신' : 'AI 최신';
    }

    function mgSetProfileSourceMedia(character, kind, data, source, meta = {}) {
        if (!character || !data) return;
        const normalizedSource = mgNormalizeProfileMediaSource(source);
        character[mgProfileSourceField(kind, normalizedSource)] = data;
        character[mgProfileSourceUpdatedField(kind, normalizedSource)] = Date.now();
        character[mgProfileSourceMetaField(kind, normalizedSource)] = {
            source: normalizedSource,
            name: meta.name || '',
            prompt: meta.prompt || '',
            createdAt: Date.now()
        };
        character[mgProfileActiveSourceField(kind)] = normalizedSource;
        mgSetCurrentProfileMedia(character, kind, data);
        mgDropLegacyProfileGalleryFields(character);
        if (kind === 'cover') character.profileCoverUpdatedAt = Date.now();
        else character.avatarUpdatedAt = Date.now();
    }

    mgCurrentProfileMedia = function(character, kind) {
        if (!character) return '';
        const source = mgProfileActiveSource(character, kind);
        const sourceData = source ? mgProfileSourceMedia(character, kind, source) : '';
        return sourceData || mgLegacyProfileMediaValue(character, kind);
    };

    mgAddProfileMedia = function(character, kind, data, meta = {}) {
        mgSetProfileSourceMedia(character, kind, data, meta.source || 'generated', meta);
    };

    async function mgUseProfileMediaSource(kind = 'avatar', source = 'generated') {
        const character = mgEnsureCharacterProfileFields(currentCharacter() || mgBotProfileCharacter());
        if (!character) return;
        const normalizedSource = mgNormalizeProfileMediaSource(source);
        const data = mgProfileSourceMedia(character, kind, normalizedSource);
        if (!data) return alert(`${mgProfileSourceLabel(normalizedSource)} 사진이 아직 없습니다.`);
        character[mgProfileActiveSourceField(kind)] = normalizedSource;
        mgSetCurrentProfileMedia(character, kind, data);
        if (kind === 'cover') character.profileCoverUpdatedAt = Date.now();
        else character.avatarUpdatedAt = Date.now();
        await saveState();
        await flushSaveState();
        showTransientNotice(`${kind === 'cover' ? '배경사진' : '프로필사진'}을 ${mgProfileSourceLabel(normalizedSource)}으로 바꿨습니다.`);
        render();
    }

    mgProfileThumbHtml = function(character, kind) {
        const url = mgProfileMediaUrl(character, kind);
        const label = kind === 'cover' ? '배경사진' : '프로필사진';
        const busy = mgProfileMediaBusyIds.has(`${character.id}:${kind}`) || mgProfileMediaBusyIds.has(`${character.id}:all`);
        const activeSource = mgProfileActiveSource(character, kind);
        const generated = mgProfileSourceMedia(character, kind, 'generated');
        const uploaded = mgProfileSourceMedia(character, kind, 'upload');
        const updatedAt = activeSource ? character[mgProfileSourceUpdatedField(kind, activeSource)] : (kind === 'cover' ? character.profileCoverUpdatedAt : character.avatarUpdatedAt);
        const sourceText = url ? `${activeSource ? mgProfileSourceLabel(activeSource) : '현재 사진'} 사용 중${updatedAt ? ` · ${mgHumanDuration(Date.now() - updatedAt)} ago` : ''}` : '현재 사진 없음';
        return `<div class="mg-profile-media-tile ${kind}"><div class="mg-profile-media-preview">${url ? `<img src="${escapeHtml(url)}" alt="">` : `<span>${escapeHtml(label)}</span>`}${busy ? '<b>생성 중...</b>' : ''}</div><strong>${escapeHtml(label)}</strong><small>${escapeHtml(sourceText)}</small><div class="mg-profile-media-buttons"><button class="mg-btn" data-action="pick-profile-${kind}">직접 넣기</button><button class="mg-btn" data-action="regenerate-profile-media" data-kind="${kind}" ${state.config.imageGeneration?.enabled && !busy ? '' : 'disabled'}>사진 직접 AI 생성</button><button class="mg-btn" data-action="use-profile-source" data-kind="${kind}" data-source="generated" ${generated && activeSource !== 'generated' ? '' : 'disabled'}>AI 최신 사용</button><button class="mg-btn" data-action="use-profile-source" data-kind="${kind}" data-source="upload" ${uploaded && activeSource !== 'upload' ? '' : 'disabled'}>직접 최신 사용</button></div></div>`;
    };

    mgProfileMediaPanelHtml = function(character) {
        mgEnsureCharacterProfileFields(character);
        const aiHelp = state.config.imageGeneration?.enabled ? 'AI 생성 최신 1개와 직접 넣은 최신 1개를 따로 보관합니다.' : '이미지 생성 설정이 꺼져 있어 사진 AI 생성 버튼은 비활성화됩니다.';
        return `<div class="mg-profile-media-panel"><div class="mg-inline" style="justify-content:space-between"><h3>프로필 / 상태 AI</h3><span class="mg-inline"><button class="mg-btn" data-action="regenerate-profile-media" data-kind="status" ${mgProfileMediaBusyIds.has(`${character.id}:status`) ? 'disabled' : ''}>${mgProfileMediaBusyIds.has(`${character.id}:status`) ? '생성 중...' : '상태 직접 AI 생성'}</button><button class="mg-btn primary" data-action="regenerate-profile-media" data-kind="all" ${state.config.imageGeneration?.enabled && !mgProfileMediaBusyIds.has(`${character.id}:all`) ? '' : 'disabled'}>${mgProfileMediaBusyIds.has(`${character.id}:all`) ? '생성 중...' : '상태+사진 직접 AI 생성'}</button></span></div>${mgProfileAutoControlsHtml(character)}<div class="mg-profile-media-grid">${mgProfileThumbHtml(character, 'avatar')}${mgProfileThumbHtml(character, 'cover')}</div><div class="mg-grid">${textareaHtml('char-profile-avatar-prompt', '프로필사진 프롬프트', character.profileAvatarPrompt || '')}${textareaHtml('char-profile-cover-prompt', '배경사진 프롬프트', character.profileCoverPrompt || '')}</div><p class="mg-help">${escapeHtml(aiHelp)} 새 AI 사진은 AI 슬롯만, 직접 넣은 사진은 직접 슬롯만 교체하고 각 슬롯은 최근 1개만 남깁니다.</p></div>`;
    };

    const mgBaseHandleActionProfileSourceSlots = handleAction;
    handleAction = async function(action, element) {
        if (action === 'use-profile-source') return mgUseProfileMediaSource(element.dataset.kind || 'avatar', element.dataset.source || 'generated');
        return mgBaseHandleActionProfileSourceSlots(action, element);
    };

    const mgBaseExternalizeStateMediaProfileSourceSlots = externalizeStateMediaNow;
    externalizeStateMediaNow = async function() {
        await mgBaseExternalizeStateMediaProfileSourceSlots();
        for (const character of state.characters || []) {
            await externalizeMediaFields(character, ['profileAvatarGenerated', 'profileAvatarUploaded', 'profileCoverGenerated', 'profileCoverUploaded'], `char-profile-source-${character.id || 'item'}`);
        }
    };

    async function mgExternalizeProfileSourceSlot(character, kind, source) {
        if (!character) return;
        const field = mgProfileSourceField(kind, source);
        if (!character[field]) return;
        await externalizeMediaFields(character, [field], `char-profile-source-${character.id || 'item'}-${kind}-${source}`);
        if (mgProfileActiveSource(character, kind) === mgNormalizeProfileMediaSource(source)) mgSetCurrentProfileMedia(character, kind, character[field]);
    }

    const mgBaseExternalizeStateMediaProfileSourceSlotsFirst = externalizeStateMediaNow;
    externalizeStateMediaNow = async function() {
        for (const character of state.characters || []) {
            await mgExternalizeProfileSourceSlot(character, 'avatar', 'generated');
            await mgExternalizeProfileSourceSlot(character, 'avatar', 'upload');
            await mgExternalizeProfileSourceSlot(character, 'cover', 'generated');
            await mgExternalizeProfileSourceSlot(character, 'cover', 'upload');
        }
        await mgBaseExternalizeStateMediaProfileSourceSlotsFirst();
    };

    mgHandleProfileMediaFileSelect = async function(event, kind) {
        const file = event.target.files?.[0];
        event.target.value = '';
        const character = mgEnsureCharacterProfileFields(currentCharacter());
        if (!file || !character) return;
        if (!file.type.startsWith('image/')) return alert('이미지 파일만 사용할 수 있습니다.');
        const data = kind === 'cover' ? await fileToCompressedImage(file, 1600, 900, 0.84) : await fileToCompressedImage(file, 768, 768, 0.84);
        mgAddProfileMedia(character, kind, data, { source: 'upload', name: file.name });
        await saveState();
        await flushSaveState();
        showTransientNotice(`${kind === 'cover' ? '배경사진' : '프로필사진'} 직접 넣은 최신 사진이 저장됐습니다.`);
        render();
    };

    const mgBaseMaybeUpdateCharacterProfileAfterChatSaveUx = mgMaybeUpdateCharacterProfileAfterChat;
    mgMaybeUpdateCharacterProfileAfterChat = async function(character, ...args) {
        mgApplyVisibleProfileFormForCharacter(character);
        return mgBaseMaybeUpdateCharacterProfileAfterChatSaveUx(character, ...args);
    };

    const mgBaseInjectStylesSaveUx = injectStyles;
    injectStyles = function() {
        mgBaseInjectStylesSaveUx();
        if (document.getElementById('mg-settings-save-ux-style')) return;
        const style = document.createElement('style');
        style.id = 'mg-settings-save-ux-style';
        style.textContent = `.mg-settings-save-dock{position:fixed;left:50%;bottom:18px;transform:translateX(-50%);z-index:90;width:min(680px,calc(100vw - 24px));box-sizing:border-box;display:grid;grid-template-columns:minmax(0,1fr) auto auto;gap:10px;align-items:center;border:1px solid var(--accent);background:var(--panel);color:var(--text);box-shadow:var(--shadow);border-radius:8px;padding:10px 12px}.mg-settings-save-dock strong,.mg-settings-save-dock small{display:block}.mg-settings-save-dock small{margin-top:2px;color:var(--muted);font-size:11px}.mg-save-dock-status{color:var(--muted);font-size:12px;white-space:nowrap}.mg-save-dock-status.is-error{color:var(--danger)}.mg-settings-save-dock .mg-btn{height:34px;min-width:76px}.mg-profile-auto-grid+.mg-help{margin:2px 0 0}@media(max-width:780px){.mg-settings-save-dock{bottom:10px;grid-template-columns:minmax(0,1fr) auto;padding:9px}.mg-save-dock-status{grid-column:1/-1;grid-row:2;font-size:11px}.mg-settings-save-dock .mg-btn{grid-column:2;grid-row:1}.mg-settings-save-dock small{font-size:10px}}`;
        document.head.appendChild(style);
    };
    // ------------------------------------------

    // --- STATUS OVERRIDE ---
    function mgStatusFromContext(character, text = '') {
        const value = String(text || '').toLowerCase();
        const options = [];
        
        if (/(졸|잠|피곤|sleep|tired)/i.test(value)) options.push('...', '💤', '🥱', '피곤하다', '자도 자도', '🛌', '조금 쉬고 싶어');
        if (/(비|눈|날씨|추워|더워|weather|rain|snow)/i.test(value)) options.push('☔', '비 온다', '창밖 보는 거 좋아', '☃️', '날씨 좋네', '☁️', '❄️');
        if (/(사진|셀카|이미지|그림|photo|selfie|image)/i.test(value)) options.push('📷', '기록', '추억', '사진첩', '📸', 'V', '남는 건 사진뿐');
        if (/(보고싶|좋아|사랑|그리워|miss|love)/i.test(value)) options.push('...', '보고싶어', '생각나', '💭', '뭐해?', '보고싶다', '괜히 웃음', '🤍', '🌙');
        if (/(화났|짜증|미안|울|sad|angry|sorry)/i.test(value)) options.push('.', '...', '휴', '기분 별로야', '싱숭생숭', '생각이 많아지는 밤', '혼자 있고 싶어', '💧');
        
        options.push(
            '...', 
            '.', 
            '🎧', 
            'playlist', 
            '그냥', 
            '아무 생각 없이', 
            '좋은 하루', 
            '심심해', 
            '연락해', 
            '바쁨', 
            '😊', 
            '✨',
            'Coffee ☕'
        );
        
        return options[Math.floor(Math.random() * options.length)].slice(0, 80);
    }

    mgIsUsefulProfileStatus = function(value) {
        const text = String(value || '').trim();
        if (!text) return false;
        if (/^(statusMessage|status|message|text)\s*[:：]?\s*$/i.test(text)) return false;
        if (/^\{.*\}$/.test(text)) return false;
        return text.length <= 40;
    };

    async function mgGenerateProfileStatusMessage(character) {
        if (!character) return false;
        try {
            const roomId = selectedRoomId || state.chatRooms?.[character.id]?.[0]?.id || '';
            const recent = (state.messages?.[roomId] || []).slice(-8).map(message => `${message.role === 'user' ? userNameFor(character) : character.name}: ${message.content || mediaLabel(message)}`).join('\n');
            const payload = await callLLM([
                { role: 'system', content: [
                    `Create a realistic and aesthetic messenger profile status (상태메세지) for ${character.name}.`,
                    `Character profile: ${character.prompt || '(empty)'}`,
                    `Output language: ${state.config.language || 'Korean'}.`,
                    `Do NOT use literal actions like 'doing something', 'sleepy state', 'reading messages' (ㅇㅇ하는 중, ㅇㅇ한 상태는 절대 안됨).`,
                    `Instead, use realistic styles: short vague quotes, lyric-like moods, single emojis, aesthetic symbols, minimal words (e.g., '...', '.', '휴', '피곤하다', '💭').`,
                    'Return JSON only: {"statusMessage":"..."}',
                    'It must be 1 to 20 characters long.'
                ].join('\n') },
                { role: 'user', content: `Recent chat context:\n${recent || '(none)'}\n\nGenerate a realistic messenger statusMessage now.` }
            ], { maxTokens: 160 });
            const status = mgProfileStatusFromPayload(payload) || mgStatusFromContext(character, recent);
            if (!mgIsUsefulProfileStatus(status)) return false;
            character.statusMessage = status;
            character.statusUpdatedAt = Date.now();
            return true;
        } catch (error) {
            logDebug('profile-status-ai-error', `${character.name} profile status generation failed: ${error.message}`, {});
            return false;
        }
    }
    // -----------------------

    // --- DAILY DIARY MEMORY / CALENDAR PRESETS ---
    let mgDailyDiaryMemoryTimer = null;
    const mgDailyDiaryMemoryInFlight = new Set();

    function mgDailyDiaryDateKey(date = new Date()) {
        return date.toLocaleDateString('en-CA');
    }

    function mgDailyDiaryRange(dateKey) {
        const start = new Date(`${dateKey}T00:00:00`).getTime();
        const end = start + 24 * 60 * 60 * 1000;
        return { start, end };
    }

    function mgDailyDiaryTimeLabel(timestamp) {
        try { return new Date(timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }); }
        catch (_) { return ''; }
    }

    function mgDailyDiarySpeaker(message, fallbackCharacter) {
        if (message.role === 'user') return userNameFor(fallbackCharacter);
        if (message.role === 'system') return 'System';
        const speaker = getCharacter(message.characterId) || fallbackCharacter;
        return speaker?.name || fallbackCharacter?.name || 'Character';
    }

    function mgCollectDailyDiaryMessages(character, dateKey) {
        if (!character) return null;
        const { start, end } = mgDailyDiaryRange(dateKey);
        const entries = [];
        const seenRooms = new Set();
        const pushRoom = (roomId, label, includeAll = true) => {
            if (!roomId || seenRooms.has(roomId)) return;
            seenRooms.add(roomId);
            for (const message of state.messages?.[roomId] || []) {
                const createdAt = Number(message.createdAt) || 0;
                if (!createdAt || createdAt < start || createdAt >= end || message.role === 'system') continue;
                if (!includeAll && message.role !== 'user' && message.characterId !== character.id) continue;
                const content = String(message.content || mediaLabel(message) || '').trim();
                if (!content) continue;
                entries.push({
                    createdAt,
                    text: `[${mgDailyDiaryTimeLabel(createdAt)} · ${label}] ${mgDailyDiarySpeaker(message, character)}: ${content}`
                });
            }
        };
        for (const room of state.chatRooms?.[character.id] || []) pushRoom(room.id, room.name || 'DM', true);
        for (const room of state.groupRooms || []) {
            let participates = false;
            try { participates = groupMembers(room).some(member => member?.id === character.id); } catch (_) { participates = false; }
            if (participates) pushRoom(room.id, room.name || 'Group', true);
        }
        entries.sort((left, right) => left.createdAt - right.createdAt);
        if (!entries.length) return null;
        let transcript = entries.map(entry => entry.text).join('\n');
        const maxChars = 24000;
        if (transcript.length > maxChars) transcript = `[Earlier lines omitted for stability; this is the latter part of ${dateKey}.]\n` + transcript.slice(-maxChars);
        return { transcript, count: entries.length };
    }

    function mgDailyDiaryMemoryPrompt(character, dateKey, count) {
        return [
            `It is 23:59 on ${dateKey}.`,
            `Write ONE daily memory entry for ${character.name}, like a private diary written at the end of the day.`,
            `Use the full chat timeline from today as the source. There were ${count} chat messages/items today.`,
            'Style: intimate diary / reflective recap, not a bullet list, not a dry database summary.',
            'Include what happened, emotional shifts, promises, unresolved tension, important user preferences, and relationship changes that should matter later.',
            'Do not invent events that are not in the transcript. Do not quote every message. Compress the whole day into a useful memory.',
            `Output language: ${state.config.language || 'Korean'}.`,
            'Return JSON only: {"memory":"..."}'
        ].join('\n');
    }

    function mgDiaryMemoryFromPayload(payload) {
        const candidates = [];
        const raw = String(payload?.rawText || '').trim();
        if (raw) {
            try {
                const parsed = JSON.parse(repairJsonish(extractJson(raw)));
                candidates.push(parsed.memory, parsed.diary, parsed.newMemory, parsed.content, parsed.text);
            } catch (_) {
                candidates.push(raw);
            }
        }
        for (const item of payload?.messages || []) candidates.push(item?.memory, item?.diary, item?.newMemory, item?.content, item?.text);
        for (const candidate of candidates) {
            const text = cleanVisibleAssistantText(String(candidate || '')).replace(/^memory\s*[:：]\s*/i, '').trim();
            if (text && text.length > 10) return text.slice(0, 2400);
        }
        return '';
    }

    async function mgCreateDailyDiaryMemory(character, dateKey) {
        const daily = mgCollectDailyDiaryMessages(character, dateKey);
        if (!daily || character.lastDailyDiaryMemoryDay === dateKey) return false;
        const key = `${character.id}:${dateKey}`;
        if (mgDailyDiaryMemoryInFlight.has(key)) return false;
        mgDailyDiaryMemoryInFlight.add(key);
        try {
            const payload = await callLLM([
                { role: 'system', content: mgDailyDiaryMemoryPrompt(character, dateKey, daily.count) },
                { role: 'user', content: `Today's full chat timeline:\n${daily.transcript}\n\nWrite the diary memory now.` }
            ], { maxTokens: 900 });
            const memory = mgDiaryMemoryFromPayload(payload);
            if (!memory) return false;
            ensureLoreState();
            const now = Date.now();
            const diaryTitle = `${character.name} diary ${dateKey}`;
            const diaryHeader = `[${dateKey} 23:59 daily diary]`;
            state.loreEntries = ensureLoreState().filter(entry => !(entry.characterId === character.id && entry.source === 'memory' && entry.comment === 'mgod_memory' && (entry.memoryDate === dateKey || entry.title === diaryTitle || String(entry.content || '').startsWith(diaryHeader))));
            const entry = normalizeLoreEntry({
                title: diaryTitle,
                key: `${character.name}, ${character.handle || character.id}, ${dateKey}, daily diary`,
                content: `${diaryHeader}\n${memory}`,
                comment: 'mgod_memory',
                scope: 'character',
                characterId: character.id,
                source: 'memory',
                insertorder: 120,
                createdAt: now
            });
            entry.memoryDate = dateKey;
            state.loreEntries.push(entry);
            character.lastDailyDiaryMemoryDay = dateKey;
            character.lastMemorySavedDay = dateKey;
            state.loreEntries = state.loreEntries.slice(-300);
            return true;
        } finally {
            mgDailyDiaryMemoryInFlight.delete(key);
        }
    }

    async function mgRunDailyDiaryMemoryForDate(dateKey) {
        let changed = false;
        for (const character of state.characters || []) changed = await mgCreateDailyDiaryMemory(character, dateKey) || changed;
        if (changed) {
            await saveState();
            await flushSaveState();
            if (isWindowOpen) showTransientNotice(`${dateKey} 일기형 메모리가 저장됐습니다.`);
        }
        return changed;
    }

    function mgIsDailyDiaryDue(now = new Date()) {
        return now.getHours() === 23 && now.getMinutes() >= 59;
    }

    async function mgRunDailyDiaryMemoryIfDue(now = new Date()) {
        if (!mgIsDailyDiaryDue(now)) return false;
        return mgRunDailyDiaryMemoryForDate(mgDailyDiaryDateKey(now));
    }

    function mgScheduleDailyDiaryMemory() {
        if (mgDailyDiaryMemoryTimer) {
            clearTimeout(mgDailyDiaryMemoryTimer);
            activeTimers.delete(mgDailyDiaryMemoryTimer);
            mgDailyDiaryMemoryTimer = null;
        }
        const now = new Date();
        const target = new Date(now);
        target.setHours(23, 59, 0, 0);
        if (target.getTime() <= now.getTime()) target.setDate(target.getDate() + 1);
        mgDailyDiaryMemoryTimer = scheduleTimer(target.getTime() - now.getTime(), () => {
            mgDailyDiaryMemoryTimer = null;
            mgRunDailyDiaryMemoryForDate(mgDailyDiaryDateKey(new Date())).catch(console.warn).finally(mgScheduleDailyDiaryMemory);
        });
    }

