    // --- STATUS QUALITY / PROFILE PREVIEW / TOP SAVE OVERRIDE ---
    function mgProfileStatusLooksCut(value) {
        const text = String(value || '').trim();
        if (!text) return true;
        if (/[,，、:;]$/.test(text)) return true;
        if (/^(뭐|뭐\?|뭐\.\.\.|못\s*말|못말|말|중|상태)$/i.test(text)) return true;
        if (/(?:하는|하고|되는|되고|하려|해서|인데|지만|니까|라고|다고|못\s*말|\s말)$/.test(text)) return true;
        if (/^(?:못|안|더|또|왜|아직|그냥)\s+[가-힣]{1,2}$/.test(text)) return true;
        return false;
    }

    mgCleanProfileStatusCandidate = function(value) {
        return cleanVisibleAssistantText(String(value || ''))
            .replace(/^```(?:json)?\s*|```$/g, '')
            .replace(/^\s*[,{}]?\s*["']?(statusMessage|status|message|text)["']?\s*[:：]\s*/i, '')
            .replace(/[{}[\]"]/g, '')
            .replace(/\s+/g, ' ')
            .trim();
    };

    mgIsUsefulProfileStatus = function(value) {
        const text = String(value || '').trim();
        if (!text) return false;
        if (text.length > 60) return false;
        if (/^(statusMessage|status|message|text)\s*[:：]?\s*$/i.test(text)) return false;
        if (/^\{.*\}$/.test(text)) return false;
        if (/^[,;:，、]+$/.test(text)) return false;
        if (mgProfileStatusLooksCut(text)) return false;
        return true;
    };

    const mgBaseGenerateProfileStatusQuality = mgGenerateProfileStatusMessage;
    mgGenerateProfileStatusMessage = async function(character) {
        if (!character) return false;
        try {
            const roomId = selectedRoomId || state.chatRooms?.[character.id]?.[0]?.id || '';
            const recent = (state.messages?.[roomId] || []).slice(-8).map(message => `${message.role === 'user' ? userNameFor(character) : character.name}: ${message.content || mediaLabel(message)}`).join('\n');
            const payload = await callLLM([
                { role: 'system', content: [
                    `Create a natural, diverse messenger profile status (상태메세지) for ${character.name}.`,
                    `Character profile: ${character.prompt || '(empty)'}`,
                    `Output language: ${state.config.language || 'Korean'}.`,
                    `The status must be a complete phrase or sentence. It can be short or slightly descriptive.`,
                    `Never end with a comma or unfinished word. Bad examples: "뭐,", "못 말", "하는", "중", "상태".`,
                    `Do NOT use literal action strings like ㅇㅇ하는 중 or ㅇㅇ한 상태.`,
                    `CRITICAL: Indirectly reflect the character's mood based on the RECENT CHAT CONTEXT. It can be a passing thought, how they feel about the conversation, a lyric, an emoji, or a simple dot.`,
                    `Embrace variety! Sometimes use extremely short ones ("휴", "💭"), and sometimes use longer, expressive thoughts ("오늘 이야기 즐겁네", "비 오니까 커피 마시고 싶다").`,
                    'Return JSON only: {"statusMessage":"..."}'
                ].join('\n') },
                { role: 'user', content: `Recent chat context:\n${recent || '(none)'}\n\nGenerate one natural statusMessage now.` }
            ], { maxTokens: 120 });
            const status = mgProfileStatusFromPayload(payload) || mgStatusFromContext(character, recent);
            if (!mgIsUsefulProfileStatus(status)) {
                const fallback = mgStatusFromContext(character, recent);
                if (!mgIsUsefulProfileStatus(fallback)) return false;
                character.statusMessage = fallback;
            } else {
                character.statusMessage = status;
            }
            character.statusUpdatedAt = Date.now();
            return true;
        } catch (error) {
            logDebug('profile-status-ai-error', `${character.name} profile status generation failed: ${error.message}`, {});
            return mgBaseGenerateProfileStatusQuality(character);
        }
    };

