    mgRenderSaveDock = function() {
        document.getElementById('mg-settings-save-dock')?.remove();
        document.querySelectorAll('[data-mg-top-save="1"]').forEach(element => element.remove());
        const target = mgVisibleSaveTarget();
        const actions = document.querySelector('.mg-top .mg-actions');
        if (!target || !actions) return;
        const wrapper = document.createElement('span');
        wrapper.className = 'mg-top-save-wrap';
        wrapper.dataset.mgTopSave = '1';
        wrapper.innerHTML = `<span id="mg-save-dock-status" class="mg-save-dock-status" title="${escapeHtml(target.note)}">변경 후 저장 필요</span><button class="mg-btn primary" type="button" id="mg-save-dock-button">저장</button>`;
        const settingsButton = actions.querySelector('[data-action="show-settings"]');
        if (settingsButton) actions.insertBefore(wrapper, settingsButton);
        else actions.prepend(wrapper);
        document.getElementById('mg-save-dock-button')?.addEventListener('click', event => {
            event.preventDefault();
            event.stopPropagation();
            mgSaveVisibleSettingsFromDock(event.currentTarget).catch(error => console.warn('[MessengerGod] top save failed:', error));
        });
    };

