    const mgBaseHandleActionUserCalendar = handleAction;
    handleAction = async function(action, element) {
        if (action === 'add-user-calendar-event') return mgAddUserCalendarEvent();
        if (action === 'add-user-calendar-preset') return mgAddUserCalendarPreset(element.dataset.preset || 'anniversary');
        if (action === 'delete-user-calendar-event') return mgDeleteUserCalendarEvent(element.dataset.id);
        return mgBaseHandleActionUserCalendar(action, element);
    };

    mgCalendarAutomationEnabled = function() {
        const characterEvents = (state.characters || []).some(character =>
            Array.isArray(character.calendarEvents) && character.calendarEvents.some(event => event && event.enabled)
        );
        const userEvents = mgNormalizeConfigCalendarEvents().some(event => event && event.enabled);
        return characterEvents || userEvents;
    };

    checkCalendarEvents = async function(now = new Date()) {
        const today = calendarTodayKey(now);
        const userEvents = mgNormalizeConfigCalendarEvents();
        for (const character of state.characters || []) {
            character.calendarEvents = (character.calendarEvents || []).map(normalizeCalendarEvent);
            const events = [
                ...character.calendarEvents.map(event => ({ ...event, mgCalendarScope: 'character' })),
                ...userEvents.map(event => ({ ...event, mgCalendarScope: 'user' }))
            ];
            for (const event of events) {
                const isUserEvent = event.mgCalendarScope === 'user';
                const key = `${isUserEvent ? 'user' : 'character'}:${character.id}:${event.id}:${today}`;
                const alreadyTriggered = isUserEvent
                    ? event.lastTriggeredByCharacter?.[character.id] === today
                    : event.lastTriggeredDate === today;
                if (!event.enabled || alreadyTriggered || calendarInFlight.has(key) || !calendarEventMatchesDate(event, now)) continue;
                calendarInFlight.add(key);
                if (isUserEvent) {
                    const source = userEvents.find(item => String(item.id) === String(event.id));
                    if (source) {
                        source.lastTriggeredByCharacter = source.lastTriggeredByCharacter || {};
                        source.lastTriggeredByCharacter[character.id] = today;
                    }
                } else {
                    const source = character.calendarEvents.find(item => String(item.id) === String(event.id));
                    if (source) source.lastTriggeredDate = today;
                }
                await saveState();
                try {
                    await sendCalendarEventMessage(character, event, today);
                } catch (error) {
                    logDebug('calendar-error', `${character.name} calendar reaction failed: ${error.message}`, { event: event.title, scope: event.mgCalendarScope });
                } finally {
                    calendarInFlight.delete(key);
                }
            }
        }
    };

    sendCalendarEventMessage = async function(character, event, today) {
        const roomId = state.chatRooms[character.id]?.[0]?.id;
        if (!roomId || generatingRooms.has(roomId)) return;
        const jobId = makeId();
        replyJobs[roomId] = jobId;
        pendingRoomStatus[roomId] = { characterId: character.id, phase: 'thinking', startedAt: Date.now(), updatedAt: Date.now(), jobId, detail: 'Calendar event letter' };
        render();
        const prompt = [
            `Act as ${character.name} in a private DM with ${userNameFor(character)}.`,
            'This is a calendar/anniversary message the character is allowed to send first, even if proactive first messages are disabled.',
            `Today is: ${today}.`,
            `Event title: ${event.title}.`,
            `Event scope: ${event.mgCalendarScope === 'user' ? 'user-wide event shared by every character' : 'this character only'}.`,
            `User profile: ${userProfileFor(character) || '(empty)'}`,
            `Character profile: ${character.prompt || '(empty)'}`,
            `User editable event prompt: ${event.note || '(none)'}`,
            'Follow the user editable event prompt. If it contains bracketed placeholders that were not edited, infer the most natural meaning from the title and relationship context.',
            'Write a polished, in-character private message. It may be a heartfelt letter or several natural chat bubbles. Make it specific to the character and relationship, not a generic preset.',
            'Do not mention system settings, saved calendar events, presets, JSON, or that you were instructed to write a letter.',
            `Output language: ${state.config.language}.`,
            'Return only JSON: {"reactionDelay":0,"messages":[{"content":"..."}],"newMemory":""}'
        ].join('\n');
        try {
            const payload = await callLLM([{ role: 'system', content: prompt }, { role: 'user', content: 'Send the anniversary message now.' }]);
            await deliverCharacterMessages(character, roomId, payload.messages, jobId, 'calendar');
            if (payload.newMemory) mgBaseAddMemoryDailyDiary(character.id, payload.newMemory);
        } finally {
            if (replyJobs[roomId] === jobId) {
                delete replyJobs[roomId];
                delete pendingRoomStatus[roomId];
            }
            render();
        }
    };
    // ---------------------------------------------------------------------

    // --- VERTEX AI TEXT PROVIDER ---
    DEFAULT_CONFIG.apiProfiles.vertex = DEFAULT_CONFIG.apiProfiles.vertex || {
        projectId: '',
        location: 'us-central1',
        apiModel: 'gemini-2.5-flash',
        serviceAccountJson: '',
        maxTokens: 700,
        temperature: 0.85
    };

    const MG_VERTEX_SCOPE = 'https://www.googleapis.com/auth/cloud-platform';
    const mgVertexTokenCache = new Map();

    function mgEnsureVertexProfile() {
        state.config.apiProfiles = state.config.apiProfiles || {};
        state.config.apiProfiles.vertex = {
            ...DEFAULT_CONFIG.apiProfiles.vertex,
            ...(state.config.apiProfiles.vertex || {})
        };
        return state.config.apiProfiles.vertex;
    }

    function mgBase64Url(value) {
        const base64 = value instanceof ArrayBuffer ? arrayBufferToBase64(value) : btoa(String(value));
        return base64.replace(/=+$/g, '').replace(/\+/g, '-').replace(/\//g, '_');
    }

    function mgVertexPrivateKeyToArrayBuffer(pem) {
        const base64 = String(pem || '').replace(/-----BEGIN PRIVATE KEY-----|-----END PRIVATE KEY-----|\s+/g, '');
        if (!base64) throw new Error('Vertex AI private_key가 비어 있습니다.');
        const binary = atob(base64);
        const bytes = new Uint8Array(binary.length);
        for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
        return bytes.buffer;
    }

    function mgParseVertexServiceAccount(raw) {
        const text = String(raw || '').trim();
        if (!text) throw new Error('Vertex AI JSON 서비스 키가 비어 있습니다.');
        let serviceAccount;
        try { serviceAccount = JSON.parse(text); }
        catch (error) { throw new Error(`Vertex AI JSON 서비스 키를 파싱하지 못했습니다: ${error.message}`); }
        if (!serviceAccount.client_email || !serviceAccount.private_key) throw new Error('Vertex AI 서비스 키에 client_email/private_key가 필요합니다.');
        return serviceAccount;
    }

    async function mgSignVertexJwt(serviceAccount) {
        if (!globalThis.crypto?.subtle) throw new Error('Vertex AI JWT 서명에는 WebCrypto가 필요합니다.');
        const now = Math.floor(Date.now() / 1000);
        const header = { alg: 'RS256', typ: 'JWT' };
        const payload = {
            iss: serviceAccount.client_email,
            scope: MG_VERTEX_SCOPE,
            aud: serviceAccount.token_uri || 'https://oauth2.googleapis.com/token',
            iat: now,
            exp: now + 3600
        };
        const signingInput = `${mgBase64Url(JSON.stringify(header))}.${mgBase64Url(JSON.stringify(payload))}`;
        const key = await crypto.subtle.importKey(
            'pkcs8',
            mgVertexPrivateKeyToArrayBuffer(serviceAccount.private_key),
            { name: 'RSASSA-PKCS1-v1_5', hash: 'SHA-256' },
            false,
            ['sign']
        );
        const signature = await crypto.subtle.sign('RSASSA-PKCS1-v1_5', key, new TextEncoder().encode(signingInput));
        return `${signingInput}.${mgBase64Url(signature)}`;
    }

    async function mgGetVertexAccessToken(profile) {
        const serviceAccount = mgParseVertexServiceAccount(profile.serviceAccountJson);
        const tokenUri = serviceAccount.token_uri || 'https://oauth2.googleapis.com/token';
        const cacheKey = [serviceAccount.client_email, serviceAccount.private_key_id || '', tokenUri].join('|');
        const cached = mgVertexTokenCache.get(cacheKey);
        if (cached && cached.expiresAt > Date.now() + 60000) return cached.accessToken;
        const assertion = await mgSignVertexJwt(serviceAccount);
        const body = `grant_type=${encodeURIComponent('urn:ietf:params:oauth:grant-type:jwt-bearer')}&assertion=${encodeURIComponent(assertion)}`;
        const response = await fetchRisuEndpoint(tokenUri, {
            method: 'POST',
            headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
            body
        }, 'Vertex OAuth');
        const rawText = await response.text();
        if (response.status < 200 || response.status >= 300) throw new Error(`Vertex OAuth 오류 ${response.status}: ${rawText.slice(0, 500)}`);
        const data = JSON.parse(rawText);
        if (!data.access_token) throw new Error('Vertex OAuth 응답에서 access_token을 찾지 못했습니다.');
        mgVertexTokenCache.set(cacheKey, { accessToken: data.access_token, expiresAt: Date.now() + Math.max(60, Number(data.expires_in) || 3600) * 1000 });
        return data.access_token;
    }

    function mgVertexEndpoint(profile) {
        const projectId = String(profile.projectId || '').trim();
        const location = String(profile.location || DEFAULT_CONFIG.apiProfiles.vertex.location || 'us-central1').trim();
        const model = String(profile.apiModel || '').trim();
        if (!projectId) throw new Error('Vertex AI Project ID가 비어 있습니다.');
        if (!location) throw new Error('Vertex AI 위치가 비어 있습니다.');
        if (!model) throw new Error('Vertex AI 모델이 비어 있습니다.');
        const modelResource = model.includes('/') ? model.replace(/^\/+/, '') : `publishers/google/models/${model}`;
        return `https://${location}-aiplatform.googleapis.com/v1/projects/${encodeURIComponent(projectId)}/locations/${encodeURIComponent(location)}/${modelResource.split('/').map(encodeURIComponent).join('/')}:generateContent`;
    }

    const mgBaseCallLLMVertexProvider = callLLM;
    callLLM = async function(messages, overrides = {}) {
        const apiType = state.config.apiType || 'gemini';
        if (apiType !== 'vertex') return mgBaseCallLLMVertexProvider(messages, overrides);
        const profile = mgEnsureVertexProfile();
        const maxTokens = Number(overrides.maxTokens || profile.maxTokens) || 700;
        const tempValue = Number.isFinite(Number(profile.temperature)) ? Number(profile.temperature) : 0.85;
        const accessToken = await mgGetVertexAccessToken(profile);
        const gemini = messagesToGemini(messages);
        const body = { contents: gemini.contents, generationConfig: { temperature: tempValue, maxOutputTokens: maxTokens } };
        if (gemini.systemInstruction) body.systemInstruction = gemini.systemInstruction;
        const response = await fetchRisuEndpoint(mgVertexEndpoint(profile), {
            method: 'POST',
            headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${accessToken}` },
            body
        }, 'Vertex text');
        const rawText = await response.text();
        if (response.status < 200 || response.status >= 300) throw new Error(`Vertex AI 오류 ${response.status}: ${rawText.slice(0, 500)}`);
        const text = textFromResponse(JSON.parse(rawText), 'gemini').replace(/^```(?:json)?\s*|```$/g, '').trim();
        if (!text) throw new Error('Vertex AI 응답에서 텍스트를 찾지 못했습니다.');
        const payload = overrides.rawTextOnly
            ? { rawText: text, text, content: text, messages: [{ delay: 0, content: text, sticker: '' }], newMemory: '' }
            : parseAssistantPayload(text);
        payload.rawText = text;
        return payload;
    };
    // -----------------------------

    // --- RISUAI AUXILIARY MODEL PROVIDER ---
    DEFAULT_CONFIG.apiProfiles.risuai = DEFAULT_CONFIG.apiProfiles.risuai || {
        staticModel: '',
        apiModel: '',
        apiEndpoint: '',
        apiKey: '',
        maxTokens: 700,
        temperature: 0.85
    };

    function mgEnsureRisuAiProfile() {
        state.config.apiProfiles = state.config.apiProfiles || {};
        state.config.apiProfiles.risuai = {
            ...DEFAULT_CONFIG.apiProfiles.risuai,
            ...(state.config.apiProfiles.risuai || {})
        };
        return state.config.apiProfiles.risuai;
    }

    function mgTextFromRisuRunResult(result) {
        if (typeof result === 'string') return result.trim();
        if (result && typeof result === 'object') {
            const text = result.result || result.content || result.text || result.message || result.response;
            if (typeof text === 'string') return text.trim();
        }
        return '';
    }

    function mgMessagesForRisuAi(messages) {
        return (messages || []).map(message => ({
            role: message.role === 'assistant' ? 'assistant' : message.role === 'system' ? 'system' : 'user',
            content: contentText(message.content)
        })).filter(message => message.content);
    }

    const mgBaseCallLLMRisuAiProvider = callLLM;
    callLLM = async function(messages, overrides = {}) {
        const apiType = state.config.apiType || 'gemini';
        if (apiType !== 'risuai') return mgBaseCallLLMRisuAiProvider(messages, overrides);
        if (typeof Risu.runLLMModel !== 'function') throw new Error('RisuAI runLLMModel API를 찾지 못했습니다.');
        const profile = mgEnsureRisuAiProfile();
        const opts = {
            messages: mgMessagesForRisuAi(messages),
            mode: 'otherAx'
        };
        if (profile.staticModel) opts.staticModel = String(profile.staticModel).trim();
        logDebug('llm-risuai-start', opts.staticModel ? `RisuAI auxiliary model request: ${opts.staticModel}` : 'RisuAI auxiliary model request', { messageCount: opts.messages.length });
        const raw = await Risu.runLLMModel(opts);
        const text = mgTextFromRisuRunResult(raw);
        if (!text) throw new Error('RisuAI 보조모델 응답이 비어 있습니다.');
        const payload = parseAssistantPayload(text);
        payload.rawText = text;
        logDebug('llm-risuai-done', 'RisuAI auxiliary model response parsed', { textPreview: text.slice(0, 160) });
        return payload;
    };

    const mgBaseApiHtmlRisuAiProvider = apiHtml;
    apiHtml = function() {
        mgEnsureRisuAiProfile();
        mgEnsureVertexProfile();
        const apiType = state.config.apiType || 'gemini';
        const profile = state.config.apiProfiles[apiType] || state.config.apiProfiles.gemini || {};
        const title = typeof guideTitle === 'function' ? guideTitle('API 설정', 'api') : 'API 설정';
        const providerOptions = [['risuai', 'RisuAI auxiliary model'], ['vertex', 'Vertex AI'], ['gemini', 'Gemini'], ['openai', 'OpenAI'], ['anthropic', 'Anthropic'], ['custom', 'Custom']];
        const common = `${selectHtml('cfg-apiType', 'Provider', apiType, providerOptions)}${fieldHtml('cfg-language', 'Output language', state.config.language || 'Korean')}`;
        let fields;
        let help = 'After changing Provider, save once to refresh the fields.';
        if (apiType === 'risuai') {
            fields = `${common}${fieldHtml('api-static-model', 'Auxiliary model ID', profile.staticModel || '', 'text', 'Leave empty to use RisuAI default auxiliary model settings.')}`;
            help = `RisuAI auxiliary model uses Risu's built-in model runner, so no separate API key is required. ${help}`;
        } else if (apiType === 'vertex') {
            fields = `${common}${fieldHtml('api-project-id', 'Vertex Project ID', profile.projectId || '')}${fieldHtml('api-location', 'Location', profile.location || 'us-central1')}${fieldHtml('api-model', 'Model', profile.apiModel || 'gemini-2.5-flash')}${fieldHtml('api-tokens', 'Max tokens', profile.maxTokens || 700, 'number')}${fieldHtml('api-temp', 'Temperature', profile.temperature ?? 0.85, 'number')}<div style="grid-column:1/-1">${textareaHtml('api-service-account-json', 'Service account JSON', profile.serviceAccountJson || '')}</div>`;
            help = `Vertex AI uses a Google service account JSON key. ${help}`;
        } else {
            fields = `${common}${fieldHtml('api-model', 'Model', profile.apiModel || '')}${fieldHtml('api-endpoint', 'Endpoint', profile.apiEndpoint || '')}${fieldHtml('api-key', 'API key', profile.apiKey || '', 'password')}${fieldHtml('api-tokens', 'Max tokens', profile.maxTokens || 700, 'number')}${fieldHtml('api-temp', 'Temperature', profile.temperature ?? 0.85, 'number')}`;
        }
        return `<section class="mg-panel mg-settings"><div class="mg-section"><h3>${title}</h3><div class="mg-grid">${fields}</div><p class="mg-help">${escapeHtml(help)}</p><div class="mg-inline" style="margin-top:12px"><button class="mg-btn primary" data-action="save-api">API 저장</button><button class="mg-btn" data-action="test-api">테스트</button></div></div></section>`;
    };
    const mgBaseSaveApiFromFormRisuAiProvider = saveApiFromForm;
    saveApiFromForm = async function() {
        const selectedType = document.getElementById('cfg-apiType')?.value || state.config.apiType || 'gemini';
        if (selectedType === 'risuai') mgEnsureRisuAiProfile();
        if (selectedType === 'vertex') mgEnsureVertexProfile();
        const staticModel = valueOf('api-static-model');
        const vertexValues = selectedType === 'vertex' ? {
            projectId: valueOf('api-project-id'),
            location: valueOf('api-location'),
            apiModel: valueOf('api-model'),
            serviceAccountJson: valueOf('api-service-account-json'),
            maxTokens: valueOf('api-tokens'),
            temperature: valueOf('api-temp'),
            language: valueOf('cfg-language')
        } : null;
        const result = await mgBaseSaveApiFromFormRisuAiProvider();
        if (selectedType === 'risuai') {
            state.config.apiType = 'risuai';
            const profile = mgEnsureRisuAiProfile();
            profile.staticModel = staticModel;
            profile.apiModel = staticModel;
            profile.maxTokens = Math.max(32, Number(valueOf('api-tokens')) || Number(profile.maxTokens) || 700);
            profile.temperature = Number.isFinite(Number(valueOf('api-temp'))) ? Number(valueOf('api-temp')) : Number(profile.temperature) || 0.85;
            state.config.language = valueOf('cfg-language') || state.config.language || 'Korean';
            await saveState();
            render();
        }
        if (selectedType === 'vertex') {
            state.config.apiType = 'vertex';
            const profile = mgEnsureVertexProfile();
            profile.projectId = vertexValues?.projectId || profile.projectId || '';
            profile.location = vertexValues?.location || profile.location || 'us-central1';
            profile.apiModel = vertexValues?.apiModel || profile.apiModel || 'gemini-2.5-flash';
            profile.serviceAccountJson = vertexValues?.serviceAccountJson || profile.serviceAccountJson || '';
            profile.maxTokens = Math.max(32, Number(vertexValues?.maxTokens) || Number(profile.maxTokens) || 700);
            profile.temperature = Number.isFinite(Number(vertexValues?.temperature)) ? Number(vertexValues.temperature) : Number(profile.temperature) || 0.85;
            state.config.language = vertexValues?.language || state.config.language || 'Korean';
            await saveState();
            if (typeof flushSaveState === 'function') await flushSaveState();
            render();
        }
        return result;
    };
