    // --- NAI / COMFYUI ONLY IMAGE PROVIDERS ---
    DEFAULT_CONFIG.imageGeneration.provider = 'novelai';
    DEFAULT_CONFIG.imageGeneration.comfyuiEndpoint = DEFAULT_CONFIG.imageGeneration.comfyuiEndpoint || 'http://127.0.0.1:8188';
    DEFAULT_CONFIG.imageGeneration.comfyuiWorkflow = DEFAULT_CONFIG.imageGeneration.comfyuiWorkflow || '';
    DEFAULT_CONFIG.imageGeneration.comfyuiClientId = DEFAULT_CONFIG.imageGeneration.comfyuiClientId || '';
    DEFAULT_CONFIG.imageGeneration.comfyuiPositiveNodeId = DEFAULT_CONFIG.imageGeneration.comfyuiPositiveNodeId || '';
    DEFAULT_CONFIG.imageGeneration.comfyuiNegativeNodeId = DEFAULT_CONFIG.imageGeneration.comfyuiNegativeNodeId || '';

    const mgBaseMergeConfigNaiComfyOnly = mergeConfig;
    mergeConfig = function(saved) {
        const config = mgBaseMergeConfigNaiComfyOnly(saved);
        config.imageGeneration = { ...DEFAULT_CONFIG.imageGeneration, ...(config.imageGeneration || {}) };
        if (!['novelai', 'comfyui'].includes(config.imageGeneration.provider)) config.imageGeneration.provider = 'novelai';
        return config;
    };

    const mgBaseCallImageGenerationNaiComfyOnly = callImageGeneration;
    callImageGeneration = async function(character, item) {
        const config = state.config.imageGeneration || {};
        if (config.provider === 'comfyui') return mgCallComfyUiImageGeneration(character, item, config);
        return callNovelAiImageGeneration(character, item, { ...config, provider: 'novelai' });
    };

    async function mgCallComfyUiImageGeneration(character, item, config) {
        const endpoint = (config.comfyuiEndpoint || DEFAULT_CONFIG.imageGeneration.comfyuiEndpoint || 'http://127.0.0.1:8188').replace(/\/+$/, '');
        const workflowJson = config.comfyuiWorkflow;
        if (!workflowJson) throw new Error('ComfyUI workflow JSON is empty.');
        const posNodeId = String(config.comfyuiPositiveNodeId || '').trim();
        const negNodeId = String(config.comfyuiNegativeNodeId || '').trim();
        const tagConfig = { ...config, provider: 'comfyui', illustrationMode: true };
        let prompt;
        try {
            prompt = await prepareImagePrompt(character, item, tagConfig);
        } catch (error) {
            logDebug('comfyui-tag-fallback', `ComfyUI tag prompt failed, using fallback: ${error.message}`, {});
            prompt = item.imagePrompt || fallbackSnsImagePrompt(character, item.imageCaption || 'social media portrait');
            item.finalImagePrompt = prompt;
        }
        const negPrompt = selectedLightboardPreset(config)?.negative || config.negativePrompt || DEFAULT_CONFIG.imageGeneration.negativePrompt || '';
        let workflow;
        try {
            workflow = typeof workflowJson === 'string' ? JSON.parse(workflowJson) : clone(workflowJson);
        } catch (error) {
            throw new Error(`ComfyUI workflow JSON parse failed: ${error.message}`);
        }

        let posInjected = false;
        if (posNodeId && workflow[posNodeId]?.inputs) {
            const existing = String(workflow[posNodeId].inputs.text || '');
            workflow[posNodeId].inputs.text = existing.includes('{{risu_prompt}}') ? existing.replaceAll('{{risu_prompt}}', prompt) : prompt;
            posInjected = true;
        } else {
            for (const [id, node] of Object.entries(workflow)) {
                if (node?.class_type === 'CLIPTextEncode' && node.inputs && 'text' in node.inputs && String(node.inputs.text || '').trim()) {
                    const existing = String(node.inputs.text || '');
                    node.inputs.text = existing.includes('{{risu_prompt}}') ? existing.replaceAll('{{risu_prompt}}', prompt) : prompt;
                    posInjected = true;
                    logDebug('comfyui-inject-pos-auto', `Positive prompt auto-injected to node ${id}`, { prompt: prompt.slice(0, 100) });
                    break;
                }
            }
        }
        if (!posInjected) logDebug('comfyui-inject-pos-warn', 'No positive prompt node found.', {});

        let negInjected = false;
        if (negNodeId && workflow[negNodeId]?.inputs) {
            const existing = String(workflow[negNodeId].inputs.text || '');
            workflow[negNodeId].inputs.text = existing.includes('{{risu_negative}}') ? existing.replaceAll('{{risu_negative}}', negPrompt) : negPrompt;
            negInjected = true;
        } else if (negPrompt) {
            for (const [id, node] of Object.entries(workflow)) {
                if (node?.class_type === 'CLIPTextEncode' && node.inputs && 'text' in node.inputs) {
                    const existing = String(node.inputs.text || '').trim();
                    if (!existing || /negative|uc|lowres|bad quality|worst quality/i.test(existing)) {
                        node.inputs.text = String(node.inputs.text || '').includes('{{risu_negative}}')
                            ? String(node.inputs.text || '').replaceAll('{{risu_negative}}', negPrompt)
                            : negPrompt;
                        negInjected = true;
                        logDebug('comfyui-inject-neg-auto', `Negative prompt auto-injected to node ${id}`, { prompt: negPrompt.slice(0, 100) });
                        break;
                    }
                }
            }
        }
        if (!negInjected && negPrompt) logDebug('comfyui-inject-neg-warn', 'No negative prompt node found.', {});

        const clientId = config.comfyuiClientId || makeId();
        const response = await fetchRisuEndpoint(`${endpoint}/prompt`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: { prompt: workflow, client_id: clientId }
        }, 'ComfyUI image');
        const result = await response.json();
        if (result.error) throw new Error(`ComfyUI error: ${result.error.message || JSON.stringify(result.error)}`);
        const promptId = result.prompt_id;
        if (!promptId) throw new Error('ComfyUI did not return prompt_id.');

        for (let i = 0; i < 120; i++) {
            await new Promise(resolve => setTimeout(resolve, 2000));
            try {
                const pollResponse = await fetchRisuEndpoint(`${endpoint}/history/${encodeURIComponent(promptId)}`, { method: 'GET' }, 'ComfyUI poll');
                const history = await pollResponse.json();
                const outputs = history?.[promptId]?.outputs || {};
                for (const output of Object.values(outputs)) {
                    const image = output?.images?.[0];
                    if (!image) continue;
                    const imageResponse = await fetchRisuEndpoint(
                        `${endpoint}/view?filename=${encodeURIComponent(image.filename)}&subfolder=${encodeURIComponent(image.subfolder || '')}&type=${encodeURIComponent(image.type || 'output')}`,
                        { method: 'GET', rawResponse: true },
                        'ComfyUI image download'
                    );
                    const contentType = imageResponse.headers?.get?.('content-type') || 'image/png';
                    const buffer = await imageResponse.arrayBuffer();
                    return `data:${contentType.split(';')[0] || 'image/png'};base64,${arrayBufferToBase64(buffer)}`;
                }
            } catch (error) {
                logDebug('comfyui-poll-error', `ComfyUI poll failed: ${error.message}`, {});
            }
        }
        throw new Error('ComfyUI image generation timed out.');
    }

    imageSettingsHtml = function() {
        const image = { ...DEFAULT_CONFIG.imageGeneration, ...(state.config.imageGeneration || {}) };
        if (!['novelai', 'comfyui'].includes(image.provider)) image.provider = 'novelai';
        const presetOptions = Object.keys(image.lightboardPresets || {}).map(name => [name, name]);
        const selectedName = image.selectedLightboardPreset || presetOptions[0]?.[0] || '';
        const selectedPreset = selectedName ? image.lightboardPresets?.[selectedName] || {} : {};
        const providerFields = image.provider === 'comfyui'
            ? `${fieldHtml('img-comfyui-endpoint', 'ComfyUI endpoint', image.comfyuiEndpoint || DEFAULT_CONFIG.imageGeneration.comfyuiEndpoint)}${fieldHtml('img-comfyui-client-id', 'Client ID', image.comfyuiClientId || '')}${fieldHtml('img-comfyui-pos-node', 'Positive node ID', image.comfyuiPositiveNodeId || '')}${fieldHtml('img-comfyui-neg-node', 'Negative node ID', image.comfyuiNegativeNodeId || '')}<div style="grid-column:1/-1">${textareaHtml('img-comfyui-workflow', 'ComfyUI workflow JSON', image.comfyuiWorkflow || '')}</div>`
            : `${fieldHtml('img-key', 'NovelAI API key', image.apiKey || '', 'password')}${fieldHtml('img-nai-endpoint', 'NovelAI URL', image.naiEndpoint || DEFAULT_CONFIG.imageGeneration.naiEndpoint)}${fieldHtml('img-nai-model', 'NovelAI model', image.naiModel || DEFAULT_CONFIG.imageGeneration.naiModel)}`;
        return `<section class="mg-panel mg-settings"><div class="mg-section"><div class="mg-inline" style="justify-content:space-between"><h3>이미지 생성</h3><button class="mg-btn" data-action="import-lightboard-presets">라이트보드 프리셋 가져오기</button></div><div class="mg-inline" style="margin-bottom:10px"><label class="mg-check"><input id="img-enabled" type="checkbox" ${image.enabled ? 'checked' : ''}> 캐릭터 사진 보내기</label><label class="mg-check"><input id="img-illustration" type="checkbox" ${image.illustrationMode ? 'checked' : ''}> 태그/일러스트 모드</label><label class="mg-check"><input id="img-nsfw" type="checkbox" ${image.nsfw ? 'checked' : ''}> NSFW 태그</label></div>${presetOptions.length ? selectHtml('img-lightboard-preset', '라이트보드 프리셋', selectedName, presetOptions) : '<p class="mg-help">프리셋이 없으면 아래에서 직접 입력할 수 있습니다.</p>'}<div class="mg-grid">${selectHtml('img-provider', 'Provider', image.provider, [['novelai','NovelAI'],['comfyui','ComfyUI']])}${fieldHtml('img-preset-name', '프리셋 이름', selectedName || 'custom')}${providerFields}${fieldHtml('img-width', 'Width', image.width ?? 832, 'number')}${fieldHtml('img-height', 'Height', image.height ?? 1216, 'number')}${selectHtml('img-sampler', 'Sampler', image.sampler || 'k_euler_ancestral', [['k_euler_ancestral','Euler Ancestral'],['k_euler','Euler'],['k_dpmpp_2m','DPM++ 2M'],['k_dpmpp_sde','DPM++ SDE']])}${selectHtml('img-noise', 'Noise Schedule', image.noiseSchedule || 'karras', [['karras','karras'],['native','native'],['exponential','exponential'],['polyexponential','polyexponential']])}${fieldHtml('img-steps', 'Steps', image.steps ?? 28, 'number')}${fieldHtml('img-scale', 'CFG scale', image.scale ?? 6, 'number')}${fieldHtml('img-cfg-rescale', 'CFG rescale', image.cfgRescale ?? 0.5, 'number')}</div><div class="mg-inline" style="margin-top:10px"><label class="mg-check"><input id="img-quality-toggle" type="checkbox" ${image.qualityToggle !== false ? 'checked' : ''}> Quality/Variety</label><label class="mg-check"><input id="img-spontaneous-enabled" type="checkbox" ${image.spontaneousEnabled ? 'checked' : ''}> 자발 사진 허용</label></div><div class="mg-grid" style="margin-top:10px">${fieldHtml('img-spontaneous-chance', '자발 사진 확률(0-100)', image.spontaneousChance ?? 0, 'number')}${fieldHtml('img-spontaneous-cooldown-messages', '자발 사진 쿨다운(메시지)', image.spontaneousCooldownMessages ?? 6, 'number')}${fieldHtml('img-spontaneous-cooldown-minutes', '자발 사진 쿨다운(분)', image.spontaneousCooldownMinutes ?? 0, 'number')}${fieldHtml('img-retained-count', '최근 이미지 보존 수', image.retainedImageCount ?? 5, 'number')}</div>${textareaHtml('img-prefix', '사진/이미지 기본 프롬프트', image.promptPrefix || DEFAULT_CONFIG.imageGeneration.promptPrefix)}${textareaHtml('img-style-preset', '태그 스타일 프리셋', image.stylePreset || '')}${textareaHtml('img-preset-positive', '선택 프리셋 Positive', selectedPreset.positive || '')}${textareaHtml('img-preset-negative', '선택 프리셋 Negative', selectedPreset.negative || '')}${textareaHtml('img-author-note', '작가 노트', image.authorNote || '')}${textareaHtml('img-negative', '기본 Negative', image.negativePrompt || DEFAULT_CONFIG.imageGeneration.negativePrompt)}<p class="mg-help">OpenAI image generation has been removed from this UI. NovelAI and ComfyUI both use the same character-aware tag prompt pipeline.</p><div class="mg-inline" style="justify-content:flex-end;margin-top:12px"><button class="mg-btn primary" data-action="save-api">이미지 설정 저장</button></div></div></section>`;
    };

    const mgBaseSaveApiFromFormNaiComfyOnly = saveApiFromForm;
    saveApiFromForm = async function() {
        const hasImageForm = Boolean(document.getElementById('img-provider'));
        const current = { ...DEFAULT_CONFIG.imageGeneration, ...(state.config.imageGeneration || {}) };
        const provider = document.getElementById('img-provider')?.value || current.provider || 'novelai';
        const selectedPresetName = valueOf('img-preset-name') || document.getElementById('img-lightboard-preset')?.value || current.selectedLightboardPreset || 'custom';
        const positive = valueOf('img-preset-positive');
        const negative = valueOf('img-preset-negative');
        const result = await mgBaseSaveApiFromFormNaiComfyOnly();
        if (hasImageForm) {
            const presets = { ...(current.lightboardPresets || {}) };
            if (positive || negative) presets[selectedPresetName] = { positive, negative };
            state.config.imageGeneration = {
                ...DEFAULT_CONFIG.imageGeneration,
                ...current,
                enabled: Boolean(document.getElementById('img-enabled')?.checked),
                provider: provider === 'comfyui' ? 'comfyui' : 'novelai',
                apiKey: valueOf('img-key') || current.apiKey || '',
                naiEndpoint: valueOf('img-nai-endpoint') || current.naiEndpoint || DEFAULT_CONFIG.imageGeneration.naiEndpoint,
                naiModel: valueOf('img-nai-model') || current.naiModel || DEFAULT_CONFIG.imageGeneration.naiModel,
                comfyuiEndpoint: valueOf('img-comfyui-endpoint') || current.comfyuiEndpoint || DEFAULT_CONFIG.imageGeneration.comfyuiEndpoint,
                comfyuiClientId: valueOf('img-comfyui-client-id') || current.comfyuiClientId || '',
                comfyuiWorkflow: valueOf('img-comfyui-workflow') || current.comfyuiWorkflow || '',
                comfyuiPositiveNodeId: valueOf('img-comfyui-pos-node') || current.comfyuiPositiveNodeId || '',
                comfyuiNegativeNodeId: valueOf('img-comfyui-neg-node') || current.comfyuiNegativeNodeId || '',
                width: clampImageDimension(valueOf('img-width'), DEFAULT_CONFIG.imageGeneration.width),
                height: clampImageDimension(valueOf('img-height'), DEFAULT_CONFIG.imageGeneration.height),
                sampler: document.getElementById('img-sampler')?.value || current.sampler || DEFAULT_CONFIG.imageGeneration.sampler,
                noiseSchedule: document.getElementById('img-noise')?.value || current.noiseSchedule || DEFAULT_CONFIG.imageGeneration.noiseSchedule,
                steps: Math.max(1, Math.min(50, Number(valueOf('img-steps')) || current.steps || DEFAULT_CONFIG.imageGeneration.steps)),
                scale: Number(valueOf('img-scale')) || current.scale || DEFAULT_CONFIG.imageGeneration.scale,
                cfgRescale: Number.isFinite(Number(valueOf('img-cfg-rescale'))) ? Number(valueOf('img-cfg-rescale')) : current.cfgRescale ?? DEFAULT_CONFIG.imageGeneration.cfgRescale,
                qualityToggle: Boolean(document.getElementById('img-quality-toggle')?.checked),
                promptPrefix: valueOf('img-prefix') || current.promptPrefix || DEFAULT_CONFIG.imageGeneration.promptPrefix,
                illustrationMode: Boolean(document.getElementById('img-illustration')?.checked),
                nsfw: Boolean(document.getElementById('img-nsfw')?.checked),
                stylePreset: valueOf('img-style-preset'),
                selectedLightboardPreset: selectedPresetName,
                lightboardPresets: presets,
                authorNote: valueOf('img-author-note'),
                negativePrompt: valueOf('img-negative') || current.negativePrompt || DEFAULT_CONFIG.imageGeneration.negativePrompt,
                spontaneousEnabled: Boolean(document.getElementById('img-spontaneous-enabled')?.checked),
                spontaneousChance: Math.max(0, Math.min(100, Number(valueOf('img-spontaneous-chance')) || 0)),
                spontaneousCooldownMessages: Math.max(1, Math.min(80, Number(valueOf('img-spontaneous-cooldown-messages')) || 6)),
                spontaneousCooldownMinutes: Math.max(0, Math.min(1440, Number(valueOf('img-spontaneous-cooldown-minutes')) || 0)),
                retainedImageCount: Math.max(0, Math.min(30, Number(valueOf('img-retained-count')) || 0))
            };
            await saveState();
            render();
        }
        return result;
    };
