    // ---------------------------------------------------------------------

    // --- FINAL SNS GENERATION STABILITY / MOBILE BUTTON LAYOUT FIX ---
    function mgFinalSnsCreateButtonHtml() {
        return `<button class="mg-btn primary mg-sns-title-create" type="button" data-action="create-sns-post" ${isPosting ? 'disabled' : ''}>${isPosting ? '작성 중...' : 'SNS 생성'}</button>`;
    }

    const mgBaseSnsComposeHtmlFinalStability = snsComposeHtml;
    snsComposeHtml = function(character, sns) {
        let html = mgBaseSnsComposeHtmlFinalStability(character, sns);
        if (!html.includes('mg-sns-title-create') && html.includes('mg-sns-compose-title')) {
            html = html.replace('<span class="mg-inline">', `<span class="mg-inline">${mgFinalSnsCreateButtonHtml()}`);
        }
        return html;
    };

    const mgBaseSocialHtmlFinalStability = socialHtml;
    socialHtml = function(...args) {
        let html = mgBaseSocialHtmlFinalStability.apply(this, args);
        const composeIndex = html.indexOf('mg-sns-compose-fixed');
        if (composeIndex > 0) {
            const beforeCompose = html.slice(0, composeIndex).replace(/<button class="mg-btn primary"(?=[^>]*data-action="create-sns-post")[\s\S]*?<\/button>/, '');
            html = beforeCompose + html.slice(composeIndex);
        }
        return html;
    };

    function mgFinalSnsFallbackStats() {
        const metric = typeof randomMetric === 'function' ? randomMetric : ((min, max) => Math.floor(min + Math.random() * Math.max(1, max - min + 1)));
        return { views: metric(90, 1800), likes: metric(1, 80), replies: 0, reposts: metric(0, 12), bookmarks: metric(0, 18) };
    }

    function mgFinalBuildFallbackSnsPost(character, roomId, hintText = '', options = {}, sourceError = null) {
        const sns = { ...DEFAULT_CONFIG.sns, ...(state.config?.sns || {}), ...(options?.sns || {}) };
        const rawText = typeof fallbackSnsPostText === 'function'
            ? fallbackSnsPostText(character, roomId, hintText)
            : `${character?.name || '캐릭터'}의 오늘 기록.`;
        const text = (typeof cleanSnsVisibleText === 'function' ? cleanSnsVisibleText(rawText) : String(rawText || '').trim()) || `${character?.name || '캐릭터'}의 오늘 기록.`;
        const targetPlatforms = sns.platform === 'hybrid' ? ['twitter', 'instagram'] : [sns.platform === 'instagram' ? 'instagram' : 'twitter'];
        const attachedImage = options?.image || '';
        const hashtags = typeof ensureSnsHashtags === 'function' ? ensureSnsHashtags([], character, text, hintText) : [];
        const platforms = targetPlatforms.map((platform, index) => ({
            platform,
            displayName: String(character?.name || 'Character'),
            handle: String(character?.handle || character?.id || 'character').replace(/^@/, ''),
            text,
            hashtags,
            time: 'now',
            stats: mgFinalSnsFallbackStats(),
            comments: [],
            image: index === 0 ? attachedImage : '',
            imagePrompt: !sns.textOnly && typeof fallbackSnsImagePrompt === 'function' ? fallbackSnsImagePrompt(character, text) : '',
            imageCaption: text
        }));
        const first = platforms[0] || {};
        const post = {
            id: makeId(),
            characterId: character?.id,
            platforms,
            dms: [],
            text,
            image: first.image || attachedImage,
            imagePrompt: first.imagePrompt || '',
            likes: Number(first.stats?.likes) || 0,
            createdAt: Date.now(),
            sourceRoomId: roomId,
            hint: hintText,
            auto: options?.manual ? false : true,
            fallbackReason: sourceError?.message || ''
        };
        state.snsPosts = state.snsPosts || [];
        state.snsPosts.unshift(post);
        try { if (typeof noteSnsPost === 'function') noteSnsPost(character, post); } catch (_) {}
        const messages = state.messages?.[roomId] || [];
        if (character) character.lastSnsMessageCount = messages.length;
        return post;
    }

    const mgBaseGenerateSnsPostFinalStability = generateSnsPost;
    generateSnsPost = async function(character, roomId, hintText = '', options = {}) {
        try {
            return await mgBaseGenerateSnsPostFinalStability(character, roomId, hintText, options);
        } catch (error) {
            try { logDebug('sns-final-fallback', `${character?.name || 'Character'} SNS hard fallback used: ${error.message}`, { roomId }); } catch (_) {}
            return mgFinalBuildFallbackSnsPost(character, roomId, hintText, options, error);
        }
    };

    const mgBaseInjectStylesSnsFinalStability = injectStyles;
    injectStyles = function() {
        mgBaseInjectStylesSnsFinalStability();
        if (document.getElementById('mg-final-sns-stability-style')) return;
        const style = document.createElement('style');
        style.id = 'mg-final-sns-stability-style';
        style.textContent = `
            .mg-social>.mg-social-head{flex:0 0 auto!important;min-height:70px!important;height:auto!important;padding:14px 18px!important;box-sizing:border-box!important;align-items:center!important;overflow:visible!important}
            .mg-social>.mg-social-head>div{min-width:0!important}.mg-social>.mg-social-head>.mg-btn[data-action="create-sns-post"]{display:none!important}
            .mg-sns-compose-fixed{box-sizing:border-box!important;clear:both!important}.mg-sns-compose-fixed .mg-sns-compose-title{box-sizing:border-box!important;overflow:hidden!important}.mg-sns-compose-fixed .mg-sns-compose-title>.mg-inline{min-width:0!important}
            .mg-sns-title-create{background:var(--accent2)!important;border-color:var(--accent)!important;color:var(--accent-ink)!important;font-weight:900!important;white-space:nowrap!important;word-break:keep-all!important;writing-mode:horizontal-tb!important;flex:0 0 auto!important}
            @media(max-width:780px){
                .mg-social>.mg-social-head{display:block!important;min-height:auto!important;padding:14px 18px 12px!important;border-bottom:1px solid var(--border)!important}.mg-social>.mg-social-head h2{margin:0 0 4px!important}.mg-social>.mg-social-head p{margin:0!important;white-space:nowrap!important;overflow:hidden!important;text-overflow:ellipsis!important}
                .mg-sns-compose-fixed{width:auto!important;max-width:calc(100vw - 24px)!important;margin:10px 12px 14px!important;position:relative!important;z-index:1!important}.mg-sns-compose-fixed .mg-sns-compose-title{display:grid!important;grid-template-columns:minmax(0,1fr)!important;gap:9px!important;align-items:stretch!important;padding:12px!important}.mg-sns-compose-fixed .mg-sns-compose-title>span:first-child{min-width:0!important}.mg-sns-compose-fixed .mg-sns-compose-title>span:first-child strong,.mg-sns-compose-fixed .mg-sns-compose-title>span:first-child small{display:block!important;max-width:100%!important;overflow:hidden!important;text-overflow:ellipsis!important;white-space:nowrap!important}
                .mg-sns-compose-fixed .mg-sns-compose-title>.mg-inline{display:flex!important;flex-wrap:nowrap!important;gap:7px!important;width:100%!important;max-width:100%!important;overflow-x:auto!important;overflow-y:hidden!important;overscroll-behavior-x:contain!important;-webkit-overflow-scrolling:touch!important;scrollbar-width:none!important;padding:1px 0 3px!important;justify-content:flex-start!important}.mg-sns-compose-fixed .mg-sns-compose-title>.mg-inline::-webkit-scrollbar{display:none!important}.mg-sns-compose-fixed .mg-sns-compose-title>.mg-inline .mg-btn{flex:0 0 auto!important;width:auto!important;min-width:max-content!important;height:34px!important;padding:0 12px!important;font-size:12px!important;line-height:34px!important}
            }
        `;
        document.head.appendChild(style);
    };
    // ---------------------------------------------------------------------

    // --- FINAL DEBUG NOISE FILTER / CHARACTER CALL INTENT FIX ---
    const MG_HIDDEN_DEBUG_TYPES = new Set(['media-upload-skipped']);
    debugLogs = debugLogs.filter(item => !MG_HIDDEN_DEBUG_TYPES.has(item?.type));

    const mgBaseLogDebugNoiseFilter = logDebug;
    logDebug = function(type, message, data = {}) {
        if (MG_HIDDEN_DEBUG_TYPES.has(type)) {
            console.log('[MessengerGod]', type, redactSensitiveLogValue(message), redactSensitiveLogValue(data));
            return;
        }
        return mgBaseLogDebugNoiseFilter(type, message, data);
    };

    const mgBaseDebugHtmlNoiseFilter = debugHtml;
    debugHtml = function(...args) {
        const previousLogs = debugLogs;
        debugLogs = previousLogs.filter(item => !MG_HIDDEN_DEBUG_TYPES.has(item?.type));
        try {
            return mgBaseDebugHtmlNoiseFilter.apply(this, args);
        } finally {
            debugLogs = previousLogs;
        }
    };

    function mgLooksLikePhoneCallIntentText(text) {
        const value = String(text || '').replace(/\s+/g, ' ').trim();
        if (!value) return false;
        if (/(못|안|나중|다음에|취소|끊|거절|받지 마|받지마|cannot|can't|wont|won't|later|not now|don't call|do not call|切る|切って|無理|あとで)/i.test(value)) return false;
        return /(전화\s*(걸|할|하|해|하자|줄|준다|받|연결)|통화\s*(하|할|하자|걸|연결|받)|지금\s*(걸게|건다|걸어|전화|통화)|걸게|걸어도 돼|받아|받을래|call\s*(you|me|now)|phone\s*call|ring\s*you|電話|通話|かける|掛ける|今から.*(?:電話|通話)|出て|出る)/i.test(value);
    }

    function mgPhoneIntentTitle(character) {
        return `${character?.name || '상대'} 전화`;
    }

    function mgUpgradePhoneIntentMessages(character, messages) {
        if (!mgCharacterPhoneInvitesAllowed()) return messages;
        return (Array.isArray(messages) ? messages : []).map(item => {
            if (!item || item.callInvite || item.phoneCall || item.call) return item;
            const text = mgPhoneVisibleText(item.content || item.text || item.body || '');
            if (!mgLooksLikePhoneCallIntentText(text)) return item;
            return {
                ...item,
                content: '',
                callInvite: true,
                callTitle: mgPhoneIntentTitle(character),
                callLine: text || '지금 통화할 수 있어?'
            };
        });
    }

    const mgBaseBuildMessagesCallIntentFix = buildMessages;
    buildMessages = async function(character, options = {}) {
        const messages = await mgBaseBuildMessagesCallIntentFix(character, options);
        if (mgCharacterPhoneInvitesAllowed() && messages?.[0]) {
            messages[0].content = `${contentText(messages[0].content)}\n\nPhone call intent rule:\n- If the character says they will call now, start a call now, asks the user to pick up, or moves from text to phone, output a phone call invite object instead of a normal text bubble.\n- Use exactly this message item shape when calling: {\"content\":\"\",\"callInvite\":true,\"callTitle\":\"${character.name} phone call\",\"callLine\":\"short in-character line shown on the incoming call card\"}.\n- Do not write only phrases like \"I'll call now\" as plain text. That must become callInvite:true.`;
        }
        return messages;
    };

    const mgBaseNormalizeReplyMessagesCallIntentFix = normalizeReplyMessages;
    normalizeReplyMessages = function(character, payload) {
        return mgUpgradePhoneIntentMessages(character, mgBaseNormalizeReplyMessagesCallIntentFix(character, payload));
    };

    const mgBaseDeliverCharacterMessagesCallIntentFix = deliverCharacterMessages;
    deliverCharacterMessages = async function(character, roomId, messages, jobId = replyJobs[roomId], sourceMode = 'reply') {
        return mgBaseDeliverCharacterMessagesCallIntentFix(character, roomId, mgUpgradePhoneIntentMessages(character, messages), jobId, sourceMode);
    };
    // ---------------------------------------------------------------------

    // --- FINAL SPONTANEOUS PROACTIVE PHONE CALLS ---
    const MG_SPONTANEOUS_PHONE_COOLDOWN_MS = 35 * 60000;

    function mgSpontaneousPhoneChance(character, roomId, sourceMode) {
        if (sourceMode !== 'proactive') return 0;
        const style = String(character?.proactiveStyle || 'auto');
        const initiative = Math.max(0, Math.min(100, Number(character?.initiative) || 0));
        const unanswered = typeof unansweredProactiveCount === 'function' ? unansweredProactiveCount(roomId) : 0;
        let chance = 5 + initiative * 0.08;
        if (style === 'reserved') chance *= 0.35;
        else if (style === 'steady') chance *= 0.65;
        else if (style === 'attached') chance *= 1.45;
        else if (style === 'obsessive') chance *= 1.9;
        if (unanswered > 0 && style !== 'obsessive') chance *= Math.max(0.25, 0.85 - unanswered * 0.16);
        if (unanswered > 0 && style === 'obsessive') chance *= Math.min(1.55, 1 + unanswered * 0.12);
        return Math.max(1, Math.min(24, chance));
    }

    function mgMayUseSpontaneousPhone(character, roomId, sourceMode, messages) {
        if (!mgCharacterPhoneInvitesAllowed()) return false;
        if (sourceMode !== 'proactive') return false;
        const room = mgPhoneRoom(roomId);
        if (!room || room.type === 'group') return false;
        const list = Array.isArray(messages) ? messages : [];
        if (!list.length || list.some(item => item?.callInvite || item?.phoneCall || item?.call)) return false;
        if (list.some(item => item?.sticker || item?.imagePrompt || item?.giftType || item?.mediaType)) return false;
        const now = Date.now();
        if (now - Number(character?.lastPhoneInviteAt || 0) < MG_SPONTANEOUS_PHONE_COOLDOWN_MS) return false;
        return Math.random() * 100 < mgSpontaneousPhoneChance(character, roomId, sourceMode);
    }

    function mgMakeSpontaneousPhoneInvite(character, messages) {
        const first = (Array.isArray(messages) ? messages : []).find(item => mgPhoneVisibleText(item?.content || item?.text || item?.body || '')) || {};
        const line = mgPhoneVisibleText(first.content || first.text || first.body || '지금 잠깐 통화할 수 있어?');
        character.lastPhoneInviteAt = Date.now();
        return [{
            ...first,
            content: '',
            callInvite: true,
            callTitle: mgPhoneIntentTitle(character),
            callLine: line
        }];
    }

    const mgBaseBuildMessagesSpontaneousPhone = buildMessages;
    buildMessages = async function(character, options = {}) {
        const messages = await mgBaseBuildMessagesSpontaneousPhone(character, options);
        if (mgCharacterPhoneInvitesAllowed() && options.mode === 'proactive' && messages?.[0]) {
            messages[0].content = `${contentText(messages[0].content)}\n\nSpontaneous phone call option:\n- This is a proactive contact. The character may choose to call first instead of texting, even without saying the word call.\n- Use callInvite:true when a sudden incoming call would feel more alive, urgent, lonely, intimate, teasing, worried, or in-character than a normal text.\n- Do not rely on fixed keywords. Decide from mood, relationship, silence, time of day, and personality.\n- Keep it rare. If texting is more natural, send normal messages.`;
        }
        return messages;
    };

    const mgBaseDeliverCharacterMessagesSpontaneousPhone = deliverCharacterMessages;
    deliverCharacterMessages = async function(character, roomId, messages, jobId = replyJobs[roomId], sourceMode = 'reply') {
        const finalMessages = mgMayUseSpontaneousPhone(character, roomId, sourceMode, messages)
            ? mgMakeSpontaneousPhoneInvite(character, messages)
            : messages;
        return mgBaseDeliverCharacterMessagesSpontaneousPhone(character, roomId, finalMessages, jobId, sourceMode);
    };
    // ---------------------------------------------------------------------

    // --- FINAL PHONE CALL BROKEN JSON DISPLAY FIX ---
    function mgPhoneDecodeJsonishText(value) {
        let text = String(value || '')
            .replace(/\\n/g, '\n')
            .replace(/\\"/g, '"')
            .replace(/\\\\/g, '\\')
            .trim();
        text = text.replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/i, '').trim();
        text = text
            .replace(/^\s*[\[{]\s*/, '')
            .replace(/\s*[\]}]\s*$/g, '')
            .replace(/^\s*["']?(?:lines?|characterLines|dialogue|content|text)["']?\s*:\s*/i, '')
            .replace(/,\s*["']?(?:choices|options)["']?\s*:\s*\[[\s\S]*$/i, '')
            .replace(/^\s*\[\s*/, '')
            .replace(/\s*\]\s*$/g, '')
            .replace(/^\s*[-*]\s*/, '')
            .trim();
        text = text
            .replace(/^\s*["']+/, '')
            .replace(/["']+\s*,?\s*$/g, '')
            .replace(/[}\]]+\s*$/g, '')
            .trim();
        return mgPhoneVisibleText(text);
    }

    function mgPhoneJsonStringValue(value) {
        const raw = String(value || '').trim();
        if (!raw) return '';
        try { return JSON.parse(`"${raw.replace(/^["']|["']$/g, '').replace(/\\/g, '\\\\').replace(/"/g, '\\"')}"`); }
        catch (_) { return raw; }
    }

    function mgPhoneExtractArrayField(raw, names) {
        const source = String(raw || '');
        const key = names.join('|');
        const match = source.match(new RegExp(`["']?(?:${key})["']?\\s*:\\s*\\[([\\s\\S]*?)\\]`, 'i'));
        if (!match) return [];
        const body = match[1] || '';
        const quoted = [...body.matchAll(/"((?:\\.|[^"\\])*)"|'((?:\\.|[^'\\])*)'/g)]
            .map(item => mgPhoneDecodeJsonishText(mgPhoneJsonStringValue(item[1] || item[2] || '')))
            .filter(Boolean);
        if (quoted.length) return quoted.slice(0, 4);
        return body.split(/\s*,\s*/).map(mgPhoneDecodeJsonishText).filter(Boolean).slice(0, 4);
    }

    function mgPhoneExtractScalarField(raw, names) {
        const source = String(raw || '');
        const key = names.join('|');
        const match = source.match(new RegExp(`["']?(?:${key})["']?\\s*:\\s*([\\s\\S]*?)(?:,\\s*["']?(?:choices|options|lines|characterLines|dialogue)["']?\\s*:|[}\\]]\\s*$|$)`, 'i'));
        if (!match) return '';
        return mgPhoneDecodeJsonishText(match[1] || '');
    }

    function mgPhoneBrokenJsonFallback(raw, character) {
        let lines = mgPhoneExtractArrayField(raw, ['lines', 'characterLines', 'dialogue']);
        if (!lines.length) {
            const scalar = mgPhoneExtractScalarField(raw, ['line', 'content', 'text']);
            lines = scalar ? scalar.split(/\n+/).map(mgPhoneDecodeJsonishText).filter(Boolean) : [];
        }
        if (!lines.length) {
            lines = String(raw || '')
                .split(/\n+/)
                .map(mgPhoneDecodeJsonishText)
                .filter(line => line && !/^(?:choices|options)\s*:/i.test(line) && !/^["']?(?:lines?|characterLines|dialogue)["']?\s*:\s*\[?\s*$/i.test(line))
                .slice(0, 4);
        }
        lines = lines
            .map(mgPhoneDecodeJsonishText)
            .filter(line => line && !/^[{}\[\],"]+$/.test(line) && !/["']?(?:choices|options)["']?\s*:/.test(line))
            .slice(0, 4);
        const choices = mgPhoneExtractArrayField(raw, ['choices', 'options'])
            .map(mgPhoneDecodeJsonishText)
            .filter(Boolean)
            .slice(0, 3);
        return {
            line: (lines.length ? lines : [`${character?.name || '상대'}가 잠깐 숨을 고른다.`]).join('\n'),
            choices: choices.length >= 2 ? choices : ['응, 듣고 있어.', '그게 무슨 뜻이야?', '잠깐만, 계속 말해줘.']
        };
    }

    const mgBaseParsePhoneTurnBrokenJsonFix = mgParsePhoneTurn;
    mgParsePhoneTurn = function(payload, character) {
        const raw = mgPhonePayloadRawText(payload);
        let parsed = mgTryParsePhoneJson(raw);
        if (parsed?.messages && Array.isArray(parsed.messages)) {
            parsed = mgTryParsePhoneJson(parsed.messages.map(item => item.content || item.text || '').filter(Boolean).join('\n')) || parsed.messages[0] || parsed;
        }
        const turn = parsed ? mgPhoneTurnFromParsedLonger(parsed, character) : mgPhoneBrokenJsonFallback(raw, character);
        if (/[{}\[\]]|["']?(?:lines?|choices|options)["']?\s*:/.test(turn.line || '')) return mgPhoneBrokenJsonFallback(raw || turn.line, character);
        return {
            line: mgPhoneSequentialLines(turn.line).map(mgPhoneDecodeJsonishText).filter(Boolean).join('\n') || mgBaseParsePhoneTurnBrokenJsonFix(payload, character).line,
            choices: (turn.choices || []).map(mgPhoneDecodeJsonishText).filter(Boolean).slice(0, 3)
        };
    };

    const mgBasePhoneSequentialLinesBrokenJsonFix = mgPhoneSequentialLines;
    mgPhoneSequentialLines = function(value) {
        const lines = mgBasePhoneSequentialLinesBrokenJsonFix(value)
            .map(mgPhoneDecodeJsonishText)
            .filter(line => line && !/^[{}\[\],"]+$/.test(line) && !/["']?(?:lines?|choices|options)["']?\s*:/.test(line))
            .slice(0, 4);
        return lines.length ? lines : ['...'];
    };
    // ---------------------------------------------------------------------

    // --- FINAL PHONE MARKER / AVATAR GAP FIX ---
    const MG_PHONE_MARKER_PATTERN = /(?:\s*(?:\[\[\s*PHONE_CALL\s*(?:\]\])?|\[\s*PHONE_CALL\s*(?:\])?|\(\s*(?:PHONE_CALL|phone\s*call|call|전화|통화|電話|通話)\s*\)?|<\s*PHONE_CALL\s*>?|<\s*phone_call\s*>?|\{\{\s*PHONE_CALL\s*(?:\}\})?|\{\{\s*phone_call\s*(?:\}\})?)\s*)+/ig;

    function mgTextHasPhoneMarker(text) {
        MG_PHONE_MARKER_PATTERN.lastIndex = 0;
        return MG_PHONE_MARKER_PATTERN.test(String(text || ''));
    }

    function mgStripPhoneMarker(text) {
        MG_PHONE_MARKER_PATTERN.lastIndex = 0;
        return mgPhoneVisibleText(String(text || '').replace(MG_PHONE_MARKER_PATTERN, ' '));
    }

    mgLooksLikePhoneCallIntentText = function(text) {
        return mgTextHasPhoneMarker(text);
    };

    const mgBaseBuildMessagesPhoneMarker = buildMessages;
    buildMessages = async function(character, options = {}) {
        const messages = await mgBaseBuildMessagesPhoneMarker(character, options);
        if (mgCharacterPhoneInvitesAllowed() && messages?.[0]) {
            messages[0].content = `${contentText(messages[0].content)}\n\nPhone marker rule:\n- If ${character.name} naturally decides to place a phone call after a chat bubble, append the exact hidden marker [[PHONE_CALL]] at the end of that bubble.\n- Example visible content you may output in JSON: "Okay, I'll call you now. [[PHONE_CALL]]"\n- The app will remove [[PHONE_CALL]] from the bubble and add an incoming phone-call card immediately after it.\n- Do not use the marker unless the character is truly calling now. Do not explain the marker.`;
        }
        return messages;
    };

    function mgPhoneMarkerAvatarHtml(character) {
        if (typeof mgProfileAvatarButtonHtml === 'function') return mgProfileAvatarButtonHtml(character, 'small');
        return avatarHtml(character, 'small');
    }

    async function mgInsertPhoneMarkerCall(character, roomId, line, sourceMode = 'reply') {
        if (!mgCharacterPhoneInvitesAllowed()) return;
        state.messages[roomId] = Array.isArray(state.messages[roomId]) ? state.messages[roomId] : [];
        const title = mgPhoneIntentTitle(character);
        state.messages[roomId].push({
            id: makeId(),
            role: 'character',
            characterId: character.id,
            content: '',
            createdAt: Date.now(),
            mediaType: 'phone-call',
            mediaName: title,
            callTitle: title,
            callLine: mgPhoneVisibleText(mgStripPhoneMarker(line || ''), '지금 통화할 수 있어?'),
            sourceMode
        });
        const message = state.messages[roomId][state.messages[roomId].length - 1];
        logDebug('phone-call-card-created', `${character.name} phone call card created`, { roomId, sourceMode, line: message?.callLine || '' });
        noteIncomingMessage(roomId);
        await saveState();
        renderIncomingChange(roomId);
        render();
        if (roomId === selectedRoomId && activeTab === 'chat' && !mgPhoneCall?.open) {
            setTimeout(() => mgStartPhoneCall(roomId, 'character').catch(error => logDebug('phone-call-auto-open-error', error.message, { roomId })), 250);
        }
    }

    function mgPhoneMarkerParts(character, messages) {
        const parts = [];
        for (const item of Array.isArray(messages) ? messages : []) {
            const content = item?.content || item?.text || item?.body || '';
            if (!item || item.callInvite || item.phoneCall || item.call || !mgTextHasPhoneMarker(content)) {
                parts.push(item);
                continue;
            }
            const clean = mgStripPhoneMarker(content);
            if (clean || item.sticker || item.imagePrompt || item.giftType) parts.push({ ...item, content: clean });
            parts.push({ __phoneMarkerCall: true, callLine: clean || `${character?.name || '상대'}에게서 전화가 왔습니다.` });
        }
        return parts;
    }

    const mgBaseDeliverCharacterMessagesPhoneMarker = deliverCharacterMessages;
    deliverCharacterMessages = async function(character, roomId, messages, jobId = replyJobs[roomId], sourceMode = 'reply') {
        const markerParts = mgPhoneMarkerParts(character, messages);
        if (!markerParts.some(item => item?.__phoneMarkerCall)) {
            const stripped = mgCharacterPhoneInvitesAllowed() ? messages : (Array.isArray(messages) ? messages.map(item => item?.content ? { ...item, content: mgStripPhoneMarker(item.content) } : item) : messages);
            return mgBaseDeliverCharacterMessagesPhoneMarker(character, roomId, stripped, jobId, sourceMode);
        }
        let batch = [];
        for (const part of markerParts) {
            if (part?.__phoneMarkerCall) {
                if (batch.length) {
                    await mgBaseDeliverCharacterMessagesPhoneMarker(character, roomId, batch, jobId, sourceMode);
                    batch = [];
                }
                await mgInsertPhoneMarkerCall(character, roomId, part.callLine, sourceMode);
            } else {
                batch.push(part);
            }
        }
        if (batch.length) return mgBaseDeliverCharacterMessagesPhoneMarker(character, roomId, batch, jobId, sourceMode);
    };

    const mgBaseMessageHtmlPhoneMarkerAvatarFix = messageHtml;
    messageHtml = function(message, index = 0, messages = currentMessages()) {
        const hasPhoneMarker = message?.role === 'character' && mgTextHasPhoneMarker(message.content || '');
        const cleanMessage = hasPhoneMarker ? { ...message, content: mgStripPhoneMarker(message.content || '') } : message;
        let html = mgBaseMessageHtmlPhoneMarkerAvatarFix(cleanMessage, index, messages);
        if (message?.role !== 'character' || activeTab !== 'chat') return html;
        const character = getCharacter(message.characterId) || currentCharacter();
        const showIdentity = shouldShowCharacterIdentity(message, index, messages);
        if (hasPhoneMarker) {
            const next = messages[index + 1];
            const alreadyHasCard = next?.mediaType === 'phone-call' && next.characterId === message.characterId;
            if (!alreadyHasCard) {
                const cardMessage = {
                    ...message,
                    content: '',
                    mediaType: 'phone-call',
                    mediaName: mgPhoneIntentTitle(character),
                    callTitle: mgPhoneIntentTitle(character),
                    callLine: mgStripPhoneMarker(message.content || '') || '지금 통화할 수 있어?'
                };
                const callCard = `<div class="mg-message continued"><div class="mg-avatar-spacer"></div><div><div class="mg-bubble media-only">${mgPhoneCallCardHtml(cardMessage, character)}</div></div></div>`;
                html = `${html}${callCard}`;
            }
        }
        if (!character || !showIdentity) return html;
        const avatar = mgPhoneMarkerAvatarHtml(character);
        if (/\bmg-avatar-spacer\b/.test(html)) return String(html).replace(/<div class="mg-avatar-spacer"><\/div>/, avatar);
        if (!/\bmg-avatar\b|\bmg-avatar-button\b/.test(html)) {
            return String(html).replace(/(<div\b(?=[^>]*\bmg-message\b)(?![^>]*\buser\b)(?![^>]*\bsystem\b)[^>]*>)/, `$1${avatar}`);
        }
        return html;
    };

    function mgFixVisibleCharacterAvatarGaps() {
        if (activeTab !== 'chat') return;
        const messages = currentMessages() || [];
        document.querySelectorAll('.mg-messages .mg-message:not(.user):not(.system)').forEach(row => {
            const message = mgMessageByDomRow(row);
            if (!message || message.role !== 'character') return;
            const index = messages.findIndex(item => String(item.id || '') === String(message.id || ''));
            if (index < 0 || !shouldShowCharacterIdentity(message, index, messages)) return;
            const character = getCharacter(message.characterId) || currentCharacter();
            if (!character) return;
            const avatar = mgPhoneMarkerAvatarHtml(character);
            const spacer = row.querySelector(':scope > .mg-avatar-spacer');
            if (spacer) {
                spacer.outerHTML = avatar;
                const button = row.querySelector(':scope > .mg-avatar-button');
                if (button) mgBindDomAction(button);
            } else if (!row.querySelector(':scope > .mg-avatar, :scope > .mg-avatar-button')) {
                row.insertAdjacentHTML('afterbegin', avatar);
                const button = row.querySelector(':scope > .mg-avatar-button');
                if (button) mgBindDomAction(button);
            }
        });
    }

    const mgBaseBindEventsPhoneMarkerAvatarFix = bindEvents;
    bindEvents = function() {
        mgBaseBindEventsPhoneMarkerAvatarFix();
        mgFixVisibleCharacterAvatarGaps();
    };

    function mgRepairStoredPhoneMarkers() {
        for (const [roomId, list] of Object.entries(state.messages || {})) {
            if (!Array.isArray(list)) continue;
            for (let index = 0; index < list.length; index += 1) {
                const message = list[index];
                if (!message || message.role !== 'character' || !message.content || !mgTextHasPhoneMarker(message.content)) continue;
                const character = getCharacter(message.characterId) || currentCharacter();
                const clean = mgStripPhoneMarker(message.content);
                message.content = clean;
                const next = list[index + 1];
                if (next?.mediaType === 'phone-call' && next.characterId === message.characterId) continue;
                const title = mgPhoneIntentTitle(character);
                list.splice(index + 1, 0, {
                    id: makeId(),
                    role: 'character',
                    characterId: message.characterId,
                    content: '',
                    createdAt: (Number(message.createdAt) || Date.now()) + 1,
                    mediaType: 'phone-call',
                    mediaName: title,
                    callTitle: title,
                    callLine: clean || '지금 통화할 수 있어?',
                    sourceMode: message.sourceMode || 'reply'
                });
                index += 1;
            }
            state.messages[roomId] = list.filter(item => item?.content || item?.mediaType || item?.sticker || item?.imagePrompt || item?.giftType || item?.role === 'system');
        }
    }

    // --- FINAL EXPLICIT USER PHONE REQUEST HANDOFF ---
    function mgUserAskedForPhoneCall(text) {
        const value = String(text || '').replace(/\s+/g, ' ').trim();
        if (!value) return false;
        if (/(바로\s*)?(걸어봐|걸어줘|걸어|받을게|받아볼게|연결해|콜해|콜\s*해|call\s*(me|now)|ring\s*me)/i.test(value)) return true;
        return /(전화|통화|보이스톡|voice\s*call|phone\s*call|call\s+me|call\s+you|ring\s+me|電話|通話|かけて|掛けて|かけろ|掛けろ)/i.test(value)
            && /(걸|해|하자|보내|받|연결|바로|지금|줘|해봐|걸어봐|걸어|콜|call|ring|かけ|掛け|出て|出る)/i.test(value);
    }

    function mgPhoneRequestDeclined(text) {
        return /(안\s*(돼|해|걸|받)|못\s*(해|걸|받)|나중|다음에|싫|거절|끊|무리|바빠|잠깐만|기다|cannot|can't|wont|won't|later|not now|busy|no\b|don't|do not|無理|あとで|忙しい|待って)/i.test(String(text || ''));
    }

    function mgPhoneRequestSoundsAccepted(text) {
        const value = String(text || '').replace(/\s+/g, ' ').trim();
        if (!value || mgPhoneRequestDeclined(value)) return false;
        return /(알았|좋아|응|그래|바로|지금|받아|걸|목소리|전화|통화|보이스|call|voice|pick up|answer|電話|通話|出て|かける|掛ける)/i.test(value);
    }

    const mgBaseBuildMessagesExplicitPhoneRequest = buildMessages;
    buildMessages = async function(character, options = {}) {
        const messages = await mgBaseBuildMessagesExplicitPhoneRequest(character, options);
        if (mgCharacterPhoneInvitesAllowed() && messages?.[0] && mgUserAskedForPhoneCall(options.userText || '')) {
            messages[0].content = `${contentText(messages[0].content)}\n\nExplicit user phone request:\n- The latest user message directly asks for a phone call.\n- If ${character.name} agrees, teases while agreeing, tells the user to pick up, says they will call now, or otherwise continues toward a call, you MUST append [[PHONE_CALL]] to that same visible chat bubble.\n- Only omit [[PHONE_CALL]] if ${character.name} clearly refuses, postpones, or cannot call.\n- Example: \"Fine, pick up right away. [[PHONE_CALL]]\"`;
        }
        return messages;
    };

    function mgAddPhoneMarkerForExplicitRequest(character, payload, messages) {
        if (!mgCharacterPhoneInvitesAllowed()) return messages;
        const userText = payload?.userText || payload?.latestUserText || '';
        if (!mgUserAskedForPhoneCall(userText)) return messages;
        const list = Array.isArray(messages) ? messages : [];
        if (!list.length || list.some(item => item?.callInvite || item?.phoneCall || item?.call || mgTextHasPhoneMarker(item?.content || item?.text || item?.body || ''))) return list;
        const targetIndex = list.findIndex(item => mgPhoneRequestSoundsAccepted(item?.content || item?.text || item?.body || ''));
        if (targetIndex < 0) return list;
        return list.map((item, index) => index === targetIndex
            ? { ...item, content: `${mgPhoneVisibleText(item.content || item.text || item.body || '')} [[PHONE_CALL]]` }
            : item
        );
    }

    const mgBaseNormalizeReplyMessagesExplicitPhoneRequest = normalizeReplyMessages;
    normalizeReplyMessages = function(character, payload) {
        const messages = mgBaseNormalizeReplyMessagesExplicitPhoneRequest(character, payload);
        return mgAddPhoneMarkerForExplicitRequest(character, payload, messages);
    };

    // --- FINAL PHONE MARKER DELIVERY NORMALIZATION ---
    function mgExpandPhoneMarkersToCallInvites(character, messages) {
        const expanded = [];
        for (const item of Array.isArray(messages) ? messages : []) {
            if (!item || item.callInvite || item.phoneCall || item.call) {
                expanded.push(item);
                continue;
            }
            const text = item.content || item.text || item.body || '';
            if (!mgTextHasPhoneMarker(text)) {
                expanded.push(item);
                continue;
            }
            const clean = mgStripPhoneMarker(text);
            if (clean || item.sticker || item.imagePrompt || item.giftType) expanded.push({ ...item, content: clean });
            expanded.push({
                content: '',
                callInvite: true,
                callTitle: mgPhoneIntentTitle(character),
                callLine: clean || '지금 통화할 수 있어?'
            });
        }
        return expanded;
    }

    const mgBaseDeliverCharacterMessagesPhoneMarkerNormalized = deliverCharacterMessages;
    deliverCharacterMessages = async function(character, roomId, messages, jobId = replyJobs[roomId], sourceMode = 'reply') {
        const expanded = mgCharacterPhoneInvitesAllowed()
            ? mgExpandPhoneMarkersToCallInvites(character, messages)
            : (Array.isArray(messages) ? messages.map(item => item?.content ? { ...item, content: mgStripPhoneMarker(item.content) } : item) : messages);
        return mgBaseDeliverCharacterMessagesPhoneMarkerNormalized(character, roomId, expanded, jobId, sourceMode);
    };

    // --- FINAL DIRECT PHONE CALL CARD DELIVERY ---
    function mgPhoneCallAllowedForDelivery(sourceMode = 'reply') {
        return sourceMode !== 'proactive' || mgCharacterPhoneInvitesAllowed();
    }

    function mgDirectPhoneCallItem(character, item = {}) {
        const call = item.call && typeof item.call === 'object' ? item.call : {};
        const rawText = item.content || item.text || item.body || '';
        const clean = mgStripPhoneMarker(rawText);
        if (item.callLine) item.callLine = mgStripPhoneMarker(item.callLine);
        if (item.phoneLine) item.phoneLine = mgStripPhoneMarker(item.phoneLine);
        if (call.line) call.line = mgStripPhoneMarker(call.line);
        if (item.callInvite || item.phoneCall || item.call || item.callTitle || item.callLine) {
            return {
                title: mgPhoneVisibleText(item.callTitle || call.title || item.phoneTitle || mgPhoneIntentTitle(character)),
                line: mgPhoneVisibleText(item.callLine || call.line || item.phoneLine || clean || rawText || '지금 통화할 수 있어?')
            };
        }
        if (mgTextHasPhoneMarker(rawText)) {
            return {
                title: mgPhoneIntentTitle(character),
                line: mgPhoneVisibleText(clean || '지금 통화할 수 있어?')
            };
        }
        return null;
    }

    async function mgPushDirectPhoneCallMessage(character, roomId, phone, sourceMode = 'reply') {
        phone = { ...phone, line: mgPhoneVisibleText(mgStripPhoneMarker(phone?.line || ''), '지금 통화할 수 있어?') };
        state.messages[roomId] = Array.isArray(state.messages[roomId]) ? state.messages[roomId] : [];
        state.messages[roomId].push({
            id: makeId(),
            role: 'character',
            characterId: character.id,
            content: '',
            createdAt: Date.now(),
            mediaType: 'phone-call',
            mediaName: phone.title || mgPhoneIntentTitle(character),
            callTitle: phone.title || mgPhoneIntentTitle(character),
            callLine: phone.line || '지금 통화할 수 있어?',
            sourceMode
        });
        noteIncomingMessage(roomId);
        await saveState();
        renderIncomingChange(roomId);
        if (roomId === selectedRoomId && (activeTab === 'chat' || activeTab === 'randomchat') && !mgPhoneCall?.open) {
            setTimeout(() => mgStartPhoneCall(roomId, 'character').catch(error => logDebug('phone-call-auto-open-error', error.message, { roomId })), 250);
        }
    }

    const mgBaseDeliverCharacterMessagesDirectPhoneCard = deliverCharacterMessages;
    deliverCharacterMessages = async function(character, roomId, messages, jobId = replyJobs[roomId], sourceMode = 'reply') {
        const list = Array.isArray(messages) ? messages : [];
        if (!list.length) return mgBaseDeliverCharacterMessagesDirectPhoneCard(character, roomId, list, jobId, sourceMode);
        const allowPhone = mgPhoneCallAllowedForDelivery(sourceMode);
        let batch = [];
        for (const item of list) {
            const phone = allowPhone ? mgDirectPhoneCallItem(character, item) : null;
            if (!phone) {
                const content = item?.content || item?.text || item?.body || '';
                batch.push(!allowPhone && mgTextHasPhoneMarker(content) ? { ...item, content: mgStripPhoneMarker(content) } : item);
                continue;
            }
            const clean = mgStripPhoneMarker(item.content || item.text || item.body || '');
            const normalItem = {
                ...item,
                content: clean,
                callInvite: false,
                phoneCall: false,
                call: null,
                callTitle: '',
                callLine: '',
                phoneTitle: '',
                phoneLine: ''
            };
            if (clean || item.sticker || item.imagePrompt || item.giftType) batch.push(normalItem);
            if (batch.length) {
                await mgBaseDeliverCharacterMessagesDirectPhoneCard(character, roomId, batch, jobId, sourceMode);
                batch = [];
            }
            if (replyJobs[roomId] !== jobId) return;
            await mgPushDirectPhoneCallMessage(character, roomId, phone, sourceMode);
        }
        if (batch.length) return mgBaseDeliverCharacterMessagesDirectPhoneCard(character, roomId, batch, jobId, sourceMode);
    };

    // --- FINAL PHONE MARKER HARD BYPASS DELIVERY ---
    function mgPhoneDeliveryCurrent(roomId, jobId) {
        return !jobId || replyJobs[roomId] === jobId;
    }

    async function mgPushDirectCharacterTextMessage(character, roomId, text, sourceMode = 'reply') {
        const content = mgPhoneVisibleText(text);
        if (!content) return;
        state.messages[roomId] = Array.isArray(state.messages[roomId]) ? state.messages[roomId] : [];
        state.messages[roomId].push({
            id: makeId(),
            role: 'character',
            characterId: character.id,
            content,
            createdAt: Date.now(),
            sourceMode
        });
        noteIncomingMessage(roomId);
        await saveState();
        renderIncomingChange(roomId);
    }

    function mgHasDirectPhoneDelivery(messages, character, sourceMode = 'reply') {
        if (!mgPhoneCallAllowedForDelivery(sourceMode)) return false;
        return (Array.isArray(messages) ? messages : []).some(item => mgDirectPhoneCallItem(character, item));
    }

    const mgBaseDeliverCharacterMessagesPhoneHardBypass = deliverCharacterMessages;
    deliverCharacterMessages = async function(character, roomId, messages, jobId = replyJobs[roomId], sourceMode = 'reply') {
        const list = Array.isArray(messages) ? messages : [];
        if (!mgHasDirectPhoneDelivery(list, character, sourceMode)) {
            return mgBaseDeliverCharacterMessagesPhoneHardBypass(character, roomId, messages, jobId, sourceMode);
        }
        const allowPhone = mgPhoneCallAllowedForDelivery(sourceMode);
        for (let index = 0; index < list.length; index += 1) {
            if (!mgPhoneDeliveryCurrent(roomId, jobId)) return;
            const item = list[index] || {};
            if (index > 0) {
                const gap = messageGapSeconds(character, item);
                await new Promise(resolve => scheduleRoomTimer(roomId, gap * 1000, resolve));
            }
            if (!mgPhoneDeliveryCurrent(roomId, jobId)) return;
            const phone = allowPhone ? mgDirectPhoneCallItem(character, item) : null;
            if (phone) {
                const clean = mgStripPhoneMarker(item.content || item.text || item.body || '') || mgPhoneVisibleText(mgStripPhoneMarker(phone.line || item.callLine || item.phoneLine || ''));
                await mgPushDirectCharacterTextMessage(character, roomId, clean, sourceMode);
                await mgPushDirectPhoneCallMessage(character, roomId, phone, sourceMode);
                continue;
            }
            if (item.content && !item.sticker && !item.imagePrompt && !item.giftType && !item.mediaType) {
                await mgPushDirectCharacterTextMessage(character, roomId, item.content, sourceMode);
            } else {
                await mgBaseDeliverCharacterMessagesPhoneHardBypass(character, roomId, [item], jobId, sourceMode);
            }
        }
    };

    const mgBaseMediaHtmlPhoneHardBypass = mediaHtml;
    mediaHtml = function(message, character) {
        if (message?.mediaType === 'phone-call') return mgPhoneCallCardHtml(message, character);
        return mgBaseMediaHtmlPhoneHardBypass(message, character);
    };

    const mgBaseIsMediaOnlyPhoneHardBypass = isMediaOnlyMessage;
    isMediaOnlyMessage = function(message) {
        if (message?.mediaType === 'phone-call') return true;
        return mgBaseIsMediaOnlyPhoneHardBypass(message);
    };
    // ---------------------------------------------------------------------

    // --- FINAL INCOMING PHONE CALL FLOW ---
    let mgIncomingPhoneCall = null;
    let mgIncomingPhoneTimer = 0;
    let mgAcceptingIncomingPhoneCall = false;

    function mgFindPhoneMessage(roomId, messageId = '') {
        const list = state.messages?.[roomId] || [];
        if (messageId) return list.find(item => String(item.id || '') === String(messageId)) || null;
        return [...list].reverse().find(item => item?.mediaType === 'phone-call' && !item.callStatus) || null;
    }

    function mgPhoneDuration(ms) {
        const total = Math.max(0, Math.floor(Number(ms) / 1000));
        const hours = Math.floor(total / 3600);
        const minutes = Math.floor((total % 3600) / 60);
        const seconds = total % 60;
        const pad = value => String(value).padStart(2, '0');
        return `${pad(hours)}시간 ${pad(minutes)}분 ${pad(seconds)}초`;
    }

    async function mgAppendPhoneLogMessage(roomId, character, text, status = '') {
        if (!roomId || !character || !text) return;
        state.messages[roomId] = Array.isArray(state.messages[roomId]) ? state.messages[roomId] : [];
        state.messages[roomId].push({
            id: makeId(),
            role: 'character',
            characterId: character.id,
            content: text,
            createdAt: Date.now(),
            phoneLog: status || true
        });
        noteIncomingMessage(roomId);
        await saveState();
        renderIncomingChange(roomId);
    }

    function mgClearIncomingPhoneTimer() {
        if (mgIncomingPhoneTimer) clearTimeout(mgIncomingPhoneTimer);
        mgIncomingPhoneTimer = 0;
    }

    function mgIncomingPhoneFromMessage(roomId, message = null) {
        const room = mgPhoneRoom(roomId);
        const character = mgPhoneCharacter(room);
        const callMessage = message || mgFindPhoneMessage(roomId);
        if (!room || !character || !callMessage) return null;
        return {
            roomId: room.id,
            characterId: character.id,
            messageId: callMessage.id || '',
            title: mgPhoneVisibleText(callMessage.callTitle || callMessage.mediaName, mgPhoneIntentTitle(character)),
            line: mgPhoneVisibleText(callMessage.callLine || callMessage.content || '', '지금 통화할 수 있어?'),
            createdAt: Date.now()
        };
    }

    function mgShowIncomingPhoneCall(roomId, message = null) {
        const incoming = mgIncomingPhoneFromMessage(roomId, message);
        if (!incoming) return false;
        if (mgIncomingPhoneCall?.messageId && mgIncomingPhoneCall.messageId === incoming.messageId) return true;
        mgClearIncomingPhoneTimer();
        mgIncomingPhoneCall = incoming;
        const callMessage = mgFindPhoneMessage(incoming.roomId, incoming.messageId);
        if (callMessage) callMessage.callStatus = 'ringing';
        mgIncomingPhoneTimer = setTimeout(() => {
            mgMissIncomingPhoneCall().catch(error => {
                try { logDebug('phone-missed-error', error.message, { roomId: incoming.roomId }); } catch (_) {}
            });
        }, 15000);
        render();
        return true;
    }

    async function mgRejectIncomingPhoneCall() {
        if (!mgIncomingPhoneCall) return;
        const incoming = mgIncomingPhoneCall;
        mgClearIncomingPhoneTimer();
        mgIncomingPhoneCall = null;
        const room = mgPhoneRoom(incoming.roomId);
        const character = mgPhoneCharacter(room);
        const callMessage = mgFindPhoneMessage(incoming.roomId, incoming.messageId);
        if (callMessage) {
            callMessage.callStatus = 'rejected';
            callMessage.callHandledAt = Date.now();
        }
        await mgAppendPhoneLogMessage(incoming.roomId, character, '통화 취소', 'rejected');
        render();
    }

    async function mgMissIncomingPhoneCall() {
        if (!mgIncomingPhoneCall) return;
        const incoming = mgIncomingPhoneCall;
        mgClearIncomingPhoneTimer();
        mgIncomingPhoneCall = null;
        const room = mgPhoneRoom(incoming.roomId);
        const character = mgPhoneCharacter(room);
        const callMessage = mgFindPhoneMessage(incoming.roomId, incoming.messageId);
        if (callMessage) {
            callMessage.callStatus = 'missed';
            callMessage.callHandledAt = Date.now();
        }
        await mgAppendPhoneLogMessage(incoming.roomId, character, '부재중 전화', 'missed');
        render();
    }

    async function mgAcceptIncomingPhoneCall() {
        if (!mgIncomingPhoneCall) return;
        const incoming = mgIncomingPhoneCall;
        mgClearIncomingPhoneTimer();
        mgIncomingPhoneCall = null;
        const callMessage = mgFindPhoneMessage(incoming.roomId, incoming.messageId);
        if (callMessage) {
            callMessage.callStatus = 'accepted';
            callMessage.callHandledAt = Date.now();
        }
        await saveState();
        mgAcceptingIncomingPhoneCall = true;
        try {
            await mgBaseStartPhoneCallIncomingFlow(incoming.roomId, 'character');
            if (mgPhoneCall?.open) {
                const connectedAt = Date.now();
                mgPhoneCall.acceptedAt = connectedAt;
                mgPhoneCall.connectedAt = connectedAt;
                mgPhoneCall.sourceMessageId = incoming.messageId;
                mgPhoneCall.incomingLine = incoming.line;
                mgPhoneCall.hidden = false;
            }
        } finally {
            mgAcceptingIncomingPhoneCall = false;
        }
    }

    function mgIncomingPhoneCallOverlayHtml() {
        if (!mgIncomingPhoneCall || mgPhoneCall?.open) return '';
        const room = mgPhoneRoom(mgIncomingPhoneCall.roomId);
        const character = mgPhoneCharacter(room);
        const avatar = mgPhoneAvatarData(character);
        const avatarHtmlValue = avatar ? `<img src="${escapeHtml(mediaDisplayUrl(avatar, `incoming-phone-avatar-${character?.id || ''}`))}" alt="">` : `<span>${escapeHtml(character?.avatarText || character?.name?.slice(0, 2) || '?')}</span>`;
        const bgStyle = avatar ? ` style="--mg-phone-bg:url('${escapeHtml(mediaDisplayUrl(avatar, `incoming-phone-bg-${character?.id || ''}`))}')"` : '';
        return `<div class="mg-phone-call-overlay mg-phone-incoming-overlay"${bgStyle}><div class="mg-phone-bg"></div><section class="mg-phone-stage mg-phone-incoming-stage">
            <div class="mg-phone-avatar">${avatarHtmlValue}</div>
            <div class="mg-phone-name"><strong>${escapeHtml(character?.name || mgIncomingPhoneCall.title || '상대')}</strong><span>전화 수신 중...</span></div>
            <div class="mg-phone-line mg-phone-incoming-line">${escapeHtml(mgIncomingPhoneCall.line || '전화가 왔습니다.')}</div>
            <div class="mg-phone-incoming-actions"><button class="mg-phone-round mg-phone-decline" type="button" title="거절" data-action="reject-incoming-phone-call">✕</button><button class="mg-phone-round mg-phone-accept" type="button" title="수신" data-action="accept-incoming-phone-call">✓</button></div>
        </section></div>`;
    }

    const mgBaseStartPhoneCallIncomingFlow = mgStartPhoneCall;
    mgStartPhoneCall = async function(roomId = selectedRoomId, initiator = 'user') {
        if (initiator === 'character' && !mgAcceptingIncomingPhoneCall) {
            if (mgShowIncomingPhoneCall(roomId)) return;
        }
        return mgBaseStartPhoneCallIncomingFlow(roomId, initiator);
    };

    const mgBasePhoneCallOverlayHtmlIncomingFlow = mgPhoneCallOverlayHtml;
    mgPhoneCallOverlayHtml = function() {
        if (mgIncomingPhoneCall && !mgPhoneCall?.open) return mgIncomingPhoneCallOverlayHtml();
        if (mgPhoneCall?.hidden) return '';
        let html = mgBasePhoneCallOverlayHtmlIncomingFlow();
        if (!html) return html;
        html = html.replace(/(<button\b(?=[^>]*\bmg-phone-close\b)[^>]*title=")[^"]*("[^>]*data-action=")end-phone-call("[^>]*>×<\/button>)/, '$1닫기$2close-phone-screen$3');
        return html;
    };

    const mgBaseEndPhoneCallWithReactionIncomingFlow = mgEndPhoneCallWithReaction;
    mgEndPhoneCallWithReaction = async function() {
        if (!mgPhoneCall?.open || mgPhoneCall.ending) return;
        const call = mgPhoneCall;
        if (!call.phoneLogRecorded) {
            call.phoneLogRecorded = true;
            const room = mgPhoneRoom(call.roomId);
            const character = mgPhoneCharacter(room);
            const startedAt = Number(call.acceptedAt || call.connectedAt || call.createdAt || Date.now());
            await mgAppendPhoneLogMessage(call.roomId, character, `통화 기록 ${mgPhoneDuration(Date.now() - startedAt)}`, 'ended');
        }
        return mgBaseEndPhoneCallWithReactionIncomingFlow();
    };

    const mgBaseMessageHtmlIncomingPhoneFlow = messageHtml;
    messageHtml = function(message, index = 0, messages = currentMessages()) {
        if (message?.mediaType === 'phone-call') return '';
        return mgBaseMessageHtmlIncomingPhoneFlow(message, index, messages);
    };

    const mgBaseMediaHtmlIncomingPhoneFlow = mediaHtml;
    mediaHtml = function(message, character) {
        if (message?.mediaType === 'phone-call') return '';
        return mgBaseMediaHtmlIncomingPhoneFlow(message, character);
    };

    const mgBaseIsMediaOnlyIncomingPhoneFlow = isMediaOnlyMessage;
    isMediaOnlyMessage = function(message) {
        if (message?.mediaType === 'phone-call') return false;
        return mgBaseIsMediaOnlyIncomingPhoneFlow(message);
    };

    const mgBaseHandleActionIncomingPhoneFlow = handleAction;
    handleAction = async function(action, element) {
        if (action === 'accept-incoming-phone-call') return mgAcceptIncomingPhoneCall();
        if (action === 'reject-incoming-phone-call') return mgRejectIncomingPhoneCall();
        if (action === 'close-phone-screen') { if (mgPhoneCall?.open) mgPhoneCall.hidden = true; render(); return; }
        if (action === 'start-phone-call' && mgPhoneCall?.open && mgPhoneCall.hidden) { mgPhoneCall.hidden = false; render(); return; }
        if (action === 'accept-phone-call') {
            const found = mgFindMessageByIdSafe(element?.dataset?.id || '');
            const message = found ? mgFindPhoneMessage(found.roomId, found.id) : null;
            if (message && mgShowIncomingPhoneCall(found.roomId, message)) return mgAcceptIncomingPhoneCall();
        }
        return mgBaseHandleActionIncomingPhoneFlow(action, element);
    };

    const mgBaseInjectStylesIncomingPhoneFlow = injectStyles;
    injectStyles = function() {
        mgBaseInjectStylesIncomingPhoneFlow();
        if (document.getElementById('mg-incoming-phone-flow-style')) return;
        const style = document.createElement('style');
        style.id = 'mg-incoming-phone-flow-style';
        style.textContent = `
            .mg-phone-incoming-stage{grid-template-rows:auto auto auto auto!important;gap:22px!important}.mg-phone-incoming-overlay .mg-phone-bg{filter:blur(20px) saturate(1.05) brightness(.72)!important}.mg-phone-incoming-line{text-align:center!important;min-height:auto!important;background:rgba(0,0,0,.22)!important;color:rgba(255,255,255,.84)!important;font-size:16px!important}.mg-phone-incoming-actions{display:flex!important;justify-content:center!important;align-items:center!important;gap:54px!important;margin-top:8px!important}.mg-phone-round{width:72px!important;height:72px!important;border-radius:50%!important;border:0!important;color:#fff!important;font-size:30px!important;font-weight:900!important;display:grid!important;place-items:center!important;box-shadow:0 18px 46px rgba(0,0,0,.34)!important}.mg-phone-decline{background:#ef4444!important}.mg-phone-accept{background:#22c55e!important}.mg-phone-call-overlay .mg-phone-close{top:12px!important;right:12px!important}
            @media(max-width:780px){.mg-phone-incoming-actions{gap:46px!important}.mg-phone-round{width:64px!important;height:64px!important;font-size:27px!important}.mg-phone-incoming-line{font-size:15px!important}.mg-phone-call-overlay .mg-phone-close{top:10px!important;right:10px!important}}
        `;
        document.head.appendChild(style);
    };

    // --- FINAL PHONE CALL PRECISION / LOG UI / MANUAL LINE FLOW ---
    const MG_STRICT_PHONE_MARKER_PATTERN = /\[\[\s*PHONE_CALL\s*\]\]/i;

    mgTextHasPhoneMarker = function(text) {
        return MG_STRICT_PHONE_MARKER_PATTERN.test(String(text || ''));
    };

    mgStripPhoneMarker = function(text) {
        return mgPhoneVisibleText(String(text || '').replace(/\[\[\s*PHONE_CALL\s*\]\]/ig, ' '));
    };

    mgLooksLikePhoneCallIntentText = function(text) {
        return mgTextHasPhoneMarker(text);
    };

    mgNormalizePhoneItem = function(item = {}) {
        const call = item.call && typeof item.call === 'object' ? item.call : {};
        const explicitInvite = item.callInvite === true || item.phoneCall === true || call.callInvite === true || call.phoneCall === true || mgTextHasPhoneMarker(item.content || item.text || item.body || '');
        if (!explicitInvite) return null;
        return {
            callInvite: true,
            callTitle: mgPhoneVisibleText(item.callTitle || call.title || item.phoneTitle, '전화'),
            callLine: mgPhoneVisibleText(mgStripPhoneMarker(item.callLine || call.line || item.phoneLine || item.content || item.text || item.body || ''), '지금 통화할 수 있어?')
        };
    };

    mgDirectPhoneCallItem = function(character, item = {}) {
        const call = item.call && typeof item.call === 'object' ? item.call : {};
        const rawText = item.content || item.text || item.body || '';
        const explicitInvite = item.callInvite === true || item.phoneCall === true || call.callInvite === true || call.phoneCall === true || mgTextHasPhoneMarker(rawText);
        if (!explicitInvite) return null;
        const clean = mgStripPhoneMarker(rawText);
        return {
            title: mgPhoneVisibleText(item.callTitle || call.title || item.phoneTitle || mgPhoneIntentTitle(character)),
            line: mgPhoneVisibleText(item.callLine || call.line || item.phoneLine || clean || rawText || '지금 통화할 수 있어?')
        };
    };

    const mgBaseMediaLabelNoPhoneLeak = mediaLabel;
    mediaLabel = function(message) {
        if (message?.mediaType === 'phone-call') return '';
        return mgBaseMediaLabelNoPhoneLeak(message);
    };

    function mgStripPhoneArtifacts(value) {
        return String(value || '')
            .replace(/\[\s*전화\s*[:：][^\]]+\]/g, '')
            .replace(/\[\s*통화\s*[:：][^\]]+\]/g, '')
            .replace(/^\s*(?:통화\s*취소|부재중\s*전화|통화\s*기록\s*\d{2}시간\s*\d{2}분\s*\d{2}초)\s*$/gmi, '')
            .replace(/\n{3,}/g, '\n\n')
            .trim();
    }

    function mgLooksLikePhoneArtifactOnly(value) {
        const text = String(value || '').trim();
        if (!text) return false;
        if (/^\[\s*(?:전화|통화)\s*[:：][^\]]+\]\s*$/i.test(text)) return true;
        if (/^(?:통화\s*취소|부재중\s*전화|통화\s*기록\s*\d{2}시간\s*\d{2}분\s*\d{2}초)\s*$/i.test(text)) return true;
        return false;
    }

    const mgBaseBuildSnsPostMessagesNoPhoneLeak = buildSnsPostMessages;
    buildSnsPostMessages = function(character, hintText, roomId = selectedRoomId, options = {}) {
        const messages = mgBaseBuildSnsPostMessagesNoPhoneLeak(character, hintText, roomId, options);
        for (const message of messages || []) {
            if (typeof message?.content === 'string') {
                message.content = mgStripPhoneArtifacts(message.content)
                    .replace(/^.*:\s*(?:통화\s*취소|부재중\s*전화|통화\s*기록\s*\d{2}시간\s*\d{2}분\s*\d{2}초)\s*$/gmi, '')
                    .replace(/^.*:\s*$/gm, '')
                    .replace(/\n{3,}/g, '\n\n')
                    .trim();
            }
        }
        if (messages?.[0]) messages[0].content = `${contentText(messages[0].content)}\n\nSNS phone-artifact rule:\n- Never turn phone-call UI labels, missed-call logs, canceled-call logs, or call-duration records into SNS post text, hashtags, comments, image prompts, or captions.\n- If the recent timeline only contains phone metadata, write from the surrounding emotional context instead.`;
        return messages;
    };

    const mgBaseSanitizeSnsPlatformNoPhoneLeak = sanitizeSnsPlatform;
    sanitizeSnsPlatform = function(item, post, character) {
        const cleaned = mgBaseSanitizeSnsPlatformNoPhoneLeak(item, post, character);
        const stripped = mgStripPhoneArtifacts(cleaned?.text || '');
        if (mgLooksLikePhoneArtifactOnly(cleaned?.text || '') || !stripped) {
            const fallback = typeof fallbackSnsPostText === 'function'
                ? fallbackSnsPostText(character || currentCharacter(), post?.sourceRoomId || selectedRoomId, post?.hint || state.config?.sns?.subject || '')
                : `${character?.name || '캐릭터'}의 오늘 기록.`;
            cleaned.text = cleanSnsVisibleText(fallback) || `${character?.name || '캐릭터'}의 오늘 기록.`;
            cleaned.hashtags = typeof ensureSnsHashtags === 'function' ? ensureSnsHashtags([], character || currentCharacter(), cleaned.text, post?.hint || '') : [];
        } else {
            cleaned.text = stripped;
            if (Array.isArray(cleaned.hashtags)) cleaned.hashtags = cleaned.hashtags.filter(tag => !/전화|통화|부재중|call|phone/i.test(String(tag || '')));
        }
        return cleaned;
    };

    const mgBaseSnsPostPlainTextNoPhoneLeak = snsPostPlainText;
    snsPostPlainText = function(post) {
        return mgStripPhoneArtifacts(mgBaseSnsPostPlainTextNoPhoneLeak(post));
    };

    function mgPhoneLogKind(message) {
        const status = String(message?.phoneLog || '').toLowerCase();
        const text = String(message?.content || '');
        if (status.includes('miss') || /부재중/.test(text)) return 'missed';
        if (status.includes('reject') || /취소|거절/.test(text)) return 'rejected';
        if (status.includes('end') || /통화\s*기록/.test(text)) return 'ended';
        return 'info';
    }

    function mgPhoneLogHtml(message) {
        const kind = mgPhoneLogKind(message);
        const label = kind === 'missed' ? '부재중 전화' : kind === 'rejected' ? '통화 취소' : kind === 'ended' ? '통화 기록' : '전화 기록';
        const detail = String(message?.content || label).replace(/^통화\s*기록\s*/i, '').trim();
        return `<div class="mg-message system mg-phone-log-row mg-phone-log-${escapeHtml(kind)}"><div class="mg-phone-log-bubble"><span class="mg-phone-log-icon">☎</span><strong>${escapeHtml(label)}</strong>${detail && detail !== label ? `<em>${escapeHtml(detail)}</em>` : ''}<small>${escapeHtml(formatTime(message.createdAt))}</small></div></div>`;
    }

    const mgBaseMessageHtmlPhoneLogPolish = messageHtml;
    messageHtml = function(message, index = 0, messages = currentMessages()) {
        if (message?.phoneLog) return mgPhoneLogHtml(message);
        return mgBaseMessageHtmlPhoneLogPolish(message, index, messages);
    };

    function mgPhoneTypeManualLine() {
        clearInterval(mgPhoneTypeTimer);
        clearTimeout(mgPhoneSequencePauseTimer);
        if (!mgPhoneCall?.open) return;
        const lines = Array.isArray(mgPhoneCall.manualLines) && mgPhoneCall.manualLines.length ? mgPhoneCall.manualLines : mgPhoneSequentialLines(mgPhoneCall.line || '');
        const lineIndex = Math.max(0, Math.min(Number(mgPhoneCall.manualLineIndex) || 0, lines.length - 1));
        const text = lines[lineIndex] || '';
        mgPhoneCall.displayLine = '';
        mgPhoneCall.typing = true;
        mgPhoneCall.awaitingNextLine = false;
        render();
        let index = 0;
        mgPhoneTypeTimer = setInterval(() => {
            if (!mgPhoneCall?.open) { clearInterval(mgPhoneTypeTimer); return; }
            index += 1;
            mgPhoneCall.displayLine = text.slice(0, index);
            const target = document.getElementById('mg-phone-line');
            if (target) target.textContent = mgPhoneCall.displayLine;
            if (index >= text.length) {
                clearInterval(mgPhoneTypeTimer);
                mgPhoneCall.typing = false;
                mgPhoneCall.awaitingNextLine = lineIndex < lines.length - 1;
                render();
            }
        }, 52);
    }

    mgStartPhoneTypewriter = function(line) {
        if (!mgPhoneCall?.open) return;
        const lines = mgPhoneSequentialLines(line);
        mgPhoneCall.manualLines = lines;
        mgPhoneCall.manualLineIndex = 0;
        mgPhoneCall.line = lines.join('\n');
        mgPhoneCall.awaitingNextLine = false;
        mgPhoneTypeManualLine();
    };

    const mgBasePhoneCallOverlayHtmlManualFlow = mgPhoneCallOverlayHtml;
    mgPhoneCallOverlayHtml = function() {
        let html = mgBasePhoneCallOverlayHtmlManualFlow();
        if (!html || !mgPhoneCall?.open || mgPhoneCall.hidden) return html;
        if (mgPhoneCall.awaitingNextLine) {
            html = html.replace(/<div class="mg-phone-choices">[\s\S]*?<\/div>\s*<button class="mg-btn mg-phone-hangup"/, '<div class="mg-phone-choices mg-phone-next-wrap"><button class="mg-btn mg-phone-next-line" type="button" data-action="phone-next-line">다음</button></div><button class="mg-btn mg-phone-hangup"');
        } else if (!mgPhoneCall.loading && !mgPhoneCall.typing) {
            html = html.replace(/(<div class="mg-phone-choices">[\s\S]*?<\/div>)(\s*<button class="mg-btn mg-phone-hangup")/, '$1<div class="mg-phone-custom-reply"><input class="mg-field" id="mg-phone-custom-reply" placeholder="직접 답하기"><button class="mg-btn primary" type="button" data-action="phone-custom-reply">전송</button></div>$2');
        }
        return html;
    };

    const mgBaseBuildMessagesPhonePrecision = buildMessages;
    buildMessages = async function(character, options = {}) {
        const messages = await mgBaseBuildMessagesPhonePrecision(character, options);
        if (messages?.[0]) {
            messages[0].content = `${contentText(messages[0].content)}\n\nStrict phone-call trigger rules:\n- Only create a new phone call when ${character?.name || 'the character'} is actively calling now or explicitly telling the user to pick up now.\n- References to a previous call, missed call, call record, call cancellation, phone-related SNS text, or sentences like \"전화해서 좋았어\" are NOT new call triggers.\n- For a real call, use exactly one of these: append [[PHONE_CALL]] to the visible chat line, or set callInvite:true. Do not set callTitle/callLine alone.`;
        }
        return messages;
    };

    const mgBaseHandleActionPhonePrecision = handleAction;
    handleAction = async function(action, element) {
        if (action === 'phone-next-line') {
            if (!mgPhoneCall?.open || !mgPhoneCall.awaitingNextLine) return;
            mgPhoneCall.manualLineIndex = (Number(mgPhoneCall.manualLineIndex) || 0) + 1;
            mgPhoneTypeManualLine();
            return;
        }
        if (action === 'phone-custom-reply') {
            if (!mgPhoneCall?.open || mgPhoneCall.loading || mgPhoneCall.typing || mgPhoneCall.awaitingNextLine) return;
            const input = document.getElementById('mg-phone-custom-reply');
            const text = String(input?.value || '').trim();
            if (!text) return;
            if (input) input.value = '';
            return mgGeneratePhoneTurn(text);
        }
        return mgBaseHandleActionPhonePrecision(action, element);
    };

    const mgBaseBindEventsPhonePrecision = bindEvents;
    bindEvents = function() {
        mgBaseBindEventsPhonePrecision();
        const input = document.getElementById('mg-phone-custom-reply');
        if (input && !input.dataset.phoneCustomBound) {
            input.dataset.phoneCustomBound = '1';
            input.addEventListener('keydown', event => {
                if (event.key === 'Enter' && !event.shiftKey) {
                    event.preventDefault();
                    document.querySelector('[data-action="phone-custom-reply"]')?.click();
                }
            });
        }
    };

    const mgBaseInjectStylesPhonePrecision = injectStyles;
    injectStyles = function() {
        mgBaseInjectStylesPhonePrecision();
        if (document.getElementById('mg-phone-precision-style')) return;
        const style = document.createElement('style');
        style.id = 'mg-phone-precision-style';
        style.textContent = `
            .mg-phone-log-row{justify-content:center!important;margin:10px 0!important}.mg-phone-log-row .mg-phone-log-bubble{display:inline-grid!important;grid-template-columns:auto auto auto!important;gap:6px 9px!important;align-items:center!important;max-width:min(86vw,420px)!important;border:1px solid var(--border2)!important;border-radius:999px!important;background:color-mix(in srgb,var(--surface2),var(--accent2) 18%)!important;color:var(--sub)!important;padding:8px 12px!important;box-shadow:0 8px 22px rgba(0,0,0,.08)!important}.mg-phone-log-icon{width:24px!important;height:24px!important;border-radius:50%!important;display:grid!important;place-items:center!important;background:var(--accent2)!important;color:var(--accent-ink)!important;font-size:13px!important}.mg-phone-log-bubble strong{font-size:12px!important;color:var(--text)!important}.mg-phone-log-bubble em{font-style:normal!important;font-size:12px!important;color:var(--muted)!important}.mg-phone-log-bubble small{grid-column:2 / -1!important;font-size:10px!important;color:var(--muted)!important}.mg-phone-log-missed .mg-phone-log-icon{background:#f5d3d6!important;color:#8d242b!important}.mg-phone-log-rejected .mg-phone-log-icon{background:#f7e1c6!important;color:#8a4a10!important}.mg-phone-log-ended .mg-phone-log-icon{background:var(--accent2)!important;color:var(--accent-ink)!important}
            .mg-phone-next-wrap{display:grid!important}.mg-phone-next-line{min-height:46px!important;background:rgba(255,255,255,.92)!important;color:#111!important;border-color:rgba(255,255,255,.8)!important;font-weight:900!important}.mg-phone-custom-reply{display:grid!important;grid-template-columns:minmax(0,1fr) auto!important;gap:8px!important;margin-top:8px!important}.mg-phone-custom-reply .mg-field{height:42px!important;background:rgba(255,255,255,.92)!important;color:#111!important;border-color:rgba(255,255,255,.6)!important}.mg-phone-custom-reply .mg-field::placeholder{color:rgba(0,0,0,.45)!important}.mg-phone-custom-reply .mg-btn{height:42px!important;min-width:64px!important}
            @media(max-width:780px){.mg-phone-log-row .mg-phone-log-bubble{border-radius:18px!important;grid-template-columns:auto minmax(0,auto)!important}.mg-phone-log-bubble em{grid-column:2 / -1!important}.mg-phone-custom-reply{grid-template-columns:1fr!important}.mg-phone-custom-reply .mg-btn{width:100%!important}}
        `;
        document.head.appendChild(style);
    };
    // ---------------------------------------------------------------------

    // --- FINAL PHONE UX / CONTEXT / SNS ARTIFACT FIX ---
    const MG_FINAL_PHONE_MARKER_PATTERN = /\[\[\s*PHONE_CALL\s*(?:\]\])?/ig;
    const MG_PHONE_DURATION_PATTERN = /(?:통화|전화)\s*기록\s*(?:\d{1,2}\s*시간\s*)?\d{1,2}\s*분\s*\d{1,2}\s*초/ig;
    const mgIncomingPhoneDelayTimers = new Map();

    mgTextHasPhoneMarker = function(text) {
        MG_FINAL_PHONE_MARKER_PATTERN.lastIndex = 0;
        return MG_FINAL_PHONE_MARKER_PATTERN.test(String(text || ''));
    };

    mgStripPhoneMarker = function(text) {
        MG_FINAL_PHONE_MARKER_PATTERN.lastIndex = 0;
        return mgPhoneVisibleText(String(text || '').replace(MG_FINAL_PHONE_MARKER_PATTERN, ' '));
    };

    mgLooksLikePhoneCallIntentText = function(text) {
        return mgTextHasPhoneMarker(text);
    };

    mgNormalizePhoneItem = function(item = {}) {
        const call = item.call && typeof item.call === 'object' ? item.call : {};
        const rawText = item.content || item.text || item.body || '';
        const explicitInvite = item.callInvite === true || item.phoneCall === true || call.callInvite === true || call.phoneCall === true || mgTextHasPhoneMarker(rawText);
        if (!explicitInvite) return null;
        return {
            callInvite: true,
            callTitle: mgPhoneVisibleText(item.callTitle || call.title || item.phoneTitle, '전화'),
            callLine: mgPhoneVisibleText(mgStripPhoneMarker(item.callLine || call.line || item.phoneLine || rawText), '지금 통화할 수 있어?')
        };
    };

    mgDirectPhoneCallItem = function(character, item = {}) {
        const call = item.call && typeof item.call === 'object' ? item.call : {};
        const rawText = item.content || item.text || item.body || '';
        const explicitInvite = item.callInvite === true || item.phoneCall === true || call.callInvite === true || call.phoneCall === true || mgTextHasPhoneMarker(rawText);
        if (!explicitInvite) return null;
        const clean = mgStripPhoneMarker(rawText);
        return {
            title: mgPhoneVisibleText(item.callTitle || call.title || item.phoneTitle || mgPhoneIntentTitle(character)),
            line: mgPhoneVisibleText(item.callLine || call.line || item.phoneLine || clean || rawText || '지금 통화할 수 있어?')
        };
    };

    mgStripPhoneArtifacts = function(value) {
        return String(value || '')
            .replace(MG_FINAL_PHONE_MARKER_PATTERN, '')
            .replace(/\[\s*(?:전화|통화)\s*[:：][^\]]+\]/g, '')
            .replace(MG_PHONE_DURATION_PATTERN, '')
            .replace(/^\s*(?:통화\s*취소|부재중\s*전화|전화\s*취소|전화\s*거절)\s*$/gmi, '')
            .replace(/(?:통화|전화)\s*기록\s*$/gmi, '')
            .replace(/\n{3,}/g, '\n\n')
            .trim();
    };

    function mgIsPhoneArtifactLine(value) {
        const text = String(value || '').trim();
        if (!text) return true;
        if (/^.*:\s*(?:\[\s*(?:전화|통화)\s*[:：][^\]]+\]|통화\s*취소|부재중\s*전화|전화\s*취소|전화\s*거절|(?:통화|전화)\s*기록\s*(?:\d{1,2}\s*시간\s*)?\d{1,2}\s*분\s*\d{1,2}\s*초)\s*$/i.test(text)) return true;
        if (/^(?:\[\s*(?:전화|통화)\s*[:：][^\]]+\]|통화\s*취소|부재중\s*전화|전화\s*취소|전화\s*거절|(?:통화|전화)\s*기록\s*(?:\d{1,2}\s*시간\s*)?\d{1,2}\s*분\s*\d{1,2}\s*초)\s*$/i.test(text)) return true;
        return false;
    }

    function mgCleanPhoneArtifactsFromPrompt(value) {
        return String(value || '')
            .split('\n')
            .filter(line => !mgIsPhoneArtifactLine(line))
            .map(line => mgStripPhoneArtifacts(line))
            .filter(Boolean)
            .join('\n')
            .replace(/\n{3,}/g, '\n\n')
            .trim();
    }

    function mgPhoneContextText(call = mgPhoneCall) {
        if (!call) return '';
        const room = mgPhoneRoom(call.roomId);
        const character = mgPhoneCharacter(room);
        const transcript = Array.isArray(call.transcript) ? call.transcript : [];
        if (!transcript.length) return '';
        return transcript.map(item => {
            const who = item.role === 'user' ? userNameFor(character) : character?.name || 'Character';
            return `${who}: ${item.text || ''}`;
        }).filter(line => !/:\s*$/.test(line)).join('\n');
    }

    function mgUpdateLatestPhoneLogContext(call = mgPhoneCall) {
        if (!call?.roomId) return;
        const list = state.messages?.[call.roomId] || [];
        const log = [...list].reverse().find(item => item?.phoneLog === 'ended' || /통화\s*기록/.test(String(item?.content || '')));
        if (!log) return;
        log.phoneTranscriptContext = mgPhoneContextText(call);
        log.phoneStartedAt = call.acceptedAt || call.connectedAt || call.createdAt || log.phoneStartedAt || Date.now();
        log.phoneEndedAt = Date.now();
    }

    const mgBaseAppendPhoneLogMessageFinal = mgAppendPhoneLogMessage;
    mgAppendPhoneLogMessage = async function(roomId, character, text, status = '') {
        await mgBaseAppendPhoneLogMessageFinal(roomId, character, text, status);
        if (status === 'ended') {
            mgUpdateLatestPhoneLogContext(mgPhoneCall);
            try { await saveState(); } catch (_) {}
        }
    };

    const mgBaseGeneratePhoneTurnChoiceEcho = mgGeneratePhoneTurn;
    mgGeneratePhoneTurn = async function(userChoice = '') {
        const choiceText = String(userChoice || '').trim();
        if (choiceText && mgPhoneCall?.open) {
            clearInterval(mgPhoneTypeTimer);
            clearTimeout(mgPhoneSequencePauseTimer);
            mgPhoneCall.line = choiceText;
            mgPhoneCall.displayLine = choiceText;
            mgPhoneCall.manualLines = [];
            mgPhoneCall.awaitingNextLine = false;
            mgPhoneCall.typing = false;
            mgPhoneCall.loading = true;
            mgPhoneCall.options = [];
            render();
        }
        return mgBaseGeneratePhoneTurnChoiceEcho(userChoice);
    };

    mgTypePhoneLineThenClose = function(line) {
        clearInterval(mgPhoneTypeTimer);
        clearTimeout(mgPhoneSequencePauseTimer);
        if (!mgPhoneCall?.open) return;
        mgUpdateLatestPhoneLogContext(mgPhoneCall);
        try { saveState(); } catch (_) {}
        const text = String(line || '나중에 다시 전화할게.');
        mgPhoneCall.loading = false;
        mgPhoneCall.ending = true;
        mgPhoneCall.options = [];
        mgPhoneCall.line = text;
        mgPhoneCall.displayLine = '';
        mgPhoneCall.typing = true;
        render();
        let index = 0;
        mgPhoneTypeTimer = setInterval(() => {
            if (!mgPhoneCall?.open) { clearInterval(mgPhoneTypeTimer); return; }
            index += 1;
            mgPhoneCall.displayLine = text.slice(0, index);
            const node = document.getElementById('mg-phone-line');
            if (node) node.textContent = mgPhoneCall.displayLine;
            if (index >= text.length) {
                clearInterval(mgPhoneTypeTimer);
                mgPhoneCall.typing = false;
                mgPhoneCall.displayLine = text;
                render();
                setTimeout(() => {
                    if (mgPhoneCall?.ending) {
                        mgPhoneCall = null;
                        render();
                    }
                }, 2400);
            }
        }, 54);
    };

    mgIncomingPhoneCallOverlayHtml = function() {
        if (!mgIncomingPhoneCall || mgPhoneCall?.open) return '';
        const room = mgPhoneRoom(mgIncomingPhoneCall.roomId);
        const character = mgPhoneCharacter(room);
        const avatar = mgPhoneAvatarData(character);
        const avatarHtmlValue = avatar ? `<img src="${escapeHtml(mediaDisplayUrl(avatar, `incoming-phone-avatar-${character?.id || ''}`))}" alt="">` : `<span>${escapeHtml(character?.avatarText || character?.name?.slice(0, 2) || '?')}</span>`;
        const bgStyle = avatar ? ` style="--mg-phone-bg:url('${escapeHtml(mediaDisplayUrl(avatar, `incoming-phone-bg-${character?.id || ''}`))}')"` : '';
        return `<div class="mg-phone-call-overlay mg-phone-incoming-overlay"${bgStyle}><div class="mg-phone-bg"></div><section class="mg-phone-stage mg-phone-incoming-stage">
            <div class="mg-phone-avatar">${avatarHtmlValue}</div>
            <div class="mg-phone-name"><strong>${escapeHtml(character?.name || mgIncomingPhoneCall.title || '상대')}</strong><span>전화 수신 중...</span></div>
            <div class="mg-phone-incoming-actions"><button class="mg-phone-round mg-phone-decline" type="button" title="거절" data-action="reject-incoming-phone-call">✕</button><button class="mg-phone-round mg-phone-accept" type="button" title="수신" data-action="accept-incoming-phone-call">✓</button></div>
        </section></div>`;
    };

    const mgBaseStartPhoneCallDelayIncoming = mgStartPhoneCall;
    mgStartPhoneCall = async function(roomId = selectedRoomId, initiator = 'user') {
        if (initiator === 'character' && !mgAcceptingIncomingPhoneCall) {
            const room = mgPhoneRoom(roomId);
            const callMessage = mgFindPhoneMessage(room?.id || roomId);
            if (!room || !callMessage) return;
            const key = `${room.id}:${callMessage.id || 'latest'}`;
            if (mgIncomingPhoneDelayTimers.has(key)) clearTimeout(mgIncomingPhoneDelayTimers.get(key));
            mgIncomingPhoneDelayTimers.set(key, setTimeout(() => {
                mgIncomingPhoneDelayTimers.delete(key);
                if (!mgPhoneCall?.open) mgShowIncomingPhoneCall(room.id, callMessage);
            }, 3000));
            return;
        }
        return mgBaseStartPhoneCallDelayIncoming(roomId, initiator);
    };

    const mgBasePhoneCallOverlayHtmlFinalNoEndingInput = mgPhoneCallOverlayHtml;
    mgPhoneCallOverlayHtml = function() {
        let html = mgBasePhoneCallOverlayHtmlFinalNoEndingInput();
        if (!html || !mgPhoneCall?.open || mgPhoneCall.hidden) return html;
        if (mgPhoneCall.ending) html = html.replace(/<div class="mg-phone-custom-reply">[\s\S]*?<\/div>(?=\s*<button class="mg-btn mg-phone-hangup")/, '');
        return html;
    };

    function mgRecentPhoneContextForRoom(roomId) {
        const rows = (state.messages?.[roomId] || [])
            .filter(item => item?.phoneTranscriptContext)
            .slice(-3)
            .map(item => `통화 기록 ${formatTime(item.createdAt)}\n${item.phoneTranscriptContext}`.trim());
        return rows.join('\n\n');
    }

    const mgBaseBuildMessagesPhoneContextMemory = buildMessages;
    buildMessages = async function(character, options = {}) {
        const messages = await mgBaseBuildMessagesPhoneContextMemory(character, options);
        const roomId = options.roomId || selectedRoomId;
        const phoneContext = mgRecentPhoneContextForRoom(roomId);
        if (phoneContext && messages?.[0]) {
            messages[0].content = `${contentText(messages[0].content)}\n\nRecent phone-call transcript memory:\n${phoneContext}\n\nUse this as relationship/context memory. Do not quote the call log marker or duration unless the user asks.`;
        }
        return messages;
    };

    const mgBaseBuildSnsPostMessagesFinalPhoneClean = buildSnsPostMessages;
    buildSnsPostMessages = function(character, hintText, roomId = selectedRoomId, options = {}) {
        const messages = mgBaseBuildSnsPostMessagesFinalPhoneClean(character, hintText, roomId, options);
        for (const message of messages || []) {
            if (typeof message?.content === 'string') message.content = mgCleanPhoneArtifactsFromPrompt(message.content);
        }
        if (messages?.[0]) messages[0].content = `${contentText(messages[0].content)}\n\nFinal SNS phone-log exclusion:\n- Do not output phone-call markers, phone labels, missed/canceled call labels, or duration records such as 통화기록 00분 12초 / 통화 기록 00시간 00분 12초.\n- Do not make hashtags from 전화, 통화, 부재중, PHONE_CALL, call, or phone unless the user explicitly asks for a phone-themed SNS post.`;
        return messages;
    };

    const mgBaseSanitizeSnsPlatformFinalPhoneClean = sanitizeSnsPlatform;
    sanitizeSnsPlatform = function(item, post, character) {
        const cleaned = mgBaseSanitizeSnsPlatformFinalPhoneClean(item, post, character);
        const originalText = String(cleaned?.text || '');
        const strippedText = mgStripPhoneArtifacts(originalText);
        if (!strippedText || mgIsPhoneArtifactLine(originalText)) {
            const fallback = typeof fallbackSnsPostText === 'function'
                ? fallbackSnsPostText(character || currentCharacter(), post?.sourceRoomId || selectedRoomId, post?.hint || state.config?.sns?.subject || '')
                : `${character?.name || '캐릭터'}의 오늘 기록.`;
            cleaned.text = cleanSnsVisibleText(mgStripPhoneArtifacts(fallback)) || `${character?.name || '캐릭터'}의 오늘 기록.`;
        } else {
            cleaned.text = strippedText;
        }
        if (Array.isArray(cleaned.hashtags)) cleaned.hashtags = cleaned.hashtags.filter(tag => !/전화|통화|부재중|PHONE_CALL|call|phone/i.test(String(tag || '')));
        cleaned.imageCaption = mgStripPhoneArtifacts(cleaned.imageCaption || '');
        cleaned.imagePrompt = String(cleaned.imagePrompt || '').replace(/PHONE_CALL|phone call|call record|missed call/ig, '').trim();
        return cleaned;
    };

    const mgBaseMessageHtmlStripBrokenPhoneMarker = messageHtml;
    messageHtml = function(message, index = 0, messages = currentMessages()) {
        if (message?.content && mgTextHasPhoneMarker(message.content)) {
            return mgBaseMessageHtmlStripBrokenPhoneMarker({ ...message, content: mgStripPhoneMarker(message.content) }, index, messages);
        }
        return mgBaseMessageHtmlStripBrokenPhoneMarker(message, index, messages);
    };
    // ---------------------------------------------------------------------

    // --- FINAL USER-CALL DURATION / OLD-SNS STYLE RESTORE ---
    const mgBaseStartPhoneCallDurationFix = mgStartPhoneCall;
    mgStartPhoneCall = async function(roomId = selectedRoomId, initiator = 'user') {
        const result = await mgBaseStartPhoneCallDurationFix(roomId, initiator);
        if (mgPhoneCall?.open && !mgPhoneCall.connectedAt && !mgIncomingPhoneCall) {
            const now = Date.now();
            mgPhoneCall.createdAt = mgPhoneCall.createdAt || now;
            mgPhoneCall.connectedAt = now;
            mgPhoneCall.acceptedAt = mgPhoneCall.acceptedAt || now;
        }
        return result;
    };

    function mgSnsCleanTimelineText(value) {
        return mgStripPhoneArtifacts(mgStripPhoneMarker(String(value || '')))
            .replace(/^\s*(?:통화\s*취소|부재중\s*전화|전화\s*취소|전화\s*거절)\s*$/gmi, '')
            .replace(/\n{3,}/g, '\n\n')
            .trim();
    }

    function mgSnsMessageTimelineLine(message, character, userName) {
        if (!message || message.role === 'system' || message.mediaType === 'phone-call' || message.phoneLog) return '';
        const raw = message.content || (message.mediaType && message.mediaType !== 'phone-call' ? mediaLabel(message) : '');
        const clean = mgSnsCleanTimelineText(raw);
        if (!clean || mgIsPhoneArtifactLine(clean)) return '';
        if (message.role === 'user') return `${userName}: ${clean}`;
        return `${getCharacter(message.characterId)?.name || character?.name || 'Character'}: ${clean}`;
    }

    function mgSnsRecentCleanMessages(roomId, character, limit = mgSnsContextMessageLimit()) {
        const userName = userNameFor(character);
        return (state.messages?.[roomId] || [])
            .slice(-Math.max(limit * 2, 24))
            .map(message => mgSnsMessageTimelineLine(message, character, userName))
            .filter(Boolean)
            .slice(-limit);
    }

    function mgSnsFallbackSeed(character, roomId, hintText = '') {
        const cleanHint = mgSnsCleanTimelineText(hintText);
        if (cleanHint && !mgIsPhoneArtifactLine(cleanHint)) return cleanHint;
        const lines = mgSnsRecentCleanMessages(roomId, character, 8);
        const last = [...lines].reverse().find(line => !/통화|전화|PHONE_CALL|부재중/i.test(line)) || lines[lines.length - 1] || '';
        return mgSnsCleanTimelineText(last.replace(/^.*?:\s*/, ''));
    }

    const mgBaseFallbackSnsPostTextOldStyleRestore = fallbackSnsPostText;
    fallbackSnsPostText = function(character, roomId, hintText = '') {
        const seed = mgSnsFallbackSeed(character, roomId, hintText);
        if (seed) {
            const clipped = seed.length > 170 ? `${seed.slice(0, 170).trim()}...` : seed;
            return clipped;
        }
        const name = character?.name || 'Character';
        const variants = [
            `${name}의 오늘 기록. 말로 다 적기 애매해서 여기만 남겨둔다.`,
            `오늘은 괜히 조용한 문장만 남기고 싶은 날.`,
            `별일 아닌 척 지나갔는데, 이상하게 오래 남는 순간이 있다.`,
            `타임라인에 올릴 말은 아닌데, 그래도 지우긴 싫어서.`
        ];
        const index = Math.abs(Math.floor((Date.now() / 1000) + Math.random() * variants.length)) % variants.length;
        return mgSnsCleanTimelineText(variants[index]) || mgBaseFallbackSnsPostTextOldStyleRestore(character, roomId, hintText);
    };

    function mgSnsPreviousPostsForPrompt(character) {
        return (state.snsPosts || [])
            .filter(post => post.characterId === character?.id)
            .slice(-5)
            .map(post => mgSnsCleanTimelineText(snsPostPlainText(post)).slice(0, 280))
            .filter(Boolean)
            .map(text => `- ${text}`)
            .join('\n');
    }

    buildSnsPostMessages = function(character, hintText, roomId = selectedRoomId, options = {}) {
        const room = getRoomById(roomId) || getCurrentRoom();
        const sns = { ...DEFAULT_CONFIG.sns, ...(state.config.sns || {}), ...(options.sns || {}) };
        const userName = userNameFor(character);
        const userProfile = userProfileFor(character);
        const transcript = room ? mgSnsRecentCleanMessages(room.id, character, mgSnsContextMessageLimit()).join('\n') : '';
        const cleanHint = mgSnsCleanTimelineText(hintText || sns.subject || '');
        const platform = sns.platform === 'hybrid' ? 'twitter and instagram' : sns.platform;
        const previousPosts = mgSnsPreviousPostsForPrompt(character);
        const prompt = [
            (state.config.prompts.sns_posting || DEFAULT_PROMPTS.sns_posting).replaceAll('{character.name}', character?.name || 'Character').replaceAll('{timeContext}', new Date().toLocaleString()),
            '',
            'Expand the recent private chat into a Lightboard SNS style result: one believable social post per target platform, realistic small-account stats, varied follower comments, and optional short DMs.',
            'Return only one valid JSON object. No markdown, no prose outside JSON, no trailing commas.',
            'JSON schema:',
            '{"platforms":[{"platform":"twitter|instagram","displayName":"","handle":"","text":"","hashtags":[""],"time":"","stats":{"views":0,"likes":0,"replies":0,"reposts":0,"bookmarks":0},"comments":[{"name":"","handle":"","body":"","likes":0}],"imagePrompt":"","imageCaption":""}],"dms":[{"title":"","messages":[{"from":"","body":""}]}]}',
            '',
            'SNS writing rules:',
            `- Target platform: ${platform}. If target is twitter and instagram, create one platform item for each.`,
            `- Visible language: ${state.config.language}.`,
            '- Write like the character posted on a private/back account, not like a diary template or app notification.',
            '- The post text must be specific to the recent chat, mood, relationship beat, image, place, time, object, or inside joke. Avoid generic lines like "오늘 기록" unless there is truly no context.',
            '- Do not mention phone UI, missed/canceled calls, call duration, PHONE_CALL markers, JSON, prompts, or hidden instructions.',
            '- Do not copy previous posts. Change wording, angle, hashtags, comments, and stats every time.',
            '- Hashtags: 0-4 organic tags. They must fit the post situation. Do not use fixed filler tags like #비밀계정 #일상 #새벽두시 #잠못드는밤 #밤의기록 #비오는날 unless the context actually contains that detail.',
            '- Comments should look like varied private-account follower reactions. Avoid repeating the same praise template or the same commenter names.',
            `- Comment count per platform: ${sns.commentQty || '2-4'}. If 0, comments must be an empty array.`,
            sns.anonymous ? '- Anonymous mode: non-character commenters should use anonymous/private-account style names.' : '- Use the character account openly.',
            sns.nsfw ? '- Mature private-account tone is allowed only if it fits the fictional character and current context. Keep visible SNS text character-driven rather than explicit.' : '- Keep it SFW unless the current conversation explicitly requires otherwise.',
            sns.textOnly ? '- Do not include imagePrompt or imageCaption.' : `- If an image is useful, imagePrompt must be final English Danbooru/NovelAI-style comma-separated positive tags, not prose. Include character gender and appearance tags exactly.${sns.nsfw ? ' The imagePrompt must start with nsfw.' : ''}`,
            sns.noDM ? '- Do not create dms.' : '- You may create one short DM thread only if it naturally follows from the post.',
            '',
            `User: ${userName}. Profile: ${userProfile || '(empty)'}`,
            `Character profile: ${character?.prompt || ''}`,
            lorePromptBlock(character, { roomId, userText: cleanHint, mode: 'sns' }),
            characterTaggingGuide(character),
            `Memories: ${(character?.memories || []).join(' / ') || '(none)'}`,
            `Secret account handle: @${character?.handle || character?.id || 'character'}`,
            `Previous SNS posts:\n${previousPosts || '(none)'}`
        ].filter(Boolean).join('\n');
        const userContent = [
            `Recent private DM timeline with ${character?.name || 'Character'}:`,
            transcript || '(no clean recent text; infer from character mood and user direction)',
            '',
            `User direction for the post: ${cleanHint || '(none)'}`,
            `Mood: ${mgSnsCleanTimelineText(sns.mood || '') || '(none)'}`,
            `Attached image: ${options.image ? 'yes' : 'none'}`,
            '',
            'Create the SNS JSON now.'
        ].join('\n');
        return [
            { role: 'system', content: prompt },
            { role: 'user', content: userContent }
        ];
    };

    const mgBaseNormalizeSnsPlatformsOldStyleRestore = normalizeSnsPlatforms;
    normalizeSnsPlatforms = function(platforms, sns, character) {
        const normalized = mgBaseNormalizeSnsPlatformsOldStyleRestore(platforms, sns, character) || [];
        return normalized.map(item => {
            item.text = mgSnsCleanTimelineText(item.text || '');
            if (!item.text || mgIsPhoneArtifactLine(item.text)) item.text = fallbackSnsPostText(character, selectedRoomId, state.config?.sns?.subject || '');
            item.hashtags = (Array.isArray(item.hashtags) ? item.hashtags : [])
                .map(tag => String(tag || '').trim())
                .filter(Boolean)
                .filter(tag => !/전화|통화|부재중|PHONE_CALL|call|phone|새벽두시|잠못드는밤|밤의기록|비오는날/i.test(tag));
            item.hashtags = typeof ensureSnsHashtags === 'function' ? ensureSnsHashtags(item.hashtags, character, item.text, state.config?.sns?.subject || '') : item.hashtags;
            item.hashtags = item.hashtags.filter(tag => !/전화|통화|부재중|PHONE_CALL|call|phone/i.test(String(tag || ''))).slice(0, 4);
            item.imageCaption = mgSnsCleanTimelineText(item.imageCaption || '');
            return item;
        });
    };
    // ---------------------------------------------------------------------

    // --- FINAL SNS / PHONE SUMMARY CONTRACT FIX ---
    const MG_SNS_STALE_CALL_INVITE_PATTERN = /(?:PHONE_CALL|지금\s*바로\s*걸|바로\s*전화|전화\s*받|받아\s*줘|받을래|통화\s*연결|목소리.{0,20}(?:듣|들)|call\s+you\s+now|pick\s+up)/i;
    const MG_SNS_UI_ARTIFACT_TAG_PATTERN = /(?:PHONE_CALL|통화\s*기록|전화\s*기록|부재중|전화\s*취소|통화\s*취소|전화\s*거절|call\s*record|missed\s*call|duration)/i;

    function mgSnsLooksLikeCallInviteSeed(value) {
        const text = String(value || '').replace(/\s+/g, ' ').trim();
        if (!text) return false;
        if (/아까|방금|통화했|전화했|전화하고|통화하고|통화\s*후|전화\s*후/.test(text)) return false;
        return MG_SNS_STALE_CALL_INVITE_PATTERN.test(text);
    }

    function mgSnsEffectiveDirection(hintText = '', sns = {}) {
        const direct = mgSnsCleanTimelineText(hintText);
        if (direct && !mgSnsLooksLikeCallInviteSeed(direct)) return direct;
        const subject = mgSnsCleanTimelineText(sns?.subject || '');
        if (subject && !mgSnsLooksLikeCallInviteSeed(subject)) return subject;
        return '';
    }

    function mgPhoneSummaryRowsFromTranscript(value, character = currentCharacter()) {
        const userName = userNameFor(character || {});
        return String(value || '').split('\n').map(line => line.trim()).filter(Boolean).map(line => {
            const match = line.match(/^([^:：]{1,48})[:：]\s*(.+)$/);
            const label = match?.[1]?.trim() || '';
            const text = mgSnsCleanTimelineText(match?.[2] || line);
            if (!text || mgIsPhoneArtifactLine(text)) return null;
            return { role: label && label === userName ? 'user' : 'character', text };
        }).filter(Boolean);
    }

    function mgPhoneSummaryFromRows(rows, character = currentCharacter()) {
        const cleanRows = (Array.isArray(rows) ? rows : [])
            .map(item => ({ role: item?.role === 'user' ? 'user' : 'character', text: mgSnsCleanTimelineText(item?.text || '') }))
            .filter(item => item.text && !mgIsPhoneArtifactLine(item.text))
            .slice(-10);
        if (!cleanRows.length) return '';
        const characterName = character?.name || '상대';
        const userName = userNameFor(character || {});
        const combined = cleanRows.map(item => `${item.role === 'user' ? userName : characterName}: ${item.text}`).join(' / ');
        const lastCharacter = [...cleanRows].reverse().find(item => item.role !== 'user')?.text || '';
        const lastUser = [...cleanRows].reverse().find(item => item.role === 'user')?.text || '';
        const parts = [`${characterName}와 ${userName}가 전화로 대화했다`];
        parts.push(`주요 내용은 ${combined.slice(0, 420)}${combined.length > 420 ? '...' : ''}`);
        if (lastCharacter) parts.push(`${characterName}의 마지막 뉘앙스: ${lastCharacter.slice(0, 150)}`);
        if (lastUser) parts.push(`${userName}의 반응: ${lastUser.slice(0, 150)}`);
        return parts.join('. ').replace(/\.{2,}/g, '.').trim() + '.';
    }

    function mgPhoneSummaryText(call = mgPhoneCall) {
        if (!call) return '';
        const room = mgPhoneRoom(call.roomId);
        const character = mgPhoneCharacter(room) || currentCharacter();
        return mgPhoneSummaryFromRows(call.transcript || [], character);
    }

    mgPhoneContextText = function(call = mgPhoneCall) {
        return mgPhoneSummaryText(call);
    };

    const mgBaseUpdateLatestPhoneLogContextSummaryOnly = mgUpdateLatestPhoneLogContext;
    mgUpdateLatestPhoneLogContext = function(call = mgPhoneCall) {
        try { mgBaseUpdateLatestPhoneLogContextSummaryOnly(call); } catch (_) {}
        if (!call?.roomId) return;
        const list = state.messages?.[call.roomId] || [];
        const log = [...list].reverse().find(item => item?.phoneLog === 'ended' || /통화\s*기록/.test(String(item?.content || '')));
        if (!log) return;
        const summary = mgPhoneSummaryText(call);
        if (summary) {
            log.phoneSummaryContext = summary;
            delete log.phoneTranscriptContext;
        }
        log.phoneStartedAt = call.acceptedAt || call.connectedAt || call.createdAt || log.phoneStartedAt || Date.now();
        log.phoneEndedAt = Date.now();
    };

    function mgPhoneSummaryForStoredLog(message, character = currentCharacter()) {
        if (message?.phoneSummaryContext) return mgSnsCleanTimelineText(message.phoneSummaryContext);
        const rows = mgPhoneSummaryRowsFromTranscript(message?.phoneTranscriptContext || '', character);
        return mgPhoneSummaryFromRows(rows, character);
    }

    mgRecentPhoneContextForRoom = function(roomId, character = currentCharacter(), limit = 3) {
        return (state.messages?.[roomId] || [])
            .filter(item => item?.phoneLog === 'ended' || item?.phoneSummaryContext || item?.phoneTranscriptContext)
            .slice(-Math.max(1, limit))
            .map(item => mgPhoneSummaryForStoredLog(item, character))
            .filter(Boolean)
            .map(text => `- ${text}`)
            .join('\n');
    };

    function mgBackfillPhoneSummaries() {
        for (const messages of Object.values(state.messages || {})) {
            for (const message of messages || []) {
                if (!message?.phoneTranscriptContext || message.phoneSummaryContext) continue;
                const character = getCharacter(message.characterId) || currentCharacter();
                const summary = mgPhoneSummaryForStoredLog(message, character);
                if (summary) {
                    message.phoneSummaryContext = summary;
                    delete message.phoneTranscriptContext;
                }
            }
        }
    }

    mgPhoneTranscript = function(roomId) {
        const character = mgPhoneCharacter(mgPhoneRoom(roomId)) || currentCharacter();
        const userName = userNameFor(character || {});
        return (state.messages?.[roomId] || []).slice(-mgPhoneContextMessageLimit()).map(message => {
            if (!message || message.phoneLog || message.mediaType === 'phone-call') return '';
            const text = mgSnsCleanTimelineText(message.content || mediaLabel(message) || '');
            if (!text || mgIsPhoneArtifactLine(text)) return '';
            const speaker = message.role === 'user' ? userName : character?.name || 'Character';
            return `${speaker}: ${text}`;
        }).filter(Boolean).slice(-mgPhoneContextMessageLimit()).join('\n');
    };

    function mgRemoveOldPhoneTranscriptBlock(value) {
        return String(value || '')
            .replace(/\n{1,3}Recent phone-call transcript memory:\n[\s\S]*?Use this as relationship\/context memory\. Do not quote the call log marker or duration unless the user asks\./g, '')
            .replace(/\n{3,}/g, '\n\n')
            .trim();
    }

    const mgBaseBuildMessagesPhoneSummaryOnly = buildMessages;
    buildMessages = async function(character, options = {}) {
        const messages = await mgBaseBuildMessagesPhoneSummaryOnly(character, options);
        const roomId = options.roomId || selectedRoomId;
        const summary = mgRecentPhoneContextForRoom(roomId, character, 3);
        for (const message of messages || []) {
            if (typeof message?.content === 'string') message.content = mgRemoveOldPhoneTranscriptBlock(mgCleanPhoneArtifactsFromPrompt(message.content));
        }
        if (summary && messages?.[0]) {
            messages[0].content = `${contentText(messages[0].content)}\n\nRecent phone-call memory summaries:\n${summary}\n\nUse these summaries as relationship context. The visible chat may naturally mention that a call happened, but never quote phone-log UI labels, call duration, or raw transcript lines unless the user explicitly asks.`;
        }
        return messages;
    };

    function mgSnsMessageIsCallPrelude(message, messages, index) {
        if (!message || message.role === 'system') return false;
        const text = mgSnsCleanTimelineText(message.content || '');
        if (!text) return false;
        const next = Array.isArray(messages) ? messages[index + 1] : null;
        if (next?.mediaType === 'phone-call') {
            const line = mgSnsCleanTimelineText(next.callLine || next.content || '');
            if (!line || text.includes(line) || line.includes(text) || mgSnsLooksLikeCallInviteSeed(text)) return true;
        }
        return mgSnsLooksLikeCallInviteSeed(text);
    }

    mgSnsMessageTimelineLine = function(message, character, userName, messages = [], index = 0) {
        if (!message || message.role === 'system' || message.mediaType === 'phone-call' || message.phoneLog) return '';
        if (mgSnsMessageIsCallPrelude(message, messages, index)) return '';
        const raw = message.content || (message.mediaType && message.mediaType !== 'phone-call' ? mediaLabel(message) : '');
        const clean = mgSnsCleanTimelineText(raw);
        if (!clean || mgIsPhoneArtifactLine(clean)) return '';
        if (message.role === 'user') return `${userName}: ${clean}`;
        return `${getCharacter(message.characterId)?.name || character?.name || 'Character'}: ${clean}`;
    };

    mgSnsRecentCleanMessages = function(roomId, character, limit = mgSnsContextMessageLimit()) {
        const userName = userNameFor(character || {});
        const messages = (state.messages?.[roomId] || []).slice(-Math.max(limit * 2, 32));
        return messages.map((message, index) => mgSnsMessageTimelineLine(message, character, userName, messages, index)).filter(Boolean).slice(-limit);
    };

    function mgSnsPhoneFallbackLine(character, roomId) {
        const summary = mgRecentPhoneContextForRoom(roomId, character, 1);
        if (!summary) return '';
        const userName = userNameFor(character || {});
        const variants = [
            `아까 ${userName}이랑 통화했다. 별말 아닌 척했는데 목소리가 생각보다 오래 남는다.`,
            `${userName} 목소리 듣고 나니까 타임라인에 괜히 한 줄 남기고 싶어짐.`,
            `통화 끝났는데 아직 귀에 ${userName} 목소리 남아있는 거 좀 웃김.`,
            `아까 전화한 거 별일 아닌 척하려고 했는데, 생각보다 기분이 오래 간다.`
        ];
        return variants[Math.floor(Math.random() * variants.length)];
    }

    fallbackSnsPostText = function(character, roomId, hintText = '') {
        const cleanHint = mgSnsCleanTimelineText(hintText);
        if (cleanHint && !mgSnsLooksLikeCallInviteSeed(cleanHint)) return cleanHint.length > 190 ? `${cleanHint.slice(0, 190).trim()}...` : cleanHint;
        const phoneLine = mgSnsPhoneFallbackLine(character, roomId);
        if (phoneLine) return phoneLine;
        const lines = mgSnsRecentCleanMessages(roomId, character, 8);
        const seed = [...lines].reverse().map(line => mgSnsCleanTimelineText(line.replace(/^.*?:\s*/, ''))).find(line => line && !mgSnsLooksLikeCallInviteSeed(line));
        if (seed) return seed.length > 190 ? `${seed.slice(0, 190).trim()}...` : seed;
        const variants = [
            '별일 아닌 척 지나갔는데 이상하게 오래 남는 순간이 있다.',
            '타임라인에 올릴 말은 아닌데, 그래도 지우긴 싫어서.',
            '오늘은 괜히 조용한 문장 하나만 남겨두고 싶다.',
            '말로 다 정리되진 않아서 여기만 살짝 남겨둔다.'
        ];
        return variants[Math.floor(Math.random() * variants.length)];
    };

    function mgSnsCleanTagFresh(tag) {
        let value = String(tag || '').trim().replace(/^#+/, '');
        value = value.replace(/[#"'`“”‘’{}[\],.?!;:]+/g, '').replace(/\s+/g, '');
        value = value.replace(/[^\p{L}\p{N}_-]/gu, '');
        if (!value || MG_SNS_UI_ARTIFACT_TAG_PATTERN.test(value)) return '';
        return `#${value}`;
    }

    ensureSnsHashtags = function(tags, character, text = '', hintText = '') {
        const source = `${text}\n${hintText}`;
        const lower = source.toLowerCase();
        const stale = new Set(['#새벽두시', '#잠못드는밤', '#밤의기록', '#비오는날', '#비밀계정', '#비밀계', '#일상', '#데일리', '#daily', '#secret', '#private']);
        const clean = (Array.isArray(tags) ? tags : String(tags || '').split(/[\s,]+/))
            .map(mgSnsCleanTagFresh)
            .filter(Boolean)
            .filter(tag => !stale.has(tag) || (/새벽|밤|잠|비|우산|흐림/.test(source) && !/#비밀계정|#비밀계|#일상|#데일리|#daily|#secret|#private/i.test(tag)))
            .filter((tag, index, array) => array.indexOf(tag) === index)
            .slice(0, 4);
        if (clean.length) return clean;
        const inferred = [];
        const add = (...items) => { for (const item of items) { const tag = mgSnsCleanTagFresh(item); if (tag && !inferred.includes(tag)) inferred.push(tag); } };
        if (/통화|전화|목소리|call|voice/i.test(lower)) add('통화후기', '목소리');
        if (/사진|셀카|거울|image|photo|selfie/i.test(lower)) add('사진기록');
        if (/비|우산|흐림|rain/i.test(lower)) add('비오는날');
        if (/새벽|밤|잠|midnight|night/i.test(lower)) add('밤기록');
        if (/보고싶|그리움|외로|질투|좋아|사랑|마음|miss|love/i.test(lower)) add('마음기록');
        return inferred.slice(0, 4);
    };

    mgFallbackSnsComments = function(character, text = '', count = 3) {
        const max = Math.max(0, Math.min(Number(count) || 0, 8));
        if (max <= 0) return [];
        const source = String(text || '');
        const userName = userNameFor(character || {});
        const pool = /통화|전화|목소리/.test(source)
            ? [`아까 통화했다는 거 왜 이렇게 신경 쓰이냐`, `${userName} 얘기 맞지 이거`, '목소리 얘기 나오면 괜히 더 사적인 느낌', '담담한 척하는데 통화 좋았던 거 다 티 남', '이런 글은 당사자가 보면 바로 알 듯']
            : ['짧은데 괜히 다시 읽게 됨', '이거 무슨 일인지 조금 궁금한데', '말투는 평온한데 묘하게 티 남', '이런 글 올라오면 스크롤 멈춤', '별말 아닌 척하는 게 제일 수상함'];
        return pool.map(body => ({ body, sort: Math.random() })).sort((a, b) => a.sort - b.sort).slice(0, max).map((item, index) => ({
            name: state.config?.sns?.anonymous ? '익명' : ['눈팅러', '알림켜둔사람', '지나가다봄', '친구의친구', '스크롤멈춤'][index % 5],
            handle: state.config?.sns?.anonymous ? '' : `u${Math.random().toString(36).slice(2, 7)}`,
            body: item.body,
            likes: randomMetric(0, 45),
            createdAt: Date.now() - randomMetric(1000, 600000)
        }));
    };

    mgSnsPreviousPostsForPrompt = function(character) {
        return (state.snsPosts || [])
            .filter(post => post.characterId === character?.id)
            .slice(-8)
            .map(post => mgSnsCleanTimelineText(snsPostPlainText(post)).slice(0, 280))
            .filter(text => text && !mgSnsLooksLikeCallInviteSeed(text))
            .slice(-5)
            .map(text => `- ${text}`)
            .join('\n');
    };

    buildSnsPostMessages = function(character, hintText, roomId = selectedRoomId, options = {}) {
        const room = getRoomById(roomId) || getCurrentRoom();
        const sns = { ...DEFAULT_CONFIG.sns, ...(state.config.sns || {}), ...(options.sns || {}) };
        const userName = userNameFor(character || {});
        const userProfile = userProfileFor(character || {});
        const cleanDirection = mgSnsEffectiveDirection(hintText, sns);
        const transcript = room ? mgSnsRecentCleanMessages(room.id, character, mgSnsContextMessageLimit()).join('\n') : '';
        const phoneSummary = room ? mgRecentPhoneContextForRoom(room.id, character, 2) : '';
        const platform = sns.platform === 'hybrid' ? 'twitter and instagram' : sns.platform;
        const previousPosts = mgSnsPreviousPostsForPrompt(character);
        const prompt = [
            (state.config.prompts.sns_posting || DEFAULT_PROMPTS.sns_posting).replaceAll('{character.name}', character?.name || 'Character').replaceAll('{timeContext}', new Date().toLocaleString()),
            '',
            'Create a Lightboard SNS result from the clean chat context and phone-call summaries below.',
            'Return exactly one valid JSON object. No markdown, no prose outside JSON, no trailing commas.',
            'JSON schema:',
            '{"platforms":[{"platform":"twitter|instagram","displayName":"","handle":"","text":"","hashtags":[""],"time":"","stats":{"views":0,"likes":0,"replies":0,"reposts":0,"bookmarks":0},"comments":[{"name":"","handle":"","body":"","likes":0}],"imagePrompt":"","imageCaption":""}],"dms":[{"title":"","messages":[{"from":"","body":""}]}]}',
            '',
            'Writing rules:',
            `- Target platform: ${platform}. If target is twitter and instagram, create one item for each.`,
            `- Visible language: ${state.config.language}.`,
            `- The post is written by ${character?.name || 'the character'} on their own private/back account.`,
            `- If the phone summary is the most recent meaningful event, it is allowed and encouraged to turn it into natural SNS text such as "아까 ${userName}이랑 통화했다 ㅎㅎ" when it fits the character.`,
            '- Do not output UI artifacts: PHONE_CALL markers, call cards, missed/canceled call labels, raw call duration, or bracket labels like [전화: ...].',
            '- Do not copy a call invitation line as the post. The invitation line is not the SNS topic; the later call experience or emotional aftermath is.',
            '- Avoid repeating previous posts. Change the angle, wording, hashtags, comments, and stats.',
            '- Hashtags are optional. Use 0-4 specific tags from the actual post. Do not add fixed filler tags just because the character profile mentions night/rain/mood.',
            '- Comments must sound like varied real followers reacting to the concrete post detail, not a fixed praise template.',
            `- Comment count per platform: ${sns.commentQty || '2-4'}. If 0, comments must be an empty array.`,
            sns.anonymous ? '- Use private/anonymous follower names.' : '- Use normal small-account follower names.',
            sns.nsfw ? '- Mature tone is allowed only if it naturally fits the fictional character and context. Do not become explicit by default.' : '- Keep it SFW unless the current context explicitly requires otherwise.',
            sns.textOnly ? '- Do not include imagePrompt or imageCaption.' : `- If an image is useful, imagePrompt must be English comma-separated positive image tags, not prose. Include character gender and appearance tags exactly.${sns.nsfw ? ' The imagePrompt must start with nsfw.' : ''}`,
            sns.noDM ? '- Do not create dms.' : '- You may create one short DM thread only if it naturally follows from the post.',
            '',
            `User: ${userName}. Profile: ${userProfile || '(empty)'}`,
            `Character profile: ${character?.prompt || ''}`,
            lorePromptBlock(character, { roomId, userText: cleanDirection || phoneSummary, mode: 'sns' }),
            characterTaggingGuide(character),
            `Memories: ${(character?.memories || []).join(' / ') || '(none)'}`,
            `Secret account handle: @${character?.handle || character?.id || 'character'}`,
            `Previous SNS posts:\n${previousPosts || '(none)'}`
        ].filter(Boolean).join('\n');
        const userContent = [
            `Clean recent private DM timeline with ${character?.name || 'Character'}:`,
            transcript || '(no clean recent chat text)',
            '',
            'Recent phone-call summaries, if any:',
            phoneSummary || '(none)',
            '',
            `User direction for this post: ${cleanDirection || '(none)'}`,
            `Mood: ${mgSnsCleanTimelineText(sns.mood || '') || '(none)'}`,
            `Attached image: ${options.image ? 'yes' : 'none'}`,
            '',
            'Create the SNS JSON now.'
        ].join('\n');
        return [{ role: 'system', content: prompt }, { role: 'user', content: userContent }];
    };

    function mgSnsSanitizeConfigForGeneration(sns = {}, hintText = '') {
        const next = { ...DEFAULT_CONFIG.sns, ...(sns || {}) };
        if (!hintText && mgSnsLooksLikeCallInviteSeed(next.subject || '')) next.subject = '';
        if (mgSnsLooksLikeCallInviteSeed(next.mood || '')) next.mood = '';
        return next;
    }

    function mgSnsNormalizeCommentFresh(comment, index = 0, character = currentCharacter()) {
        const body = cleanSnsVisibleText(comment?.body || comment?.text || comment?.comment || comment?.content || '');
        if (!body || mgIsPhoneArtifactLine(body)) return null;
        return {
            id: comment?.id || `c_${Date.now().toString(36)}_${index}_${Math.random().toString(36).slice(2, 7)}`,
            name: String(comment?.name || comment?.nick || (comment?.isUser ? userNameFor(character || {}) : '익명')),
            handle: String(comment?.handle || '').replace(/^@/, ''),
            body: mgSnsCleanTimelineText(body),
            likes: Number(comment?.likes) || 0,
            isUser: Boolean(comment?.isUser),
            isCharacter: Boolean(comment?.isCharacter),
            createdAt: comment?.createdAt || Date.now()
        };
    }

    sanitizeSnsPlatform = function(item, post = {}, character = currentCharacter()) {
        const sns = item?.__sns || post?.__sns || state.config?.sns || DEFAULT_CONFIG.sns;
        const rawText = item?.text || item?.post || item?.tweet || item?.caption || post?.text || '';
        let text = mgSnsCleanTimelineText(cleanSnsVisibleText(rawText));
        if (mgSnsLooksLikeCallInviteSeed(text) || mgIsPhoneArtifactLine(text)) text = '';
        if (!text) text = fallbackSnsPostText(character, post?.sourceRoomId || selectedRoomId, post?.hint || mgSnsEffectiveDirection('', sns));
        const targetCount = typeof mgDesiredSnsCommentCount === 'function' ? mgDesiredSnsCommentCount(sns) : 3;
        let comments = Array.isArray(item?.comments) ? item.comments.map((comment, index) => mgSnsNormalizeCommentFresh(comment, index, character)).filter(Boolean) : [];
        if (comments.length < targetCount && typeof mgFallbackSnsComments === 'function') comments = comments.concat(mgFallbackSnsComments(character, text, targetCount - comments.length));
        comments = comments.slice(0, targetCount);
        const stats = item?.stats && typeof item.stats === 'object' ? item.stats : {};
        const platform = ['twitter', 'instagram', 'onlyfans'].includes(item?.platform) ? item.platform : (sns.platform === 'instagram' ? 'instagram' : 'twitter');
        const hashtagSource = Array.isArray(item?.hashtags) ? item.hashtags : extractSnsHashtags(item, `${rawText}\n${post?.text || ''}`);
        return {
            ...item,
            platform,
            displayName: String(item?.displayName || character?.name || 'Character'),
            handle: String(item?.handle || character?.handle || character?.id || '').replace(/^@/, ''),
            text,
            hashtags: ensureSnsHashtags(hashtagSource, character, text, post?.hint || mgSnsEffectiveDirection('', sns)),
            time: String(item?.time || 'now'),
            stats: {
                views: Number(stats.views) || randomMetric(90, 2600),
                likes: Number(stats.likes) || Number(post?.likes) || randomMetric(2, 160),
                replies: comments.length,
                reposts: Number(stats.reposts) || Number(stats.retweets) || randomMetric(0, 24),
                bookmarks: Number(stats.bookmarks) || randomMetric(0, 40)
            },
            comments,
            image: snsImageValue(item?.image || post?.image || ''),
            imagePrompt: String(item?.imagePrompt || item?.image_desc || post?.imagePrompt || '').replace(/PHONE_CALL|call record|missed call|duration/ig, '').trim(),
            imageCaption: mgSnsCleanTimelineText(item?.imageCaption || item?.caption || ''),
            finalImagePrompt: String(item?.finalImagePrompt || '').trim()
        };
    };

    normalizeSnsPlatforms = function(platforms, sns, character) {
        sns = mgSnsSanitizeConfigForGeneration(sns || state.config?.sns || {}, '');
        const expected = sns.platform === 'hybrid' ? ['twitter', 'instagram'] : [sns.platform === 'instagram' ? 'instagram' : 'twitter'];
        const source = Array.isArray(platforms) && platforms.length ? platforms : expected.map(platform => ({ platform, text: '' }));
        const picked = [...source];
        if (sns.platform === 'hybrid') for (const platform of expected) if (!picked.some(item => item?.platform === platform)) picked.push({ platform, text: picked[0]?.text || '' });
        return picked.slice(0, expected.length).map((item, index) => sanitizeSnsPlatform({ ...item, __sns: sns, platform: ['twitter', 'instagram', 'onlyfans'].includes(item?.platform) ? item.platform : expected[index] }, { __sns: sns, sourceRoomId: selectedRoomId }, character)).filter(item => item.text || item.image || item.imagePrompt);
    };

    generateSnsPost = async function(character, roomId, hintText = '', options = {}) {
        const characterSns = typeof snsConfigForCharacter === 'function' ? snsConfigForCharacter(character?.id) : { ...DEFAULT_CONFIG.sns, ...(state.config.sns || {}) };
        const sns = mgSnsSanitizeConfigForGeneration({ ...characterSns, ...(options.sns || {}) }, hintText);
        let raw = '';
        let parsed = null;
        try {
            const profile = state.config.apiProfiles?.[state.config.apiType || 'gemini'] || {};
            const configuredMax = Number(profile.maxTokens) || 0;
            const tokenBudget = Math.max(configuredMax, sns.platform === 'hybrid' ? 3600 : 2800);
            const payload = await callLLM(buildSnsPostMessages(character, hintText, roomId, { ...options, sns }), { maxTokens: tokenBudget, rawTextOnly: true, responseMimeType: 'application/json' });
            raw = String(payload?.rawText || payload?.text || payload?.content || payload?.messages?.map(item => item.content || item.text || '').filter(Boolean).join('\n') || '').trim();
            if (!raw) throw new Error('SNS post text was empty.');
            parsed = parseSnsPayload(raw, sns, character, roomId, mgSnsEffectiveDirection(hintText, sns));
        } catch (error) {
            raw = fallbackSnsPostText(character, roomId, mgSnsEffectiveDirection(hintText, sns));
            parsed = { platforms: [{ platform: sns.platform === 'instagram' ? 'instagram' : 'twitter', text: raw, comments: [], stats: {}, imagePrompt: fallbackSnsImagePrompt(character, raw), imageCaption: raw }], dms: [] };
            try { logDebug('sns-summary-fallback', `${character?.name || 'Character'} SNS generation fallback used: ${error.message}`, { roomId }); } catch (_) {}
        }
        const platforms = normalizeSnsPlatforms(parsed?.platforms || [], sns, character);
        if (!platforms.length) platforms.push(sanitizeSnsPlatform({ platform: sns.platform === 'instagram' ? 'instagram' : 'twitter', text: fallbackSnsPostText(character, roomId, mgSnsEffectiveDirection(hintText, sns)), __sns: sns }, { __sns: sns, sourceRoomId: roomId }, character));
        const attachedImage = options.image || '';
        for (const [index, item] of platforms.entries()) {
            item.hashtags = ensureSnsHashtags(item.hashtags || [], character, item.text || raw, mgSnsEffectiveDirection(hintText, sns));
            if (attachedImage && index === 0) item.image = attachedImage;
            if (!item.imagePrompt && !sns.textOnly && sns.autoImage !== false) item.imagePrompt = fallbackSnsImagePrompt(character, item.text);
            if (sns.nsfw && item.imagePrompt) item.imagePrompt = ensureNsfwTag(item.imagePrompt, { nsfw: true });
            if (!item.image && !sns.textOnly && sns.autoImage !== false && item.imagePrompt && (state.config.imageGeneration || {}).enabled) {
                try {
                    const imageItem = { imagePrompt: item.imagePrompt, imageCaption: item.imageCaption || item.text || '' };
                    item.image = await callImageGeneration(character, imageItem);
                    item.finalImagePrompt = imageItem.finalImagePrompt || item.imagePrompt;
                } catch (error) {
                    try { logDebug('sns-image-error', `${character?.name || 'Character'} SNS image generation failed: ${error.message}`, { roomId, platform: item.platform }); } catch (_) {}
                }
            }
        }
        state.snsPosts = state.snsPosts || [];
        const first = platforms[0] || {};
        const post = {
            id: makeId(),
            characterId: character?.id,
            platforms,
            dms: Array.isArray(parsed?.dms) && !sns.noDM ? parsed.dms.slice(0, 2) : [],
            text: first.text || cleanSnsVisibleText(raw),
            image: first.image || attachedImage,
            imagePrompt: first.finalImagePrompt || first.imagePrompt || '',
            likes: Number(first.stats?.likes) || 0,
            createdAt: Date.now(),
            sourceRoomId: roomId,
            hint: mgSnsEffectiveDirection(hintText, sns),
            auto: options.manual ? false : true
        };
        state.snsPosts.unshift(post);
        try { if (typeof noteSnsPost === 'function') noteSnsPost(character, post); } catch (_) {}
        const messages = state.messages?.[roomId] || [];
        if (character) character.lastSnsMessageCount = messages.length;
        return post;
    };
    // ---------------------------------------------------------------------

    // --- FINAL SNS CORE REPAIR: CALL/PARSE/FALLBACK SEPARATION ---
    const mgBaseCallLLMNoImplicitJsonMime = callLLM;
    callLLM = async function(messages, overrides = {}) {
        const nextOverrides = Object.prototype.hasOwnProperty.call(overrides || {}, 'responseMimeType')
            ? overrides
            : { ...(overrides || {}), responseMimeType: false };
        return mgBaseCallLLMNoImplicitJsonMime(messages, nextOverrides);
    };

    function mgSnsRawTextFromPayload(payload) {
        return String(
            payload?.rawText ||
            payload?.text ||
            payload?.content ||
            (Array.isArray(payload?.messages) ? payload.messages.map(item => item?.content || item?.text || item?.body || '').filter(Boolean).join('\n') : '') ||
            ''
        ).trim();
    }

    function mgSnsTryJson(value) {
        const raw = String(value || '').trim();
        if (!raw) return null;
        const attempts = [
            raw,
            raw.replace(/^```(?:json)?\s*|```$/g, '').trim(),
            extractJson(raw),
            repairJsonish(extractJson(raw))
        ].filter(Boolean);
        for (const attempt of attempts) {
            try { return JSON.parse(attempt); } catch (_) {}
        }
        return null;
    }

    function mgSnsTextFromMessageArray(messages) {
        return (Array.isArray(messages) ? messages : [])
            .map(item => cleanSnsVisibleText(item?.content || item?.body || item?.text || item?.message || ''))
            .filter(Boolean)
            .join('\n')
            .trim();
    }

    function mgSnsPayloadFromRaw(raw, sns, character, roomId, hintText = '') {
        const parsed = mgSnsTryJson(raw);
        if (parsed && typeof parsed === 'object') {
            if (Array.isArray(parsed.platforms)) return { ...parsed, platforms: parsed.platforms };
            const messageText = mgSnsTextFromMessageArray(parsed.messages || parsed.replies || parsed.posts);
            const text = cleanSnsVisibleText(parsed.text || parsed.post || parsed.tweet || parsed.caption || parsed.body || messageText || raw);
            return {
                platforms: [{
                    platform: sns?.platform === 'instagram' ? 'instagram' : 'twitter',
                    displayName: parsed.displayName || character?.name || '',
                    handle: parsed.handle || character?.handle || character?.id || '',
                    text,
                    hashtags: Array.isArray(parsed.hashtags) ? parsed.hashtags : extractLooseHashtags(raw, text),
                    comments: Array.isArray(parsed.comments) ? parsed.comments : Array.isArray(parsed.replies) ? parsed.replies : [],
                    stats: parsed.stats || {},
                    imagePrompt: parsed.imagePrompt || parsed.image_desc || '',
                    imageCaption: parsed.imageCaption || parsed.caption || ''
                }],
                dms: Array.isArray(parsed.dms) ? parsed.dms : []
            };
        }
        const looseText = cleanSnsVisibleText(raw);
        return {
            platforms: [{
                platform: sns?.platform === 'instagram' ? 'instagram' : 'twitter',
                text: looseText,
                hashtags: extractLooseHashtags(raw, looseText),
                comments: extractSnsTrailingComments(raw),
                stats: {},
                imagePrompt: extractSnsLooseField(raw, 'imagePrompt'),
                imageCaption: extractSnsLooseField(raw, 'imageCaption')
            }],
            dms: []
        };
    }

    function mgSnsFreshFallbackText(character, roomId, hintText = '') {
        const direct = mgSnsCleanTimelineText(hintText);
        if (direct && !mgSnsLooksLikeCallInviteSeed(direct)) return direct.slice(0, 190);
        const phoneLine = typeof mgSnsPhoneFallbackLine === 'function' ? mgSnsPhoneFallbackLine(character, roomId) : '';
        if (phoneLine) return phoneLine;
        const lines = typeof mgSnsRecentCleanMessages === 'function' ? mgSnsRecentCleanMessages(roomId, character, 10) : [];
        const recent = [...lines].reverse()
            .map(line => mgSnsCleanTimelineText(String(line || '').replace(/^.*?:\s*/, '')))
            .find(line => line && !mgSnsLooksLikeCallInviteSeed(line));
        if (recent) return recent.length > 190 ? `${recent.slice(0, 190).trim()}...` : recent;
        const profile = String(character?.prompt || '').replace(/\s+/g, ' ').trim();
        const seeds = [
            profile ? `${character?.name || '나'}답게 굴지 않으려고 했는데, 결국 이런 말만 남기게 된다.` : '',
            '별일 아닌 척 넘긴 순간이 이상하게 오래 남는다.',
            '타임라인에는 짧게만 남겨둔다. 자세한 건 굳이 말 안 해도 될 것 같아서.',
            '오늘은 조용한 말 하나가 더 오래 가는 날.',
            '괜찮은 척하는 게 제일 티 나는 순간이 있다.'
        ].filter(Boolean);
        return seeds[Math.floor(Math.random() * seeds.length)];
    }

    fallbackSnsPostText = function(character, roomId, hintText = '') {
        return mgSnsFreshFallbackText(character, roomId, hintText);
    };

    function mgSnsBuildCoreMessages(character, hintText, roomId = selectedRoomId, options = {}) {
        const room = getRoomById(roomId) || getCurrentRoom();
        const sns = { ...DEFAULT_CONFIG.sns, ...(state.config.sns || {}), ...(options.sns || {}) };
        const cleanDirection = mgSnsEffectiveDirection(hintText, sns);
        const userName = userNameFor(character || {});
        const transcript = room ? mgSnsRecentCleanMessages(room.id, character, mgSnsContextMessageLimit()).join('\n') : '';
        const phoneSummary = room ? mgRecentPhoneContextForRoom(room.id, character, 2) : '';
        const previousPosts = mgSnsPreviousPostsForPrompt(character);
        const platform = sns.platform === 'hybrid' ? 'twitter and instagram' : sns.platform;
        const prompt = [
            (state.config.prompts.sns_posting || DEFAULT_PROMPTS.sns_posting).replaceAll('{character.name}', character?.name || 'Character').replaceAll('{timeContext}', new Date().toLocaleString()),
            '',
            'Create a Lightboard SNS post result as one valid JSON object.',
            'Return JSON only. No markdown, no prose outside JSON, no trailing commas.',
            'Schema: {"platforms":[{"platform":"twitter|instagram","displayName":"","handle":"","text":"","hashtags":[""],"time":"","stats":{"views":0,"likes":0,"replies":0,"reposts":0,"bookmarks":0},"comments":[{"name":"","handle":"","body":"","likes":0}],"imagePrompt":"","imageCaption":""}],"dms":[{"title":"","messages":[{"from":"","body":""}]}]}',
            '',
            `Target platform: ${platform}. If target is twitter and instagram, create one platform item for each.`,
            `Visible language: ${state.config.language}.`,
            `Character: ${character?.name || 'Character'} (@${character?.handle || character?.id || 'character'}).`,
            `User: ${userName}. Profile: ${userProfileFor(character || {}) || '(empty)'}`,
            `Character profile: ${character?.prompt || '(empty)'}`,
            lorePromptBlock(character, { roomId, userText: cleanDirection || phoneSummary, mode: 'sns' }),
            characterTaggingGuide(character),
            `Memories: ${(character?.memories || []).join(' / ') || '(none)'}`,
            '',
            'Writing rules:',
            '- Make the post feel like an actual private/back-account SNS update: specific, indirect, character-authored, and socially readable.',
            '- Do not write a generic fallback diary line. Use the clean timeline, phone summary, character profile, mood, image, place, time, relationship beat, or inside joke.',
            `- If a phone summary exists and is the strongest recent event, it may naturally become text like "아까 ${userName}이랑 통화했다 ㅎㅎ".`,
            '- Do not copy phone invitation lines or UI logs. Never output PHONE_CALL, [전화: ...], missed/canceled labels, or raw duration records.',
            '- Comments must be varied follower reactions to the concrete post. Avoid fixed praise templates.',
            `- Comment count per platform: ${sns.commentQty || '2-4'}. If 0, comments must be an empty array.`,
            '- Hashtags are optional. Use 0-4 organic tags; no fixed filler tags.',
            sns.textOnly ? '- Do not include imagePrompt or imageCaption.' : `- If an image is useful, imagePrompt must be English comma-separated positive tags, not prose. Include character gender and appearance tags exactly.${sns.nsfw ? ' The imagePrompt must start with nsfw.' : ''}`,
            sns.noDM ? '- Do not create dms.' : '- You may create one short DM thread only if it naturally follows from the post.',
            '',
            `Previous SNS posts:\n${previousPosts || '(none)'}`
        ].filter(Boolean).join('\n');
        const userContent = [
            `Clean recent private DM timeline with ${character?.name || 'Character'}:`,
            transcript || '(no recent chat text; use the character profile and direction)',
            '',
            'Recent phone-call summaries:',
            phoneSummary || '(none)',
            '',
            `User direction for this post: ${cleanDirection || '(none)'}`,
            `Mood: ${mgSnsCleanTimelineText(sns.mood || '') || '(none)'}`,
            `Attached image: ${options.image ? 'yes' : 'none'}`,
            '',
            'Create the SNS JSON now.'
        ].join('\n');
        return [{ role: 'system', content: prompt }, { role: 'user', content: userContent }];
    }

    buildSnsPostMessages = function(character, hintText, roomId = selectedRoomId, options = {}) {
        return mgSnsBuildCoreMessages(character, hintText, roomId, options);
    };

    async function mgSnsCallLLMForPost(character, roomId, hintText, options, sns) {
        const profile = state.config.apiProfiles?.[state.config.apiType || 'gemini'] || {};
        const configuredMax = Number(profile.maxTokens) || 0;
        const tokenBudget = Math.max(configuredMax, sns.platform === 'hybrid' ? 3600 : 2800);
        const messages = mgSnsBuildCoreMessages(character, hintText, roomId, { ...options, sns });
        try { logDebug('sns-llm-call-start', `${character?.name || 'Character'} SNS LLM call started`, { roomId, platform: sns.platform }); } catch (_) {}
        const payload = await callLLM(messages, { maxTokens: tokenBudget, responseMimeType: false });
        const raw = mgSnsRawTextFromPayload(payload);
        if (!raw) throw new Error('SNS LLM returned empty text.');
        try { logDebug('sns-llm-call-ok', `${character?.name || 'Character'} SNS LLM call returned text`, { roomId, preview: raw.slice(0, 240) }); } catch (_) {}
        return raw;
    }

    function mgSnsEnsurePlatforms(parsed, sns, character, roomId, hintText) {
        let platforms = normalizeSnsPlatforms(parsed?.platforms || [], sns, character);
        if (!platforms.length) {
            const text = mgSnsFreshFallbackText(character, roomId, hintText);
            platforms = normalizeSnsPlatforms([{ platform: sns.platform === 'instagram' ? 'instagram' : 'twitter', text, comments: [], stats: {}, __sns: sns }], sns, character);
        }
        return platforms;
    }

    generateSnsPost = async function(character, roomId, hintText = '', options = {}) {
        const characterSns = typeof snsConfigForCharacter === 'function' ? snsConfigForCharacter(character?.id) : { ...DEFAULT_CONFIG.sns, ...(state.config.sns || {}) };
        const sns = mgSnsSanitizeConfigForGeneration({ ...characterSns, ...(options.sns || {}) }, hintText);
        const direction = mgSnsEffectiveDirection(hintText, sns);
        let raw = '';
        let parsed = null;
        let fallbackReason = '';
        try {
            raw = await mgSnsCallLLMForPost(character, roomId, direction, options, sns);
        } catch (error) {
            fallbackReason = error?.message || String(error || 'unknown SNS LLM error');
            raw = mgSnsFreshFallbackText(character, roomId, direction);
            try { logDebug('sns-llm-fallback', `${character?.name || 'Character'} SNS LLM failed, fallback used: ${fallbackReason}`, { roomId }); } catch (_) {}
        }
        parsed = mgSnsPayloadFromRaw(raw, sns, character, roomId, direction);
        const platforms = mgSnsEnsurePlatforms(parsed, sns, character, roomId, direction);
        const attachedImage = options.image || '';
        for (const [index, item] of platforms.entries()) {
            item.hashtags = ensureSnsHashtags(item.hashtags || [], character, item.text || raw, direction);
            if (attachedImage && index === 0) item.image = attachedImage;
            if (!item.imagePrompt && !sns.textOnly && sns.autoImage !== false) item.imagePrompt = fallbackSnsImagePrompt(character, item.text || raw);
            if (sns.nsfw && item.imagePrompt) item.imagePrompt = ensureNsfwTag(item.imagePrompt, { nsfw: true });
            if (!item.image && !sns.textOnly && sns.autoImage !== false && item.imagePrompt && (state.config.imageGeneration || {}).enabled) {
                try {
                    const imageItem = { imagePrompt: item.imagePrompt, imageCaption: item.imageCaption || item.text || '' };
                    item.image = await callImageGeneration(character, imageItem);
                    item.finalImagePrompt = imageItem.finalImagePrompt || item.imagePrompt;
                } catch (error) {
                    try { logDebug('sns-image-error', `${character?.name || 'Character'} SNS image generation failed: ${error.message}`, { roomId, platform: item.platform }); } catch (_) {}
                }
            }
        }
        state.snsPosts = state.snsPosts || [];
        const first = platforms[0] || {};
        const post = {
            id: makeId(),
            characterId: character?.id,
            platforms,
            dms: Array.isArray(parsed?.dms) && !sns.noDM ? parsed.dms.slice(0, 2) : [],
            text: first.text || cleanSnsVisibleText(raw),
            image: first.image || attachedImage,
            imagePrompt: first.finalImagePrompt || first.imagePrompt || '',
            likes: Number(first.stats?.likes) || 0,
            createdAt: Date.now(),
            sourceRoomId: roomId,
            hint: direction,
            auto: options.manual ? false : true,
            llmGenerated: !fallbackReason,
            fallbackReason
        };
        state.snsPosts.unshift(post);
        try { if (typeof noteSnsPost === 'function') noteSnsPost(character, post); } catch (_) {}
        const messages = state.messages?.[roomId] || [];
        if (character) character.lastSnsMessageCount = messages.length;
        return post;
    };
    // ---------------------------------------------------------------------

    // --- FINAL PLATFORM-SPECIFIC SNS UI / RETENTION FIX ---
    const MG_SNS_POST_LIMIT = 30;

    function mgSnsIdTimestamp(id) {
        const text = String(id || '').toLowerCase().match(/^[0-9a-z]+/)?.[0] || '';
        const min = Date.parse('2020-01-01T00:00:00Z');
        const max = Date.now() + 366 * 86400000;
        for (const length of [8, 9, 10]) {
            if (text.length < length) continue;
            const value = parseInt(text.slice(0, length), 36);
            if (Number.isFinite(value) && value >= min && value <= max) return value;
        }
        return 0;
    }

    snsPostSortTime = function(post) {
        const direct = Number(post?.createdAt || post?.updatedAt || post?.timestamp || 0);
        if (Number.isFinite(direct) && direct > 0) return direct;
        const parsed = Date.parse(post?.createdAt || post?.updatedAt || post?.timestamp || '');
        if (Number.isFinite(parsed) && parsed > 0) return parsed;
        if (typeof timestampFromMakeId === 'function') {
            const fromId = timestampFromMakeId(post?.id);
            if (Number.isFinite(fromId) && fromId > 0) return fromId;
        }
        return mgSnsIdTimestamp(post?.id);
    };

    sortSnsPostsNewestFirst = function(posts) {
        return [...(posts || [])].sort((left, right) => {
            const timeDiff = snsPostSortTime(right) - snsPostSortTime(left);
            if (timeDiff) return timeDiff;
            return String(right?.id || '').localeCompare(String(left?.id || ''));
        });
    };

    function mgPruneSnsPosts(limit = MG_SNS_POST_LIMIT) {
        state.snsPosts = sortSnsPostsNewestFirst(state.snsPosts || []).slice(0, limit);
        return state.snsPosts;
    }

    const mgBaseSaveStateSnsRetention = saveState;
    saveState = async function(...args) {
        mgPruneSnsPosts();
        return mgBaseSaveStateSnsRetention.apply(this, args);
    };

    const mgBaseGenerateSnsPostRetention = generateSnsPost;
    generateSnsPost = async function(...args) {
        const post = await mgBaseGenerateSnsPostRetention.apply(this, args);
        mgPruneSnsPosts();
        return post;
    };

    function mgSnsDisplayTime(post, item = null) {
        const explicit = String(item?.time || '').trim();
        if (explicit && explicit !== 'now') return explicit;
        const timestamp = snsPostSortTime(post) || Date.now();
        const diff = Math.max(0, Date.now() - timestamp);
        if (diff < 60000) return 'now';
        if (diff < 3600000) return `${Math.floor(diff / 60000)}m`;
        if (diff < 86400000) return `${Math.floor(diff / 3600000)}h`;
        const date = new Date(timestamp);
        return date.toLocaleDateString([], { month: 'short', day: 'numeric' });
    }

    function mgSnsHandle(item, character) {
        return String(item?.handle || character?.handle || character?.id || 'character').replace(/^@/, '');
    }

    function mgSnsStats(item, post = null) {
        const stats = item?.stats && typeof item.stats === 'object' ? item.stats : {};
        return {
            likes: Number(stats.likes) || Number(post?.likes) || 0,
            replies: Number(stats.replies) || (Array.isArray(item?.comments) ? item.comments.length : 0),
            reposts: Number(stats.reposts) || Number(stats.retweets) || 0,
            bookmarks: Number(stats.bookmarks) || 0,
            views: Number(stats.views) || 0
        };
    }

    function mgSnsCommentText(comment) {
        if (typeof mgV12CommentText === 'function') return mgV12CommentText(comment);
        return String(comment?.body || comment?.text || comment?.comment || comment?.content || '').trim();
    }

    function mgSnsCommentName(comment, character) {
        try { if (typeof mgSnsV4CommentDisplayName === 'function') return mgSnsV4CommentDisplayName(comment, character); } catch (_) {}
        if (comment?.isUser) return userNameFor(character || {});
        if (comment?.isCharacter) return character?.name || comment?.name || 'Character';
        return comment?.name || comment?.nick || '익명';
    }

    function mgSnsCommentHandle(comment, character) {
        try { if (typeof mgSnsV4CommentHandle === 'function') return mgSnsV4CommentHandle(comment, character); } catch (_) {}
        return String(comment?.handle || '').replace(/^@/, '');
    }

    function mgSnsCommentEntriesForRender(item) {
        try {
            if (typeof mgV12CommentEntries === 'function') return mgV12CommentEntries(item) || [];
            if (typeof mgV11AllCommentEntries === 'function') return mgV11AllCommentEntries(item) || [];
        } catch (_) {}
        return (Array.isArray(item?.comments) ? item.comments : []).map((comment, originalIndex) => ({ comment, originalIndex }));
    }

    function mgSnsReplyCount(item, post, character) {
        try { if (typeof mgV12EnsureGeneratedCommentCount === 'function') return mgV12EnsureGeneratedCommentCount(item, post, character); } catch (_) {}
        return mgSnsCommentEntriesForRender(item).length;
    }

    function mgSnsHashtagsHtml(item, className = 'mg-platform-tags') {
        const tags = (Array.isArray(item?.hashtags) ? item.hashtags : [])
            .map(tag => String(tag || '').trim())
            .filter(Boolean)
            .slice(0, 4);
        if (!tags.length) return '';
        return `<div class="${className}">${tags.map(tag => `<span>${escapeHtml(tag.startsWith('#') ? tag : `#${tag}`)}</span>`).join('')}</div>`;
    }

    function mgSnsImageHtml(post, item, index, className) {
        const rawImage = item?.image || post?.image || '';
        if (!rawImage) return '';
        const image = mediaDisplayUrl(rawImage, `sns-${post.id}-${index}`);
        return `<img class="mg-post-img ${className}" loading="lazy" decoding="async" src="${escapeHtml(image)}" alt="" data-action="open-sns-image" data-id="${escapeHtml(post.id)}" data-index="${index}">`;
    }

    function mgSnsEmptyAvatarSvg() {
        return "data:image/svg+xml,%3Csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24' fill='%23c0c0c0'%3E%3Cpath d='M12 12a5 5 0 1 0 0-10 5 5 0 0 0 0 10zm0 2c-5.33 0-8 2.67-8 8h16c0-5.33-2.67-8-8-8z'/%3E%3C/svg%3E";
    }

    function mgSnsCommentAvatarHtml(comment, character) {
        if (comment?.isCharacter) return avatarHtml(character, 'small');
        if (comment?.isUser && typeof userAvatarHtml === 'function') {
            try { 
                const ua = userAvatarHtml('small'); 
                if (ua) return ua;
            } catch (_) {}
        }
        return `<div class="mg-avatar"><img src="${mgSnsEmptyAvatarSvg()}" alt="" style="width:100%;height:100%;object-fit:cover;border-radius:50%;background:#f0f0f0"></div>`;
    }

    function mgSnsXCommentsHtml(post, item, index, character) {
        const entries = mgSnsCommentEntriesForRender(item);
        if (!entries.length) return '';
        return `<div class="mg-x-thread" data-post-id="${escapeHtml(post.id)}" data-index="${index}" data-comment-total="${entries.length}">${entries.map(entry => {
            const comment = entry.comment || {};
            const body = comment.pending ? (mgSnsCommentText(comment) || '답글 쓰는 중...') : mgSnsCommentText(comment);
            if (!body && !comment.pending) return '';
            const name = mgSnsCommentName(comment, character);
            const handle = mgSnsCommentHandle(comment, character);
            const roleClass = comment.isUser ? ' is-user' : comment.isCharacter ? ' is-character' : '';
            const avatar = mgSnsCommentAvatarHtml(comment, character);
            return `<article class="mg-x-reply${roleClass}${comment.pending ? ' is-pending' : ''}" data-sns-comment="${escapeHtml(post.id)}-${index}-${entry.originalIndex}"><div class="mg-x-reply-avatar">${avatar}<div class="mg-x-thread-line"></div></div><div class="mg-x-reply-content"><div class="mg-x-reply-meta"><strong>${escapeHtml(name)}</strong>${handle ? `<span>@${escapeHtml(handle)}</span>` : ''}</div><p>${escapeHtml(body)}</p><div class="mg-x-reply-actions"><button type="button" data-action="focus-sns-comment" data-id="${escapeHtml(post.id)}" data-index="${index}">💬</button><button type="button">🔁</button><button type="button" data-action="like-sns-comment" data-id="${escapeHtml(post.id)}" data-index="${index}" data-comment-index="${entry.originalIndex}">♡ ${Number(comment.likes) || 0}</button><button type="button">📊</button></div></div></article>`;
        }).join('')}</div>`;
    }

    function mgSnsIgCommentsHtml(post, item, index, character) {
        const entries = mgSnsCommentEntriesForRender(item);
        if (!entries.length) return '';
        return `<div class="mg-ig-comments" data-post-id="${escapeHtml(post.id)}" data-index="${index}" data-comment-total="${entries.length}">${entries.map(entry => {
            const comment = entry.comment || {};
            const body = comment.pending ? (mgSnsCommentText(comment) || '댓글 쓰는 중...') : mgSnsCommentText(comment);
            if (!body && !comment.pending) return '';
            const name = mgSnsCommentName(comment, character);
            const roleClass = comment.isUser ? ' is-user' : comment.isCharacter ? ' is-character' : '';
            const avatar = mgSnsCommentAvatarHtml(comment, character);
            return `<div class="mg-ig-comment${roleClass}${comment.pending ? ' is-pending' : ''}" data-sns-comment="${escapeHtml(post.id)}-${index}-${entry.originalIndex}"><div class="mg-ig-comment-avatar">${avatar}</div><div class="mg-ig-comment-body"><p><b>${escapeHtml(name)}</b> ${escapeHtml(body)}</p><div class="mg-ig-comment-meta"><span>${Math.max(1, Number(comment.likes) || 0)}w</span><span>답글 달기</span></div></div><button class="mg-ig-comment-like" type="button" data-action="like-sns-comment" data-id="${escapeHtml(post.id)}" data-index="${index}" data-comment-index="${entry.originalIndex}">♡</button></div>`;
        }).join('')}</div>`;
    }

    twitterPostHtml = function(post, item, index, character) {
        const handle = mgSnsHandle(item, character);
        const stats = mgSnsStats(item, post);
        const commentCount = mgSnsReplyCount(item, post, character);
        const imageHtml = mgSnsImageHtml(post, item, index, 'mg-x-media');
        const displayName = item.displayName || character?.name || 'Character';
        return `<section class="mg-platform-post mg-platform-x"><div class="mg-x-rail">${avatarHtml(character, 'small')}</div><div class="mg-x-main"><header class="mg-x-post-head"><div class="mg-x-author"><strong>${escapeHtml(displayName)}</strong><span>@${escapeHtml(handle)}</span><span>·</span><span>${escapeHtml(mgSnsDisplayTime(post, item))}</span></div><button class="mg-icon mg-x-more" data-action="delete-sns-post" data-id="${escapeHtml(post.id)}">⋯</button></header><p class="mg-x-post-text">${escapeHtml(item.text || '')}</p>${mgSnsHashtagsHtml(item, 'mg-x-tags')}${imageHtml}<nav class="mg-x-actionbar"><button data-action="focus-sns-comment" data-id="${escapeHtml(post.id)}" data-index="${index}"><span>💬</span>${commentCount}</button><button type="button"><span>🔁</span>${stats.reposts}</button><button data-action="like-sns-post" data-id="${escapeHtml(post.id)}"><span>♡</span>${stats.likes}</button><button type="button"><span>📊</span>${stats.views || stats.bookmarks}</button><button class="mg-sns-dm-cta" data-action="open-sns-dm" data-id="${escapeHtml(post.id)}" data-index="${index}"><span>✉️</span></button></nav><div class="mg-x-compose"><div class="mg-x-reply-avatar">${mgSnsCommentAvatarHtml({isUser:true}, character)}</div><input class="mg-field" id="sns-comment-${escapeHtml(post.id)}-${index}" placeholder="답글 게시하기"><button class="mg-btn" data-action="add-sns-comment" data-id="${escapeHtml(post.id)}" data-index="${index}">답글</button></div>${mgSnsXCommentsHtml(post, item, index, character)}</div></section>`;
    };

    instagramPostHtml = function(post, item, index, character) {
        const handle = mgSnsHandle(item, character);
        const stats = mgSnsStats(item, post);
        const commentCount = mgSnsReplyCount(item, post, character);
        const rawImage = item.image || post.image || '';
        const imageHtml = mgSnsImageHtml(post, item, index, 'mg-ig-media');
        const displayName = item.displayName || character?.name || 'Character';
        return `<section class="mg-platform-post mg-platform-ig"><header class="mg-ig-post-head"><div class="mg-ig-author">${avatarHtml(character, 'small')}<div><span class="mg-ig-name">${escapeHtml(displayName)}</span></div></div><div class="mg-ig-time">${escapeHtml(mgSnsDisplayTime(post, item))}</div><button class="mg-icon mg-ig-more" data-action="delete-sns-post" data-id="${escapeHtml(post.id)}">⋯</button></header>${rawImage ? imageHtml : `<div class="mg-ig-text-card"><p>${escapeHtml(item.text || '')}</p></div>`}<nav class="mg-ig-actionbar"><div class="mg-ig-actions-left"><button data-action="like-sns-post" data-id="${escapeHtml(post.id)}">♡</button><button data-action="focus-sns-comment" data-id="${escapeHtml(post.id)}" data-index="${index}">💬</button><button class="mg-sns-dm-cta" data-action="open-sns-dm" data-id="${escapeHtml(post.id)}" data-index="${index}">↗️</button></div><div class="mg-ig-actions-right"><button type="button">🔖</button></div></nav><div class="mg-ig-body"><strong class="mg-ig-likes">좋아요 ${stats.likes}개</strong><div class="mg-ig-caption"><span class="mg-ig-caption-name">${escapeHtml(handle)}</span> ${escapeHtml(item.text || '')}</div>${mgSnsHashtagsHtml(item, 'mg-ig-tags')}<button class="mg-ig-comment-count" data-action="focus-sns-comment" data-id="${escapeHtml(post.id)}" data-index="${index}">댓글 ${commentCount}개 모두 보기</button>${mgSnsIgCommentsHtml(post, item, index, character)}<div class="mg-ig-compose">${mgSnsCommentAvatarHtml({isUser:true}, character)}<input class="mg-field" id="sns-comment-${escapeHtml(post.id)}-${index}" placeholder="댓글 달기..."><button class="mg-btn" data-action="add-sns-comment" data-id="${escapeHtml(post.id)}" data-index="${index}">게시</button></div></div></section>`;
    };

    function mgSnsFeedExportButtonHtml(post, index) {
        return `<button class="mg-sns-feed-export-btn" type="button" title="피드 이미지로 내보내기" data-action="download-sns-post" data-id="${escapeHtml(post.id)}" data-index="${escapeHtml(index)}">피드 이미지</button>`;
    }

    function mgSnsInjectFeedExportButton(html, post, index, platform) {
        if (/data-action=["']download-sns-post["']/.test(html)) return html;
        const button = mgSnsFeedExportButtonHtml(post, index);
        if (platform === 'instagram' && html.includes('<div class="mg-ig-actions-right">')) {
            return html.replace('<div class="mg-ig-actions-right">', `<div class="mg-ig-actions-right">${button}`);
        }
        if (html.includes('<button class="mg-sns-dm-cta"')) {
            return html.replace('<button class="mg-sns-dm-cta"', `${button}<button class="mg-sns-dm-cta"`);
        }
        return html.replace('</nav>', `${button}</nav>`);
    }

    const mgBaseTwitterPostHtmlFeedExport = twitterPostHtml;
    twitterPostHtml = function(post, item, index, character) {
        const renderPost = typeof mgSnsHybridRenderPostForPlatform === 'function' ? mgSnsHybridRenderPostForPlatform(post, item, index) : post;
        return mgSnsInjectFeedExportButton(mgBaseTwitterPostHtmlFeedExport(renderPost, item, index, character), renderPost, index, 'twitter');
    };

    const mgBaseInstagramPostHtmlFeedExport = instagramPostHtml;
    instagramPostHtml = function(post, item, index, character) {
        const renderPost = typeof mgSnsHybridRenderPostForPlatform === 'function' ? mgSnsHybridRenderPostForPlatform(post, item, index) : post;
        return mgSnsInjectFeedExportButton(mgBaseInstagramPostHtmlFeedExport(renderPost, item, index, character), renderPost, index, 'instagram');
    };

    snsPostHtml = function(post) {
        const character = getCharacter(post.characterId) || state.characters[0];
        const platforms = visibleSnsPlatforms(post, character);
        return `<article class="mg-post mg-post-real mg-platform-post-wrap">${platforms.map((item, index) => (item.platform === 'instagram' ? instagramPostHtml : twitterPostHtml)(post, item, index, character)).join('')}</article>`;
    };

    socialHtml = function() {
        const character = currentCharacter() || state.characters[0];
        if (!character) return '<section class="mg-panel mg-social"><div class="mg-empty">캐릭터가 없습니다.</div></section>';
        const sns = typeof snsConfigForCharacter === 'function' ? snsConfigForCharacter(character.id) : { ...DEFAULT_CONFIG.sns, ...(state.config.sns || {}) };
        const posts = mgPruneSnsPosts().filter(post => post.characterId === character.id);
        return `<section class="mg-panel mg-social"><div class="mg-social-head"><div><h2>${escapeHtml(character.name || '캐릭터')} SNS</h2><p>@${escapeHtml(character.handle || character.id || '')} · ${escapeHtml(sns.platform === 'hybrid' ? 'X + Instagram' : platformLabel(sns.platform))} · 최근 ${Math.min(posts.length, MG_SNS_POST_LIMIT)}/${MG_SNS_POST_LIMIT}</p></div><button class="mg-btn primary" data-action="create-sns-post" ${isPosting ? 'disabled' : ''}>${isPosting ? '작성 중...' : 'SNS 생성'}</button></div>${snsComposeHtml(character, sns)}<div class="mg-feed mg-platform-feed">${posts.length ? posts.map(snsPostHtml).join('') : '<div class="mg-empty">이 캐릭터의 SNS 게시물이 아직 없습니다.</div>'}</div></section>`;
    };

    function mgEnsureStyle(id, css) {
        if (!id || typeof document === 'undefined' || !document.head) return null;
        const existing = document.getElementById(id);
        if (existing) return existing;
        const style = document.createElement('style');
        style.id = id;
        style.textContent = String(css || '');
        document.head.appendChild(style);
        return style;
    }

    const mgBaseInjectStylesPlatformSns = injectStyles;
    injectStyles = function() {
        mgBaseInjectStylesPlatformSns();
        if (document.getElementById('mg-platform-sns-style')) return;
        const style = document.createElement('style');
        style.id = 'mg-platform-sns-style';
        style.textContent = `
            .mg-platform-feed{gap:24px!important;width:100%!important;align-items:center!important}.mg-platform-post-wrap{display:grid!important;gap:24px!important;width:100%!important;border:0!important;background:transparent!important;box-shadow:none!important}.mg-platform-post{box-sizing:border-box;overflow:hidden;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,Helvetica,Arial,sans-serif}.mg-platform-post button{font:inherit;cursor:pointer}.mg-platform-post .mg-field{min-width:0;box-sizing:border-box;border:0!important;box-shadow:none!important}.mg-platform-tags,.mg-x-tags,.mg-ig-tags{display:flex;flex-wrap:wrap;gap:4px;min-width:0;margin-top:8px}.mg-platform-tags span,.mg-x-tags span,.mg-ig-tags span{overflow-wrap:anywhere}.mg-avatar img{object-fit:cover!important;border-radius:50%!important}.mg-sns-feed-export-btn{white-space:nowrap!important;border:1px solid currentColor!important;border-radius:999px!important;background:transparent!important;padding:4px 10px!important;font-size:12px!important;font-weight:700!important;line-height:1.2!important}
            .mg-platform-x{display:grid;grid-template-columns:40px minmax(0,1fr);gap:12px;width:100%;max-width:600px;margin:0 auto;padding:16px;background:#000;color:#e7e9ea;border:1px solid #2f3336;border-radius:0}.mg-platform-x .mg-avatar,.mg-x-reply-avatar .mg-avatar{width:40px!important;height:40px!important}.mg-x-post-head{display:flex;justify-content:space-between;align-items:center;margin-bottom:4px}.mg-x-author{display:flex;gap:6px;align-items:center;flex-wrap:wrap;font-size:15px}.mg-x-author strong{font-weight:700;color:#e7e9ea}.mg-x-author span{color:#71767b}.mg-x-more{background:transparent!important;border:0!important;color:#71767b!important;font-size:20px;padding:0;line-height:1}.mg-x-post-text{white-space:pre-wrap;overflow-wrap:anywhere;line-height:1.5;font-size:15px;margin:0 0 12px;color:#e7e9ea}.mg-x-tags span{color:#1d9bf0}.mg-x-media{width:100%;max-height:600px;object-fit:cover;border:1px solid #2f3336;border-radius:16px;margin-bottom:12px}.mg-x-actionbar{display:flex;justify-content:space-between;border-top:1px solid #2f3336;padding:8px 0;border-bottom:1px solid #2f3336}.mg-x-actionbar button{background:transparent;border:0;color:#71767b;font-size:13px;display:flex;align-items:center;gap:6px;transition:color 0.2s}.mg-x-actionbar button span{font-size:16px}.mg-x-actionbar button:hover{color:#1d9bf0}.mg-x-actionbar button[data-action="like-sns-post"]:hover{color:#f91880}.mg-x-compose{display:grid;grid-template-columns:30px minmax(0,1fr) auto;gap:10px;align-items:center;padding:12px 0 0}.mg-x-compose .mg-avatar{width:30px!important;height:30px!important}.mg-x-compose .mg-field{background:transparent!important;border:0!important;color:#e7e9ea!important;font-size:15px;padding:0}.mg-x-compose .mg-btn{background:#1d9bf0!important;border:0!important;color:#fff!important;border-radius:999px!important;font-weight:700;padding:6px 16px;font-size:14px}.mg-x-thread{display:grid;gap:0;padding-top:4px}.mg-x-reply{display:grid;grid-template-columns:30px minmax(0,1fr);gap:10px;padding:12px 0;border-bottom:1px solid #2f3336}.mg-x-reply:last-child{border-bottom:0}.mg-x-reply-avatar{display:flex;flex-direction:column;align-items:center;gap:4px}.mg-x-reply-avatar .mg-avatar{width:30px!important;height:30px!important}.mg-x-thread-line{flex:1;width:2px;background:#333639;margin-top:4px;min-height:20px}.mg-x-reply-content{min-width:0}.mg-x-reply-meta{display:flex;gap:5px;align-items:center;font-size:14px}.mg-x-reply-meta strong{font-weight:700;color:#e7e9ea}.mg-x-reply-meta span{color:#71767b}.mg-x-reply-content p{margin:4px 0 8px;white-space:pre-wrap;overflow-wrap:anywhere;line-height:1.45;font-size:14px}.mg-x-reply-actions{display:flex;gap:16px}.mg-x-reply-actions button{background:transparent;border:0;padding:0;color:#71767b;font-size:12px;display:flex;align-items:center;gap:4px}
            .mg-platform-ig{width:100%;max-width:640px;margin:0 auto;background:#fff;color:#000;border:1px solid #dbdbdb;border-radius:3px;padding-bottom:10px}.mg-ig-post-head{display:flex;justify-content:space-between;align-items:center;padding:10px 12px}.mg-ig-author{display:flex;gap:10px;align-items:center}.mg-ig-author .mg-avatar{width:32px!important;height:32px!important;background:linear-gradient(45deg,#f09433,#e6683c,#dc2743,#cc2366,#bc1888);padding:2px;display:flex;align-items:center;justify-content:center}.mg-ig-author .mg-avatar img{border:2px solid #fff;width:100%;height:100%;border-radius:50%}.mg-ig-name{font-weight:600;font-size:14px;color:#262626}.mg-ig-time{font-size:12px;color:#8e8e8e}.mg-ig-more{background:transparent!important;border:0!important;color:#262626!important;font-size:18px;padding:0}.mg-ig-media{display:block;width:100%;max-height:760px;object-fit:cover}.mg-ig-text-card{width:100%;aspect-ratio:4/5;background:linear-gradient(135deg,#fdfbfb 0%,#ebedee 100%);display:flex;align-items:center;justify-content:center;padding:30px;box-sizing:border-box}.mg-ig-text-card p{font-size:20px;font-weight:600;text-align:center;margin:0;line-height:1.4;color:#262626;overflow-wrap:anywhere}.mg-ig-actionbar{display:flex;justify-content:space-between;align-items:center;padding:6px 12px 8px}.mg-ig-actions-left,.mg-ig-actions-right{display:flex;align-items:center;gap:14px}.mg-ig-actionbar button{background:transparent;border:0;color:#262626;font-size:22px;padding:4px 0 0}.mg-ig-actionbar .mg-sns-feed-export-btn{color:#262626!important;font-size:12px!important;padding:5px 10px!important}.mg-x-actionbar .mg-sns-feed-export-btn{color:#71767b!important}.mg-x-actionbar .mg-sns-feed-export-btn:hover{color:#1d9bf0!important}.mg-ig-body{padding:0 12px}.mg-ig-likes{display:block;font-weight:600;font-size:14px;margin-bottom:6px;color:#262626}.mg-ig-caption{font-size:14px;line-height:1.5;white-space:pre-wrap;overflow-wrap:anywhere;margin-bottom:8px;color:#262626}.mg-ig-caption-name{font-weight:600}.mg-ig-tags span{color:#00376b}.mg-ig-comment-count{display:block;border:0;background:transparent;color:#8e8e8e;font-size:14px;padding:0;margin-bottom:6px}.mg-ig-comments{display:flex;flex-direction:column;gap:8px;max-height:300px;overflow-y:auto;margin-bottom:10px}.mg-ig-comment{display:flex;gap:10px;align-items:flex-start}.mg-ig-comment-avatar{flex:0 0 auto}.mg-ig-comment-avatar .mg-avatar{width:28px!important;height:28px!important;background:none;padding:0}.mg-ig-comment-avatar .mg-avatar img{border:none}.mg-ig-comment-body{flex:1 1 auto;min-width:0}.mg-ig-comment-body p{margin:0 0 4px;font-size:14px;line-height:1.4;white-space:pre-wrap;overflow-wrap:anywhere;color:#262626}.mg-ig-comment-body p b{font-weight:600}.mg-ig-comment-meta{display:flex;gap:12px;font-size:12px;color:#8e8e8e}.mg-ig-comment-like{background:transparent;border:0;color:#8e8e8e;font-size:14px;padding:0 4px}.mg-ig-compose{display:flex;align-items:center;gap:12px;border-top:1px solid #efefef;padding-top:12px;padding-bottom:6px}.mg-ig-compose .mg-avatar{width:28px!important;height:28px!important;flex:0 0 auto;background:none;padding:0}.mg-ig-compose .mg-avatar img{border:none}.mg-ig-compose .mg-field{flex:1 1 auto;border:0!important;background:transparent!important;font-size:14px;padding:0;color:#262626!important}.mg-ig-compose .mg-btn{flex:0 0 auto;background:transparent!important;border:0!important;color:#0095f6!important;font-weight:600!important;padding:0}
            @media(max-width:780px){.mg-platform-feed{gap:12px!important}.mg-platform-x,.mg-platform-ig{width:100%;border-left:0!important;border-right:0!important;border-radius:0!important;padding-left:12px;padding-right:12px}.mg-social .mg-feed{width:100%!important}}
        `;
        document.head.appendChild(style);
    };

    // --- FINAL PROFILE COVER PROMPT / CHARACTER COLOR PALETTE FIX ---
    const MG_PERSONLESS_COVER_PROMPT = 'masterpiece, best quality, amazing quality, very aesthetic, highres, ultra detailed background, scenery, landscape, no humans, empty scene, personless, empty landscape, wide shot, establishing shot, environmental shot, wallpaper, profile banner, atmospheric lighting, natural light, cinematic composition, depth of field, detailed sky, clouds, architecture, interior, street, nature, no text, no logo, no watermark, no signature, no face, no portrait, no character, no body';
    const MG_PERSONLESS_COVER_NEGATIVE_PROMPT = 'human, humans, person, people, character, girl, boy, woman, man, male, female, 1girl, 1boy, solo, face, portrait, selfie, upper body, full body, body, head, hair, eyes, hands, fingers, crowd, text, logo, watermark, signature';
    const MG_PROFILE_AVATAR_DEFAULT_PROMPT = 'portrait profile photo, clear face, casual expression, messenger profile picture';

    function mgNormalizePromptText(value) {
        return String(value || '').replace(/\s+/g, ' ').trim().toLowerCase();
    }

    function mgIsLegacyProfileCoverPrompt(value) {
        const text = mgNormalizePromptText(value);
        return !text || text === 'wide messenger profile background photo, atmospheric room or place, no text, no logo' || text === 'messenger profile cover/background for character';
    }

    function mgStripHumanCoverTags(value) {
        const blocked = /^(?:1girl|1boy|1female|1male|girl|boy|male|female|woman|man|person|people|human|solo|portrait|selfie|face|close-up|upper body|full body|looking at viewer|standing|sitting|white hair|black hair|blonde hair|brown hair|red hair|blue hair|green hair|pink hair|silver hair|long hair|short hair|hair|blue eyes|green eyes|brown eyes|red eyes|yellow eyes|eyes)$/i;
        return String(value || '')
            .replace(/[\r\n]+/g, ', ')
            .split(',')
            .map(part => part.trim())
            .filter(Boolean)
            .filter(part => !blocked.test(part))
            .join(', ');
    }

    function mgPersonlessProfileCoverPrompt(character, rawPrompt = '') {
        const userPrompt = mgIsLegacyProfileCoverPrompt(rawPrompt) ? '' : mgStripHumanCoverTags(rawPrompt);
        const locationHint = character?.locationName ? `ambient place mood near ${String(character.locationName).replace(/[{}[\]"']/g, ' ').replace(/\s+/g, ' ').slice(0, 80)}` : '';
        return dedupeCommaPrompt([
            MG_PERSONLESS_COVER_PROMPT,
            userPrompt,
            locationHint
        ]);
    }

    function mgIsProfileCoverItem(item) {
        return item?.profileMediaKind === 'cover' || String(item?.imageCaption || '').toLowerCase() === 'profile cover';
    }

    const mgBaseLooksLikeTagPromptPersonlessCover = looksLikeTagPrompt;
    looksLikeTagPrompt = function(prompt) {
        const text = String(prompt || '');
        if (/\b(no humans|scenery|landscape|empty scene|personless|profile banner|wallpaper)\b/i.test(text) && (text.match(/,/g) || []).length >= 8) return true;
        return mgBaseLooksLikeTagPromptPersonlessCover(prompt);
    };

    const mgBasePrepareImagePromptPersonlessCover = prepareImagePrompt;
    prepareImagePrompt = async function(character, item, config = state.config.imageGeneration || {}) {
        if (mgIsProfileCoverItem(item)) {
            const prompt = ensureNsfwTag(mgPersonlessProfileCoverPrompt(character, item.imagePrompt || character?.profileCoverPrompt || ''), config);
            item.finalImagePrompt = prompt;
            logDebug('profile-cover-personless-prompt', `${character?.name || 'character'} profile cover final prompt`, { prompt });
            return prompt;
        }
        return mgBasePrepareImagePromptPersonlessCover(character, item, config);
    };

    const mgBaseCallImageGenerationPersonlessCover = callImageGeneration;
    callImageGeneration = async function(character, item) {
        if (!mgIsProfileCoverItem(item)) return mgBaseCallImageGenerationPersonlessCover(character, item);
        const config = state.config.imageGeneration || {};
        const previousNegative = config.negativePrompt;
        const previousPreset = config.selectedLightboardPreset;
        item.profileMediaKind = 'cover';
        try {
            config.negativePrompt = dedupeCommaPrompt([MG_PERSONLESS_COVER_NEGATIVE_PROMPT, previousNegative || DEFAULT_CONFIG.imageGeneration.negativePrompt || '']);
            config.selectedLightboardPreset = '';
            return await mgBaseCallImageGenerationPersonlessCover(character, item);
        } finally {
            config.negativePrompt = previousNegative;
            config.selectedLightboardPreset = previousPreset;
        }
    };

    const mgBaseEnsureCharacterProfileFieldsPersonlessCover = mgEnsureCharacterProfileFields;
    mgEnsureCharacterProfileFields = function(character) {
        const result = mgBaseEnsureCharacterProfileFieldsPersonlessCover(character);
        if (!result) return result;
        if (mgIsLegacyProfileCoverPrompt(result.profileCoverPrompt)) result.profileCoverPrompt = MG_PERSONLESS_COVER_PROMPT;
        if (typeof result.profileAvatarPrompt !== 'string' || !result.profileAvatarPrompt.trim()) result.profileAvatarPrompt = MG_PROFILE_AVATAR_DEFAULT_PROMPT;
        return result;
    };

    const mgBaseProfileFormValuesPersonlessCover = mgProfileFormValues;
    mgProfileFormValues = function() {
        const values = mgBaseProfileFormValuesPersonlessCover() || {};
        if (document.getElementById('char-profile-avatar-prompt')) values.profileAvatarPrompt = valueOf('char-profile-avatar-prompt') || MG_PROFILE_AVATAR_DEFAULT_PROMPT;
        if (document.getElementById('char-profile-cover-prompt')) values.profileCoverPrompt = valueOf('char-profile-cover-prompt') || MG_PERSONLESS_COVER_PROMPT;
        return values;
    };

    const mgBaseProfileMediaPromptPersonlessCover = mgProfileMediaPrompt;
    mgProfileMediaPrompt = function(character, kind) {
        if (kind === 'cover') {
            mgEnsureCharacterProfileFields(character);
            return mgPersonlessProfileCoverPrompt(character, character?.profileCoverPrompt || '');
        }
        return mgBaseProfileMediaPromptPersonlessCover(character, kind);
    };

    const mgBaseProfileGenerationCharacterPersonlessCover = mgProfileGenerationCharacter;
    mgProfileGenerationCharacter = function(character, kind) {
        if (kind !== 'cover') return mgBaseProfileGenerationCharacterPersonlessCover(character, kind);
        const base = mgBaseProfileGenerationCharacterPersonlessCover(character, kind) || character || {};
        return {
            ...base,
            prompt: `Create a messenger profile cover image as a personless landscape, room, street, sky, nature, architecture, or object-focused background only. Absolutely no humans, no face, no body, no portrait, no character. Use Danbooru-style scenery tags. ${character?.profileCoverPrompt || ''}`,
            illustrationTags: ''
        };
    };

    async function mgSaveProfilePromptsFromForm() {
        const character = mgEnsureCharacterProfileFields(currentCharacter() || mgBotProfileCharacter());
        if (!character) return;
        mgApplyProfileFormValues(character, mgProfileFormValues());
        if (mgIsLegacyProfileCoverPrompt(character.profileCoverPrompt)) character.profileCoverPrompt = MG_PERSONLESS_COVER_PROMPT;
        await saveState();
        if (typeof flushSaveState === 'function') await flushSaveState();
        showTransientNotice('프로필 사진 프롬프트가 저장됐습니다.');
        render();
    }

    const mgBaseRegenerateProfileMediaPersonlessCover = mgRegenerateProfileMedia;
    mgRegenerateProfileMedia = async function(kind = 'all') {
        const character = mgEnsureCharacterProfileFields(currentCharacter() || mgBotProfileCharacter());
        if (character) {
            mgApplyProfileFormValues(character, mgProfileFormValues());
            if (mgIsLegacyProfileCoverPrompt(character.profileCoverPrompt)) character.profileCoverPrompt = MG_PERSONLESS_COVER_PROMPT;
            await saveState();
        }
        return mgBaseRegenerateProfileMediaPersonlessCover(kind);
    };

    mgProfileMediaPanelHtml = function(character) {
        mgEnsureCharacterProfileFields(character);
        const aiHelp = state.config.imageGeneration?.enabled ? '배경사진은 사람 없는 풍경/실내/거리/하늘용 Danbooru 태그로 고정해 생성합니다.' : '이미지 생성 설정이 꺼져 있어 사진 AI 생성 버튼은 비활성화됩니다.';
        return `<div class="mg-profile-media-panel"><div class="mg-inline" style="justify-content:space-between"><h3>프로필 / 상태 AI</h3><span class="mg-inline"><button class="mg-btn" data-action="regenerate-profile-media" data-kind="status" ${mgProfileMediaBusyIds.has(`${character.id}:status`) ? 'disabled' : ''}>${mgProfileMediaBusyIds.has(`${character.id}:status`) ? '생성 중...' : '상태 직접 AI 생성'}</button><button class="mg-btn primary" data-action="regenerate-profile-media" data-kind="all" ${state.config.imageGeneration?.enabled && !mgProfileMediaBusyIds.has(`${character.id}:all`) ? '' : 'disabled'}>${mgProfileMediaBusyIds.has(`${character.id}:all`) ? '생성 중...' : '상태+사진 직접 AI 생성'}</button></span></div>${mgProfileAutoControlsHtml(character)}<div class="mg-profile-media-grid">${mgProfileThumbHtml(character, 'avatar')}${mgProfileThumbHtml(character, 'cover')}</div><div class="mg-grid">${textareaHtml('char-profile-avatar-prompt', '프로필사진 프롬프트', character.profileAvatarPrompt || MG_PROFILE_AVATAR_DEFAULT_PROMPT)}${textareaHtml('char-profile-cover-prompt', '배경사진 프롬프트', character.profileCoverPrompt || MG_PERSONLESS_COVER_PROMPT)}</div><div class="mg-inline mg-profile-prompt-actions" style="justify-content:flex-end"><button class="mg-btn" type="button" data-action="save-profile-prompts">프롬프트 적용/저장</button><button class="mg-btn" type="button" data-action="regenerate-profile-media" data-kind="cover" ${state.config.imageGeneration?.enabled && !mgProfileMediaBusyIds.has(`${character.id}:cover`) ? '' : 'disabled'}>배경사진만 재생성</button></div><p class="mg-help">${escapeHtml(aiHelp)} 새 AI 사진은 AI 슬롯만, 직접 넣은 사진은 직접 슬롯만 교체하고 각 슬롯은 최근 1개만 남깁니다.</p></div>`;
    };

    const MG_CHARACTER_COLOR_SWATCHES = [
        ['#8bd3dd','민트'],['#7cc7ff','스카이'],['#5aa9e6','블루'],['#7b8cff','인디고'],['#9d7bea','바이올렛'],['#c084fc','라일락'],
        ['#f0a6ca','핑크'],['#ff7aa2','로즈'],['#e85d75','체리'],['#ff8fab','코랄'],['#f6a04d','오렌지'],['#f6c177','앰버'],
        ['#f9e076','레몬'],['#d7e9b8','라임'],['#95d5b2','세이지'],['#52b788','그린'],['#2dd4bf','틸'],['#90dbf4','아쿠아'],
        ['#b8c0ff','페리윙클'],['#cdb4db','모브'],['#ffc8dd','블러시'],['#ffd6a5','피치'],['#fdffb6','버터'],['#caffbf','파스텔 그린'],
        ['#a0c4ff','베이비 블루'],['#bdb2ff','라벤더'],['#ffffff','화이트'],['#cbd5e1','실버'],['#64748b','슬레이트'],['#111827','차콜']
    ];

    function mgCharacterColorPaletteHtml(character) {
        const color = mgColorHex(character?.color || '#8bd3dd', '#8bd3dd');
        return `<label class="mg-field-wrap mg-color-field mg-character-color-field" data-color-field="char-color"><span class="mg-label">색상</span><span class="mg-color-row"><input class="mg-field mg-color-text" id="char-color" type="text" value="${escapeHtml(color)}" placeholder="#8bd3dd" spellcheck="false"><input class="mg-color-picker" id="char-color-picker" type="color" value="${escapeHtml(color)}"></span><span class="mg-character-color-palette">${MG_CHARACTER_COLOR_SWATCHES.map(([hex, name]) => `<button class="mg-color-swatch mg-character-color-swatch" type="button" title="${escapeHtml(name)}" aria-label="${escapeHtml(name)}" data-mg-color-target="char-color" data-mg-color-value="${escapeHtml(hex)}" style="background:${escapeHtml(hex)}"></button>`).join('')}</span><span class="mg-help">색상은 HEX 직접 입력, 브라우저 컬러피커, 아래 팔레트 중 아무 방식으로 고를 수 있습니다.</span></label>`;
    }

    const mgBaseCharacterEditorHtmlColorPalette = characterEditorHtml;
    characterEditorHtml = function(character) {
        let html = mgBaseCharacterEditorHtmlColorPalette(character);
        if (!character || html.includes('mg-character-color-field')) return html;
        return String(html).replace(/<label class="mg-field-wrap">(?:(?!<\/label>)[\s\S])*id="char-color"(?:(?!<\/label>)[\s\S])*<\/label>/, mgCharacterColorPaletteHtml(character));
    };

    const mgBaseSaveCharacterColorPalette = saveCharacterFromForm;
