    function mgSaveVisibleLoreEntriesFromForm() {
        if (activeTab !== 'lorebook') return 0;
        const buttons = Array.from(document.querySelectorAll('[data-action="save-lore-entry"][data-id]'));
        if (!buttons.length) return 0;
        ensureLoreState();
        let saved = 0;
        for (const button of buttons) {
            const id = button.dataset.id;
            const entry = state.loreEntries.find(item => item.id === id);
            if (!entry || !document.getElementById(`lore-title-${id}`)) continue;
            entry.title = valueOf(`lore-title-${id}`) || entry.title;
            entry.key = valueOf(`lore-key-${id}`);
            entry.keys = splitLoreKeys(entry.key);
            entry.secondkey = valueOf(`lore-second-${id}`);
            entry.comment = valueOf(`lore-comment-${id}`) || 'mgod_lore';
            entry.content = valueOf(`lore-content-${id}`);
            entry.scope = document.getElementById(`lore-scope-${id}`)?.value || 'global';
            entry.characterId = document.getElementById(`lore-character-${id}`)?.value || '';
            entry.roomId = document.getElementById(`lore-room-${id}`)?.value || '';
            if (entry.scope === 'room' && entry.roomId) entry.characterId = getRoomById(entry.roomId)?.characterId || entry.characterId;
            if (entry.scope !== 'room') entry.roomId = '';
            entry.insertorder = Number(valueOf(`lore-order-${id}`)) || 100;
            entry.alwaysActive = Boolean(document.getElementById(`lore-always-${id}`)?.checked);
            entry.selective = Boolean(document.getElementById(`lore-selective-${id}`)?.checked);
            entry.useRegex = Boolean(document.getElementById(`lore-regex-${id}`)?.checked);
            entry.enabled = Boolean(document.getElementById(`lore-enabled-${id}`)?.checked);
            saved += 1;
        }
        return saved;
    }

