    function mgPromptInfo(value, limit = 220) {
        return String(value || '')
            .replace(/[\r\n]+/g, ' ')
            .replace(/[{}[\]"']/g, ' ')
            .replace(/\b(?:1girl|1boy|girl|boy|woman|man|male|female|human|person|people|solo|face|portrait|selfie|upper body|full body|body|head|hair|eyes|hands|fingers|looking at viewer)\b/gi, ' ')
            .replace(/\s+/g, ' ')
            .trim()
            .slice(0, limit);
    }

    function mgIsOldGenericCoverPrompt(value) {
        const text = mgNormalizePromptText(value);
        const previous = mgNormalizePromptText(MG_PERSONLESS_COVER_PROMPT);
        return !text || text === previous || mgIsLegacyProfileCoverPrompt(value) || (text.includes('ultra detailed background') && text.includes('empty landscape') && text.includes('profile banner'));
    }

    function mgSeasonalCoverHint() {
        const month = new Date().getMonth() + 1;
        if (month === 12) return 'optional seasonal detail if it fits: christmas lights, winter street, warm empty room, holiday decorations';
        if (month <= 2) return 'optional seasonal detail if it fits: snow, cold air, winter night, quiet indoor warmth';
        if (month <= 5) return 'optional seasonal detail if it fits: spring flowers, fresh rain, early summer light, green street';
        if (month <= 8) return 'optional seasonal detail if it fits: summer evening, bright sky, ocean air, humid city lights';
        return 'optional seasonal detail if it fits: autumn leaves, late afternoon light, cozy room, quiet street';
    }

    function mgDefaultDiverseProfileCoverPrompt(character) {
        const name = mgPromptInfo(character?.name || 'this character', 60) || 'this character';
        return `personless messenger profile cover background for ${name}, a distinctive place or meaningful object that fits this character, no humans, no people, no face, no body, no portrait, no character, no text, no logo`;
    }

    function mgDiversePersonlessProfileCoverPrompt(character, rawPrompt = '') {
        const customPrompt = mgIsOldGenericCoverPrompt(rawPrompt) ? '' : mgStripHumanCoverTags(rawPrompt);
        const characterClues = [
            character?.profileMessage ? `profile mood: ${mgPromptInfo(character.profileMessage, 120)}` : '',
            character?.statusMessage ? `current status mood: ${mgPromptInfo(character.statusMessage, 120)}` : '',
            character?.prompt ? `lifestyle and personality clues: ${mgPromptInfo(character.prompt, 260)}` : '',
            character?.locationName ? `location mood: ${mgPromptInfo(character.locationName, 80)}` : ''
        ].filter(Boolean).join(', ');
        return dedupeCommaPrompt([
            customPrompt,
            mgDefaultDiverseProfileCoverPrompt(character),
            characterClues,
            mgSeasonalCoverHint(),
            'choose one concrete personless scene, possible subjects include luxury mansion interior, apartment doorway, roadside flowers, empty classroom, cafe table, train window, shrine steps, ocean pier, laboratory desk, snowy street, christmas lights, rainy alley, city rooftop, bookstore shelf, garden path, night bedroom',
            'focus on environment, belongings, architecture, weather, colors, lighting, props, make it specific and different from other characters, avoid generic landscape, avoid plain sky',
            'wide banner composition, atmospheric, detailed, no humans, no people, no face, no body, no portrait, no character, no silhouette, no crowd, no text, no logo, no watermark'
        ]);
    }

