    instagramPostHtml = function(post, item, index, character) {
        const handle = mgSnsHandle(item, character);
        const stats = mgSnsStats(item, post);
        const commentCount = mgSnsReplyCount(item, post, character);
        const displayName = item.displayName || character?.name || 'Character';
        const rawImage = String(item?.image || post?.image || '').trim();
        const imageHtml = rawImage ? mgSnsImageHtml(post, item, index, 'mg-ig-media') : '';
        const feedButton = typeof mgSnsFeedExportButtonHtml === 'function' ? mgSnsFeedExportButtonHtml(post, index) : '';
        const text = String(item?.text || '').trim();
        const textBlock = text ? `<div class="mg-ig-caption mg-ig-main-text">${escapeHtml(text)}</div>` : '';
        return `<section class="mg-platform-post mg-platform-ig ${rawImage ? 'mg-ig-image-post' : 'mg-ig-caption-post'}">
            <header class="mg-ig-post-head">
                <div class="mg-ig-author">${avatarHtml(character, 'small')}<div class="mg-ig-author-copy"><span class="mg-ig-name">${escapeHtml(displayName)}</span><small>@${escapeHtml(handle)}</small><time>${escapeHtml(mgSnsDisplayTime(post, item))}</time></div></div>
                <button class="mg-icon mg-ig-more" data-action="delete-sns-post" data-id="${escapeHtml(post.id)}">⋯</button>
            </header>
            ${imageHtml}
            <div class="mg-ig-body">
                ${textBlock}
                ${mgSnsHashtagsHtml(item, 'mg-ig-tags')}
                <nav class="mg-ig-actionbar">
                    <div class="mg-ig-actions-left">
                        <button data-action="like-sns-post" data-id="${escapeHtml(post.id)}" aria-label="좋아요">♡</button>
                        <button data-action="focus-sns-comment" data-id="${escapeHtml(post.id)}" data-index="${index}" aria-label="댓글">💬</button>
                        <button class="mg-sns-dm-cta" data-action="open-sns-dm" data-id="${escapeHtml(post.id)}" data-index="${index}" aria-label="DM">↗</button>
                    </div>
                    <div class="mg-ig-actions-right">${feedButton}<button type="button" aria-label="저장">⌑</button></div>
                </nav>
                <strong class="mg-ig-likes">좋아요 ${stats.likes}개</strong>
                <button class="mg-ig-comment-count" data-action="focus-sns-comment" data-id="${escapeHtml(post.id)}" data-index="${index}">댓글 ${commentCount}개 모두 보기</button>
                ${mgSnsIgCommentsHtml(post, item, index, character)}
                <div class="mg-ig-compose">${mgSnsCommentAvatarHtml({isUser:true}, character)}<input class="mg-field" id="sns-comment-${escapeHtml(post.id)}-${index}" placeholder="댓글 달기..."><button class="mg-btn" data-action="add-sns-comment" data-id="${escapeHtml(post.id)}" data-index="${index}">게시</button></div>
            </div>
        </section>`;
    };

