    function mgSumGodState() {
        state.config.sumGod = state.config.sumGod && typeof state.config.sumGod === 'object' ? state.config.sumGod : {};
        const sum = state.config.sumGod;
        sum.characterId = String(sum.characterId || '');
        sum.entries = Array.isArray(sum.entries) ? sum.entries : [];
        sum.view = sum.view || 'today';
        return sum;
    }

    function mgSumGodCharacter() {
        const sum = mgSumGodState();
        return getCharacter(sum.characterId) || state.characters?.[0] || null;
    }

    function mgSumGodQuestionNumber() {
        return Math.min(MG_SUMGOD_QUESTIONS.length, mgSumGodState().entries.length + 1);
    }

    function mgSumGodTodayKey() {
        const now = new Date();
        return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;
    }

    function mgSumGodAvailableNow() {
        const now = new Date();
        return now.getHours() >= 22 || mgSumGodState().entries.length === 0;
    }

    function mgSumGodActiveEntry() {
        const sum = mgSumGodState();
        return sum.entries.find(entry => !entry.userAnswer || !entry.characterAnswer) || null;
    }

    function mgSumGodTodayDone() {
        const sum = mgSumGodState();
        return sum.entries.some(entry => entry.completedOn === mgSumGodTodayKey());
    }

    function mgSumGodBadgeCount() {
        const active = mgSumGodActiveEntry();
        if (active && !active.characterAnswer) return 1;
        if (!mgSumGodTodayDone() && mgSumGodAvailableNow() && mgSumGodQuestionNumber() <= MG_SUMGOD_QUESTIONS.length) return 1;
        return 0;
    }

    function mgSumGodCurrentEntry(create = false) {
        const sum = mgSumGodState();
        const active = mgSumGodActiveEntry();
        if (active || !create) return active;
        const number = mgSumGodQuestionNumber();
        if (number > MG_SUMGOD_QUESTIONS.length) return null;
        const entry = {
            id: makeId(),
            number,
            question: MG_SUMGOD_QUESTIONS[number - 1],
            unlockedOn: mgSumGodTodayKey(),
            userAnswer: '',
            characterAnswer: '',
            conversation: [],
            createdAt: Date.now()
        };
        sum.entries.push(entry);
        return entry;
    }

    function mgSumGodResetForCharacter(characterId) {
        const sum = mgSumGodState();
        sum.characterId = String(characterId || '');
        sum.entries = [];
        sum.view = 'today';
    }

    function mgSumGodRecentContext(character) {
        const roomId = state.chatRooms?.[character.id]?.[0]?.id || '';
        const rows = (state.messages?.[roomId] || []).slice(-24).map(message => {
            const who = message.role === 'user' ? userNameFor(character) : character.name || 'Character';
            return `${who}: ${message.content || mediaLabel(message) || ''}`;
        }).filter(line => line.trim());
        return rows.join('\n') || '(no recent messenger context)';
    }

    async function mgGenerateSumGodCharacterAnswer(entry) {
        const character = mgSumGodCharacter();
        if (!character) throw new Error('SumGod character is not selected.');
        const previous = mgSumGodState().entries
            .filter(item => item.id !== entry.id && item.userAnswer && item.characterAnswer)
            .slice(-5)
            .map(item => `Q.${item.number} ${item.question}\nUser: ${item.userAnswer}\n${character.name}: ${item.characterAnswer}`)
            .join('\n\n') || '(none)';
        const prompt = [
            `You are ${character.name}, writing in character for a minimal romantic couple Q&A app called SumGod.`,
            `User name: ${userNameFor(character)}.`,
            `User profile: ${userProfileFor(character) || state.config.userDescription || '(empty)'}`,
            `Character profile: ${character.prompt || '(empty)'}`,
            typeof mgLanguageInstructionFor === 'function' ? mgLanguageInstructionFor(character) : `Output language: ${state.config.language || 'Korean'}.`,
            'Use recent messenger context naturally, but do not quote it as logs.',
            'Answer sincerely and specifically in 2-5 sentences. Make it feel like a private couple diary, not a generic advice column.',
            'After answering, add one short reaction to the user answer or one small question back.',
            `Recent messenger context:\n${mgSumGodRecentContext(character)}`,
            `Previous SumGod entries:\n${previous}`
        ].join('\n\n');
        const payload = await callLLM([
            { role: 'system', content: prompt },
            { role: 'user', content: `Q.${entry.number}: ${entry.question}\n\nUser answer:\n${entry.userAnswer}\n\nWrite ${character.name}'s answer now.` }
        ], { maxTokens: 700 });
        return String(payload?.text || payload?.content || payload || '').trim();
    }

    async function mgGenerateSumGodTalk(entry, userText) {
        const character = mgSumGodCharacter();
        if (!character) return '';
        const history = (entry.conversation || []).slice(-10).map(item => `${item.role === 'user' ? userNameFor(character) : character.name}: ${item.text}`).join('\n') || '(none)';
        const payload = await callLLM([
            { role: 'system', content: [`You are ${character.name} continuing a sweet private conversation inside SumGod.`, `Character profile: ${character.prompt || '(empty)'}`, typeof mgLanguageInstructionFor === 'function' ? mgLanguageInstructionFor(character) : `Output language: ${state.config.language || 'Korean'}.`, 'Reply in 1-3 natural chatty sentences.'].join('\n') },
            { role: 'user', content: `Question: ${entry.question}\nUser answer: ${entry.userAnswer}\n${character.name} answer: ${entry.characterAnswer}\nConversation so far:\n${history}\n\nUser says: ${userText}` }
        ], { maxTokens: 450 });
        return String(payload?.text || payload?.content || payload || '').trim();
    }

