    const mgBasePhoneAppIconSvgSumGod = mgPhoneAppIconSvg;
    mgPhoneAppIconSvg = function(app) {
        if (app === 'sumgod') return mgSumGodIconSvg();
        return mgBasePhoneAppIconSvgSumGod(app);
    };

    const mgBasePhoneHomeHtmlSumGod = mgPhoneHomeHtml;
    mgPhoneHomeHtml = function() {
        let html = mgBasePhoneHomeHtmlSumGod();
        if (html.includes('data-app="sumgod"')) return html;
        const icon = mgPhoneAppIconHtml({ app: 'sumgod', title: 'SumGod', subtitle: 'Q', badge: mgSumGodBadgeCount(), className: 'sumgod' });
        return html.replace('</main>', `${icon}</main>`);
    };

    function mgSumGodHeaderHtml(title = 'SumGod') {
        return `<header class="mg-top mg-sumgod-top"><button class="mg-icon" title="홈" data-action="mg-phone-home">‹</button><div class="mg-title"><strong>${escapeHtml(title)}</strong><span>couple question diary</span></div><div class="mg-actions"><button class="mg-btn" data-action="sumgod-archive">아카이브</button><button class="mg-btn" data-action="sumgod-today">오늘</button><button class="mg-btn" data-action="mg-phone-home">홈</button></div></header>`;
    }

    function mgSumGodCharacterSelectHtml() {
        const sum = mgSumGodState();
        return `<section class="mg-sumgod-card mg-sumgod-select"><h2>함께 문답할 캐릭터</h2><p>캐릭터를 바꾸면 Q.1부터 새로 시작합니다.</p><select class="mg-select" id="sumgod-character">${(state.characters || []).map(character => `<option value="${escapeHtml(character.id)}" ${character.id === sum.characterId ? 'selected' : ''}>${escapeHtml(character.name || character.id)}</option>`).join('')}</select><button class="mg-btn primary" data-action="sumgod-save-character">캐릭터 지정</button></section>`;
    }

    function mgSumGodTodayHtml() {
        const sum = mgSumGodState();
        const character = mgSumGodCharacter();
        const userName = userNameFor(character || {});
        const active = mgSumGodActiveEntry();
        const nextNumber = mgSumGodQuestionNumber();
        const doneToday = mgSumGodTodayDone();
        const locked = !active && doneToday;
        const waiting = !active && !doneToday && !mgSumGodAvailableNow() && sum.entries.length > 0;
        const entry = active || (!locked && !waiting ? mgSumGodCurrentEntry(false) : null);
        const title = character ? `${character.name || 'Character'} ♥ ${userName}` : 'SumGod';
        const eggLine = locked ? '오늘 문답은 완료됐어요. 내일 밤 10시에 또 만나요.' : waiting ? '오늘 질문은 밤 10시에 도착해요.' : '오늘의 질문을 받으려면 절 클릭하세요!';
        const questionPanel = entry ? `<section class="mg-sumgod-card mg-sumgod-question"><span class="mg-sumgod-qno">Q.${entry.number}</span><h2>${escapeHtml(entry.question)}</h2>${entry.userAnswer ? `<div class="mg-sumgod-answer user"><b>${escapeHtml(userName)}</b><p>${escapeHtml(entry.userAnswer)}</p></div>` : `<textarea class="mg-textarea" id="sumgod-user-answer" placeholder="내 답변을 적어주세요."></textarea><button class="mg-btn primary" data-action="sumgod-submit-answer" data-id="${escapeHtml(entry.id)}">내 답변 저장</button>`}${entry.characterAnswer ? `<div class="mg-sumgod-answer character"><b>${escapeHtml(character?.name || 'Character')}</b><p>${escapeHtml(entry.characterAnswer)}</p></div>${mgSumGodConversationHtml(entry)}` : entry.userAnswer ? '<div class="mg-sumgod-wait">캐릭터 답변을 쓰는 중...</div>' : ''}</section>` : '';
        return `<main class="mg-main mg-sumgod-main"><section class="mg-sumgod-hero"><div><h1>${escapeHtml(title)}</h1><p>밤 10시에 하나씩 도착하는 미니 커플 문답</p></div>${mgSumGodCharacterSelectHtml()}</section><button class="mg-sumgod-egg" type="button" data-action="sumgod-open-question">${mgSumGodEggSvg()}<span>${escapeHtml(eggLine)}</span></button>${questionPanel}</main>`;
    }

    function mgSumGodConversationHtml(entry) {
        const character = mgSumGodCharacter();
        const rows = (entry.conversation || []).map(item => `<div class="mg-sumgod-talk ${item.role === 'user' ? 'user' : 'character'}"><b>${escapeHtml(item.role === 'user' ? userNameFor(character || {}) : character?.name || 'Character')}</b><p>${escapeHtml(item.text || '')}</p></div>`).join('');
        return `<div class="mg-sumgod-conversation">${rows}<textarea class="mg-textarea" id="sumgod-talk-text" placeholder="이 답변에 대해 더 이야기하기"></textarea><button class="mg-btn" data-action="sumgod-send-talk" data-id="${escapeHtml(entry.id)}">보내기</button></div>`;
    }

    function mgSumGodArchiveHtml() {
        const entries = mgSumGodState().entries.filter(entry => entry.userAnswer || entry.characterAnswer);
        return `<main class="mg-main mg-sumgod-main"><section class="mg-sumgod-card"><h1>아카이브</h1><p>완료한 문답을 다시 꺼내볼 수 있어요.</p></section><div class="mg-sumgod-archive">${entries.length ? entries.map(entry => `<article class="mg-sumgod-card mg-sumgod-archive-card"><span class="mg-sumgod-qno">Q.${entry.number}</span><h2>${escapeHtml(entry.question)}</h2><p><b>나</b> ${escapeHtml(entry.userAnswer || '')}</p><p><b>${escapeHtml(mgSumGodCharacter()?.name || 'Character')}</b> ${escapeHtml(entry.characterAnswer || '')}</p></article>`).join('') : '<section class="mg-sumgod-card mg-empty">아직 저장된 문답이 없습니다.</section>'}</div></main>`;
    }

    function mgSumGodAppHtml() {
        const view = mgSumGodState().view === 'archive' ? 'archive' : 'today';
        return `<div class="mg-shell mg-phone-app-shell mg-sumgod-shell">${mgSumGodHeaderHtml(view === 'archive' ? 'SumGod Archive' : 'SumGod')}${view === 'archive' ? mgSumGodArchiveHtml() : mgSumGodTodayHtml()}${fileInputsHtml()}</div>`;
    }

    const mgBaseAppHtmlSumGod = appHtml;
    appHtml = function(...args) {
        if (mgPhoneApp === 'sumgod') return mgSumGodAppHtml();
        return mgBaseAppHtmlSumGod.apply(this, args);
    };

    const mgBaseHandleActionSumGod = handleAction;
    handleAction = async function(action, element) {
        if (action === 'sumgod-today') { mgSumGodState().view = 'today'; render(); return; }
        if (action === 'sumgod-archive') { mgSumGodState().view = 'archive'; render(); return; }
        if (action === 'sumgod-save-character') {
            const value = document.getElementById('sumgod-character')?.value || '';
            if (value && value !== mgSumGodState().characterId) mgSumGodResetForCharacter(value);
            else mgSumGodState().characterId = value;
            await saveState();
            render();
            return;
        }
        if (action === 'sumgod-open-question') {
            if (!mgSumGodState().characterId && state.characters?.[0]) mgSumGodState().characterId = state.characters[0].id;
            if (mgSumGodTodayDone() && !mgSumGodActiveEntry()) { render(); return; }
            if (!mgSumGodAvailableNow() && !mgSumGodActiveEntry() && mgSumGodState().entries.length > 0) { render(); return; }
            mgSumGodCurrentEntry(true);
            await saveState();
            render();
            return;
        }
        if (action === 'sumgod-submit-answer') {
            const entry = mgSumGodState().entries.find(item => item.id === element.dataset.id) || mgSumGodActiveEntry();
            if (!entry) return;
            const answer = String(document.getElementById('sumgod-user-answer')?.value || '').trim();
            if (!answer) return;
            entry.userAnswer = answer;
            entry.characterAnswer = await mgGenerateSumGodCharacterAnswer(entry).catch(error => {
                logDebug?.('sumgod-answer-error', error.message, { question: entry.number });
                return '조금 서툴지만, 네 답을 읽고 마음이 따뜻해졌어. 나도 이 질문을 우리답게 오래 기억하고 싶어.';
            });
            entry.completedOn = mgSumGodTodayKey();
            entry.completedAt = Date.now();
            await saveState();
            render();
            return;
        }
        if (action === 'sumgod-send-talk') {
            const entry = mgSumGodState().entries.find(item => item.id === element.dataset.id);
            const text = String(document.getElementById('sumgod-talk-text')?.value || '').trim();
            if (!entry || !text) return;
            entry.conversation = Array.isArray(entry.conversation) ? entry.conversation : [];
            entry.conversation.push({ role: 'user', text, createdAt: Date.now() });
            const reply = await mgGenerateSumGodTalk(entry, text).catch(() => '응, 그 말 들으니까 나도 조금 더 솔직해지고 싶어졌어.');
            entry.conversation.push({ role: 'character', text: reply, createdAt: Date.now() });
            await saveState();
            render();
            return;
        }
        return mgBaseHandleActionSumGod(action, element);
    };

