    mgSumGodConversationHtml = function(entry) {
        const character = mgSumGodCharacter();
        const rows = (entry.conversation || []).map(item => `<div class="mg-sumgod-talk ${item.role === 'user' ? 'user' : 'character'}"><b>${escapeHtml(item.role === 'user' ? userNameFor(character || {}) : character?.name || 'Character')}</b><p>${escapeHtml(item.text || '')}</p></div>`).join('');
        const loading = entry.generatingTalk ? mgSumGodLoadingHtml('답장이 달걀 속에서 익는 중...') : '';
        return `<div class="mg-sumgod-conversation">${rows}${loading}<textarea class="mg-textarea" id="sumgod-talk-text" maxlength="1000" placeholder="이 답변에 대해 더 이야기하기"></textarea><button class="mg-btn" data-action="sumgod-send-talk" data-id="${escapeHtml(entry.id)}">보내기</button></div>`;
    };

    const mgBaseHandleActionSumGodLoading = handleAction;
    handleAction = async function(action, element) {
        if (action === 'sumgod-submit-answer') {
            const entry = mgSumGodState().entries.find(item => item.id === element.dataset.id) || mgSumGodActiveEntry();
            if (!entry) return;
            const answer = mgSumGodClipText(document.getElementById('sumgod-user-answer')?.value || '', 1000);
            if (!answer) return;
            entry.userAnswer = answer;
            entry.characterAnswer = '';
            entry.generatingAnswer = true;
            mgSumGodState().questionOpen = true;
            await saveState();
            render();
            await new Promise(resolve => setTimeout(resolve, 60));
            entry.characterAnswer = await mgGenerateSumGodCharacterAnswer(entry).catch(error => {
                logDebug?.('sumgod-answer-error', error.message, { question: entry.number });
                return '지금 답변을 제대로 정리하지 못했어. 아래 재생성 버튼을 눌러서 캐릭터 답변만 다시 받아줘.';
            });
            entry.generatingAnswer = false;
            entry.completedOn = mgSumGodTodayKey();
            entry.completedAt = Date.now();
            await saveState();
            render();
            return;
        }
        if (action === 'sumgod-regenerate-answer') {
            const entry = mgSumGodState().entries.find(item => item.id === element.dataset.id) || mgSumGodTodayEntry() || mgSumGodActiveEntry();
            if (!entry || !entry.userAnswer) return;
            entry.characterAnswer = '';
            entry.generatingAnswer = true;
            mgSumGodState().questionOpen = true;
            await saveState();
            render();
            await new Promise(resolve => setTimeout(resolve, 60));
            entry.characterAnswer = await mgGenerateSumGodCharacterAnswer(entry).catch(error => {
                logDebug?.('sumgod-regenerate-error', error.message, { question: entry.number });
                return '이번에도 답변 생성이 실패했어. API 설정이나 모델 응답이 안정적인지 확인한 뒤 다시 눌러줘.';
            });
            entry.generatingAnswer = false;
            entry.completedOn = entry.completedOn || mgSumGodTodayKey();
            entry.completedAt = entry.completedAt || Date.now();
            await saveState();
            render();
            return;
        }
        if (action === 'sumgod-send-talk') {
            const entry = mgSumGodState().entries.find(item => item.id === element.dataset.id);
            const text = mgSumGodClipText(document.getElementById('sumgod-talk-text')?.value || '', 1000);
            if (!entry || !text) return;
            entry.conversation = Array.isArray(entry.conversation) ? entry.conversation : [];
            entry.conversation.push({ role: 'user', text, createdAt: Date.now() });
            entry.generatingTalk = true;
            await saveState();
            render();
            await new Promise(resolve => setTimeout(resolve, 60));
            const reply = await mgGenerateSumGodTalk(entry, text).catch(() => '응, 그 말 조금 더 곱씹고 있었어. 다시 한번만 말해줄래?');
            entry.generatingTalk = false;
            entry.conversation.push({ role: 'character', text: mgSumGodClipText(reply, 1000), createdAt: Date.now() });
            await saveState();
            render();
            return;
        }
        return mgBaseHandleActionSumGodLoading(action, element);
    };

