    // SumGod final layer: stronger follow-up replies, tap-to-regenerate bubbles,
    // and a pretty per-question PNG export.
    mgGenerateSumGodTalk = async function(entry, userText) {
        const character = mgSumGodCharacter();
        if (!character) return '';
        const history = (entry.conversation || []).slice(-12).map(item => `${item.role === 'user' ? userNameFor(character) : character.name}: ${item.text}`).join('\n') || '(none)';
        const text = await mgSumGodCallPlain([
            { role: 'system', content: [
                `You are ${character.name} continuing a sweet private conversation inside SumGod.`,
                `Character profile: ${character.prompt || '(empty)'}`,
                typeof mgLanguageInstructionFor === 'function' ? mgLanguageInstructionFor(character) : `Output language: ${state.config.language || 'Korean'}.`,
                'Reply in plain text only. No JSON, labels, markdown, metadata, or arrays.',
                'Reply in 2-5 natural complete sentences, between 60 and 1000 characters unless the character is intentionally extremely terse.',
                'Never stop mid-sentence. End with natural sentence-final punctuation.',
                'React specifically to the user message and the couple question. Keep it intimate, conversational, and in character.'
            ].join('\n') },
            { role: 'user', content: `Question: ${entry.question}\nUser answer: ${entry.userAnswer}\n${character.name} answer: ${entry.characterAnswer}\nConversation so far:\n${history}\n\nUser says: ${userText}` }
        ], { maxTokens: 1300 });
        return mgSumGodClipText(text, 1000);
    };

