    // Release cleanup: SumGod questions unlock only at 22:00, and Random Chat
    // is exposed as its own phone app instead of a Messenger sub-button.
    mgSumGodAvailableNow = function() {
        return new Date().getHours() >= 22;
    };

    const mgBaseSumGodTodayHtmlNoDebug = mgSumGodTodayHtml;
    mgSumGodTodayHtml = function() {
        return String(mgBaseSumGodTodayHtmlNoDebug()).replace(/<button\b(?=[^>]*data-action=["']sumgod-debug-next["'])[\s\S]*?<\/button>/g, '');
    };

    function mgRandomChatUnreadCount() {
        mgEnsureRandomChatState();
        const seenAt = Number(mgPhoneAppSeenAt?.().randomchat) || 0;
        return (state.randomChats || []).reduce((sum, room) => {
            const count = Number(state.unreadCounts?.[room.id]) || 0;
            if (!count) return sum;
            if (seenAt && mgPhoneLatestRoomActivity(room.id) <= seenAt) return sum;
            return sum + count;
        }, 0);
    }

    function mgRandomChatIconSvg() {
        return `<svg viewBox="0 0 64 64" aria-hidden="true"><defs><linearGradient id="mg-random-grad" x1="12" y1="10" x2="52" y2="56" gradientUnits="userSpaceOnUse"><stop stop-color="#8b5cf6"/><stop offset=".55" stop-color="#06b6d4"/><stop offset="1" stop-color="#f472b6"/></linearGradient></defs><path d="M32 9c-12.7 0-23 8.3-23 18.6 0 5.9 3.4 11.1 8.7 14.5l-1.4 8.4c-.2 1.2 1.1 2 2.1 1.3l8.1-4.9c1.8.3 3.6.5 5.5.5 12.7 0 23-8.3 23-18.6S44.7 9 32 9Z" fill="url(#mg-random-grad)"/><path d="M22 28c4-5 8-5 12 0s8 5 12 0" fill="none" stroke="#fff" stroke-width="4" stroke-linecap="round"/><circle cx="23" cy="35" r="3" fill="#fff"/><circle cx="41" cy="35" r="3" fill="#fff"/></svg>`;
    }

    const mgBasePhoneAppIconSvgRandomApp = mgPhoneAppIconSvg;
