    function mgRandomChatPhoneHeaderHtml(room = null) {
        const title = room?.character?.name || '랜덤채팅';
        const subtitle = room ? `Random · @${room.character?.handle || room.character?.id || 'random'}` : '낯선 캐릭터와 분리된 임시 만남';
        return `<header class="mg-top mg-random-app-top"><button class="mg-icon" title="홈" data-action="mg-phone-home">‹</button><div class="mg-title"><strong>${escapeHtml(title)}</strong><span>${escapeHtml(subtitle)}</span></div><div class="mg-actions"><button class="mg-btn" data-action="create-random-chat">새 랜덤</button><button class="mg-btn" data-action="mg-phone-home">홈</button></div></header>`;
    }

    function mgRandomChatPhoneAppHtml() {
        mgEnsureRandomChatState();
        const room = mgRandomChatById(selectedRoomId) || state.randomChats?.[0] || null;
        if (room && selectedRoomId !== room.id) selectedRoomId = room.id;
        const body = room ? mgRandomChatRoomHtml(room) : mgRandomChatHomeHtml();
        const profileModal = typeof mgRandomProfileModalHtml === 'function' ? mgRandomProfileModalHtml() : '';
        return `<div class="mg-shell mg-phone-app-shell mg-random-phone-app mg-view-randomchat">${mgRandomChatPhoneHeaderHtml(room)}<main class="mg-main">${body}</main>${profileModal}${notificationPanelHtml()}${fileInputsHtml()}</div>`;
    }

    const mgBaseAppHtmlRandomPhoneApp = appHtml;
    appHtml = function(...args) {
        if (mgPhoneApp === 'randomchat') {
            activeTab = 'randomchat';
            return mgRandomChatPhoneAppHtml();
        }
        let html = mgBaseAppHtmlRandomPhoneApp.apply(this, args);
        if (mgPhoneApp === 'messenger') {
            html = String(html).replace(/<button\b(?=[^>]*(?:data-action=["']open-random-chat["']|mg-random-title-btn))[\s\S]*?<\/button>/g, '');
        }
        return html;
    };

    const mgBaseHandleActionRandomPhoneApp = handleAction;
    handleAction = async function(action, element) {
        if (action === 'mg-phone-open-app' && (element?.dataset?.app || '') === 'randomchat') {
            mgPhoneApp = 'randomchat';
            activeTab = 'randomchat';
            mgEnsureRandomChatState();
            selectedRoomId = state.randomChats?.[0]?.id || selectedRoomId;
            mgPhoneMarkAppSeen('randomchat');
            await saveState();
            if (typeof flushSaveState === 'function') await flushSaveState();
            render();
            return;
        }
        if (action === 'open-random-chat') {
            mgPhoneApp = 'randomchat';
            activeTab = 'randomchat';
            mgEnsureRandomChatState();
            selectedRoomId = state.randomChats?.[0]?.id || selectedRoomId;
            mgPhoneMarkAppSeen('randomchat');
            render();
            return;
        }
        if (action === 'select-random-chat' && mgPhoneApp === 'randomchat') {
            selectedRoomId = element.dataset.id || selectedRoomId;
            activeTab = 'randomchat';
            if (state.unreadCounts) delete state.unreadCounts[selectedRoomId];
            mgPhoneMarkAppSeen('randomchat');
            await saveState();
            render();
            return;
        }
        if ((action === 'mg-phone-home' || action === 'close') && mgPhoneApp === 'randomchat') {
            mgPhoneMarkAppSeen('randomchat');
        }
        return mgBaseHandleActionRandomPhoneApp(action, element);
    };

