    // --- FINAL SUMGOD MOBILE RELIABILITY FIX ---
    async function mgOpenSumGodQuestionFinal() {
        const sum = mgSumGodState();
        if (!sum.characterId && state.characters?.[0]) sum.characterId = state.characters[0].id;
        sum.view = 'today';
        sum.questionOpen = true;
        if (!mgSumGodActiveEntry() && !mgSumGodTodayEntry() && mgSumGodAvailableNow()) mgSumGodCurrentEntry(true);
        await saveState();
        if (typeof flushSaveState === 'function') await flushSaveState();
        render();
    }

    mgSumGodCharacterSelectHtml = function() {
        const sum = mgSumGodState();
        const selected = state.characters?.find(character => character.id === sum.characterId);
        return `<details class="mg-sumgod-card mg-sumgod-select mg-sumgod-character-drawer"><summary><span>함께 문답할 캐릭터</span><b>${escapeHtml(selected?.name || '선택')}</b></summary><div class="mg-sumgod-select-body"><p>캐릭터를 바꾸면 Q.1부터 새로 시작합니다.</p><select class="mg-select" id="sumgod-character">${(state.characters || []).map(character => `<option value="${escapeHtml(character.id)}" ${character.id === sum.characterId ? 'selected' : ''}>${escapeHtml(character.name || character.id)}</option>`).join('')}</select><button class="mg-btn primary" data-action="sumgod-save-character">캐릭터 지정</button></div></details>`;
    };

    const mgBaseHandleActionSumGodFinalReliable = handleAction;
    handleAction = async function(action, element) {
        if (action === 'sumgod-open-question') {
            await mgOpenSumGodQuestionFinal();
            return;
        }
        return mgBaseHandleActionSumGodFinalReliable(action, element);
    };

    const mgBaseBindEventsSumGodFinalReliable = bindEvents;
    bindEvents = function() {
        mgBaseBindEventsSumGodFinalReliable();
        document.querySelectorAll('.mg-sumgod-egg').forEach(button => {
            if (button.dataset.mgSumgodEggBoundFinal) return;
            button.dataset.mgSumgodEggBoundFinal = '1';
            const open = event => {
                event.preventDefault();
                event.stopPropagation();
                mgOpenSumGodQuestionFinal().catch(console.warn);
            };
            button.addEventListener('click', open);
            button.addEventListener('touchend', open, { passive: false });
        });
    };

